'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import Link from 'next/link'

interface MediaItem {
    id: string
    page: string
    type: string
    url: string
    title: string
    sortOrder: number
    duration: number
    active: boolean
}

const PAGES = [
    { value: 'donate', label: 'Donate Page' },
    { value: 'subscribe', label: 'Notification Page' },
    { value: 'about', label: 'About Page' },
    { value: 'contact', label: 'Contact Page' },
    { value: 'home', label: 'Homepage' },
]

const HERO_VIDEO_PAGES = [
    { value: 'all', label: '🌐 All Pages', short: 'All' },
    { value: 'home', label: '🏠 Homepage', short: 'Home' },
    { value: 'works', label: '🎬 Works', short: 'Works' },
    { value: 'casting', label: '🎭 Casting', short: 'Casting' },
    { value: 'upcoming', label: '📅 Upcoming', short: 'Upcoming' },
    { value: 'training', label: '🎓 Training', short: 'Training' },
]

const SIDEBAR_LINKS = [
    { href: '/admin/analytics', label: '📊 Analytics' },
    { href: '/admin/projects', label: '🎬 Projects' },
    { href: '/admin/casting', label: '🎭 Casting' },
    { href: '/admin/applications', label: '📋 Applications' },
    { href: '/admin/media', label: '🖼️ Media Manager', active: true },
    { href: '/admin/sponsors', label: '🤝 Sponsors' },
    { href: '/admin/donations', label: '💰 Donations' },
    { href: '/admin/users', label: '👥 Users' },
    { href: '/admin/scripts', label: '✍️ Scripts' },
    { href: '/admin/training', label: '🎓 Training' },
    { href: '/admin/settings', label: '⚙️ Settings' },
]

type TabType = 'media' | 'hero-videos'

export default function AdminMediaPage() {
    const [activeTab, setActiveTab] = useState<TabType>('media')

    // ─── Page Media state ───
    const [media, setMedia] = useState<MediaItem[]>([])
    const [filterPage, setFilterPage] = useState<string>('all')
    const [uploading, setUploading] = useState(false)
    const [showForm, setShowForm] = useState(false)
    const [form, setForm] = useState({ page: 'donate', title: '', url: '', type: 'background', sortOrder: 1, duration: 10 })
    const [editingId, setEditingId] = useState<string | null>(null)
    const fileRef = useRef<HTMLInputElement>(null)

    // ─── Hero Videos state ───
    const [heroVideos, setHeroVideos] = useState<MediaItem[]>([])
    const [showVidForm, setShowVidForm] = useState(false)
    const [vidForm, setVidForm] = useState({ title: '', url: '', pages: ['all'] as string[], duration: 10, sortOrder: 1, active: true })
    const [vidEditingId, setVidEditingId] = useState<string | null>(null)
    const vidFileRef = useRef<HTMLInputElement>(null)
    const vidFormRef = useRef<HTMLDivElement>(null)
    const [vidUploading, setVidUploading] = useState(false)
    const [vidUploadMsg, setVidUploadMsg] = useState('')

    // ─── Delete confirmation state ───
    const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null)

    // ─── Drag state ───
    const [isDragging, setIsDragging] = useState(false)
    const dragCounterRef = useRef(0)

    // ─── Fetch ───
    const fetchMedia = useCallback(async () => {
        const url = filterPage === 'all' ? '/api/admin/media?admin=true' : `/api/admin/media?page=${filterPage}&admin=true`
        const res = await fetch(url)
        const data = await res.json()
        setMedia(data.filter((m: MediaItem) => m.type !== 'hero-video'))
    }, [filterPage])

    const fetchHeroVideos = async () => {
        const res = await fetch('/api/admin/media?type=hero-video&admin=true')
        if (res.status === 401) { window.location.href = '/admin/login'; return }
        const data = await res.json()
        setHeroVideos(data)
    }

    useEffect(() => { fetchMedia() }, [fetchMedia])
    useEffect(() => { fetchHeroVideos() }, [])

    // ─── Page Media handlers ───
    const resetForm = () => {
        const defaultPage = filterPage !== 'all' ? filterPage : 'donate'
        const nextSort = media.length > 0 ? Math.max(...media.map(m => m.sortOrder)) + 1 : 1
        setForm({ page: defaultPage, title: '', url: '', type: 'background', sortOrder: nextSort, duration: 10 })
        setEditingId(null)
        setShowForm(false)
        if (fileRef.current) fileRef.current.value = ''
    }

    const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return
        setUploading(true)
        const formData = new FormData()
        formData.append('file', file)
        try {
            const res = await fetch('/api/admin/upload', { method: 'POST', body: formData })
            const data = await res.json()
            if (data.url) setForm(prev => ({ ...prev, url: data.url }))
        } catch { /* */ }
        setUploading(false)
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!form.url) return
        if (editingId) {
            await fetch('/api/admin/media', { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: editingId, ...form }) })
        } else {
            await fetch('/api/admin/media', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ ...form, active: true }) })
        }
        resetForm()
        fetchMedia()
    }

    const handleEdit = (item: MediaItem) => {
        setForm({ page: item.page, title: item.title, url: item.url, type: item.type, sortOrder: item.sortOrder, duration: item.duration || 10 })
        setEditingId(item.id)
        setShowForm(true)
    }

    const handleDelete = async (id: string) => {
        if (confirmDeleteId !== id) {
            setConfirmDeleteId(id)
            setTimeout(() => setConfirmDeleteId(prev => prev === id ? null : prev), 3000)
            return
        }
        setConfirmDeleteId(null)
        try {
            await fetch(`/api/admin/media?id=${id}`, { method: 'DELETE' })
            fetchMedia()
            fetchHeroVideos()
        } catch (err) {
            console.error('Delete failed:', err)
        }
    }

    const handleToggle = async (item: MediaItem) => {
        await fetch('/api/admin/media', { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: item.id, active: !item.active }) })
        fetchMedia()
        fetchHeroVideos()
    }

    // ─── Hero Video handlers ───
    const resetVidForm = () => {
        const nextSort = heroVideos.length > 0 ? Math.max(...heroVideos.map(v => v.sortOrder)) + 1 : 1
        setVidForm({ title: '', url: '', pages: ['all'], duration: 10, sortOrder: nextSort, active: true })
        setVidEditingId(null)
        setShowVidForm(false)
    }

    const openVidForm = () => {
        const nextSort = heroVideos.length > 0 ? Math.max(...heroVideos.map(v => v.sortOrder)) + 1 : 1
        setVidForm(prev => ({ ...prev, sortOrder: nextSort }))
        setShowVidForm(true)
        setTimeout(() => vidFormRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 50)
    }

    const togglePage = (val: string) => {
        setVidForm(prev => {
            if (val === 'all') return { ...prev, pages: ['all'] }
            let next = prev.pages.filter(p => p !== 'all')
            if (next.includes(val)) next = next.filter(p => p !== val)
            else next.push(val)
            return { ...prev, pages: next.length === 0 ? ['all'] : next }
        })
    }

    const handleVidSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        const payload = {
            page: vidForm.pages.join(','),
            type: 'hero-video',
            title: vidForm.title,
            url: vidForm.url,
            duration: vidForm.duration,
            sortOrder: vidForm.sortOrder,
            active: vidForm.active,
        }
        try {
            let res: Response
            if (vidEditingId) {
                res = await fetch('/api/admin/media', { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id: vidEditingId, ...payload }) })
            } else {
                res = await fetch('/api/admin/media', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) })
            }
            if (!res.ok) {
                const err = await res.json().catch(() => ({ error: 'Unknown error' }))
                alert(`Failed to save: ${err.error || res.statusText}`)
                return
            }
            resetVidForm()
            fetchHeroVideos()
        } catch (err) {
            alert(`Network error: ${err instanceof Error ? err.message : 'Unknown'}`)
        }
    }

    const handleVidEdit = (item: MediaItem) => {
        const pages = item.page ? item.page.split(',').filter(Boolean) : ['all']
        setVidForm({ title: item.title, url: item.url, pages, duration: item.duration || 10, sortOrder: item.sortOrder, active: item.active })
        setVidEditingId(item.id)
        setShowVidForm(true)
        setTimeout(() => vidFormRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 50)
    }

    const handleVidFileUpload = useCallback(async (files: FileList | null) => {
        if (!files || files.length === 0) return
        const file = files[0]
        if (!file.type.startsWith('video/')) {
            setVidUploadMsg('Not a video file')
            setTimeout(() => setVidUploadMsg(''), 2000)
            return
        }
        setVidUploading(true)
        setVidUploadMsg(`Uploading ${file.name}...`)
        const formData = new FormData()
        formData.append('file', file)
        formData.append('directory', 'videos')
        try {
            const res = await fetch('/api/admin/upload', { method: 'POST', body: formData })
            const data = await res.json()
            if (data.url) {
                const label = file.name.replace(/\.[^.]+$/, '').replace(/[-_]/g, ' ')
                setVidForm(prev => ({ ...prev, title: label, url: data.url, sortOrder: heroVideos.length + 1 }))
                setVidEditingId(null)
                setShowVidForm(true)
                setTimeout(() => vidFormRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 50)
                setVidUploadMsg('✓ Uploaded, configure below')
                setTimeout(() => { setVidUploadMsg(''); setVidUploading(false) }, 2000)
            }
        } catch {
            setVidUploadMsg('Upload failed')
            setTimeout(() => { setVidUploading(false); setVidUploadMsg('') }, 2000)
        }
    }, [heroVideos.length])

    // Drag handlers (hero videos tab only)
    const handleDragEnter = useCallback((e: React.DragEvent) => {
        e.preventDefault(); e.stopPropagation()
        dragCounterRef.current++
        if (activeTab === 'hero-videos' && e.dataTransfer.types.includes('Files')) setIsDragging(true)
    }, [activeTab])
    const handleDragLeave = useCallback((e: React.DragEvent) => {
        e.preventDefault(); e.stopPropagation()
        dragCounterRef.current--
        if (dragCounterRef.current === 0) setIsDragging(false)
    }, [])
    const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); e.stopPropagation() }, [])
    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault(); e.stopPropagation()
        setIsDragging(false); dragCounterRef.current = 0
        if (activeTab === 'hero-videos') handleVidFileUpload(e.dataTransfer.files)
    }, [activeTab, handleVidFileUpload])

    const getPagePills = (val: string) => {
        const pages = val.split(',').filter(Boolean)
        return pages.map(p => {
            const found = HERO_VIDEO_PAGES.find(o => o.value === p)
            return { label: found?.short || p, icon: found?.label.charAt(0) || '📄' }
        })
    }

    const getPageLabel = (page: string) => {
        return PAGES.find(p => p.value === page)?.label || page
    }

    const inputStyle: React.CSSProperties = {
        width: '100%', padding: '0.5rem 0.7rem',
        background: 'var(--bg-primary)', border: '1px solid var(--border-subtle)',
        borderRadius: 'var(--radius-md)', color: 'var(--text-primary)', fontSize: '0.82rem', outline: 'none',
    }
    const labelStyle: React.CSSProperties = {
        display: 'block', fontSize: '0.65rem', color: 'var(--text-tertiary)',
        marginBottom: '3px', textTransform: 'uppercase', letterSpacing: '0.08em', fontWeight: 600,
    }

    return (
        <div className="admin-layout"
            onDragEnter={handleDragEnter} onDragLeave={handleDragLeave}
            onDragOver={handleDragOver} onDrop={handleDrop}
        >
            <aside className="admin-sidebar">
                <div className="admin-sidebar-logo">
                    <Link href="/" style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 800 }}>
                        <span style={{ color: 'var(--accent-gold)' }}>AIM</span> Studio
                    </Link>
                    <div style={{ fontSize: '0.7rem', color: 'var(--text-tertiary)', marginTop: '2px' }}>Admin Panel</div>
                </div>
                <ul className="admin-sidebar-nav">
                    {SIDEBAR_LINKS.map(link => (
                        <li key={link.href}>
                            <Link href={link.href} className={link.active ? 'active' : ''}>{link.label}</Link>
                        </li>
                    ))}
                    <li style={{ borderTop: '1px solid var(--border-subtle)', marginTop: 'var(--space-md)', paddingTop: 'var(--space-md)' }}>
                        <Link href="/" style={{ color: 'var(--text-tertiary)' }}>← Back to Site</Link>
                    </li>
                </ul>
            </aside>

            <main className="admin-main">
                {/* Drag overlay */}
                {isDragging && (
                    <div style={{
                        position: 'fixed', inset: 0, zIndex: 9999,
                        background: 'rgba(0,0,0,0.85)', backdropFilter: 'blur(8px)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center', pointerEvents: 'none',
                    }}>
                        <div style={{
                            textAlign: 'center', padding: 'var(--space-2xl)',
                            border: '3px dashed var(--accent-gold)', borderRadius: 'var(--radius-xl)',
                            background: 'rgba(212,168,83,0.05)', maxWidth: '400px',
                        }}>
                            <div style={{ fontSize: '2.5rem', marginBottom: 'var(--space-sm)' }}>🎬</div>
                            <div style={{ fontSize: '1.1rem', fontWeight: 700 }}>Drop video here</div>
                        </div>
                    </div>
                )}

                {/* Header */}
                <div className="admin-header">
                    <h1 className="admin-page-title" style={{ marginBottom: 0 }}>Media Manager</h1>
                </div>

                {/* Tabs */}
                <div style={{ display: 'flex', gap: '2px', marginBottom: 'var(--space-lg)', borderBottom: '1px solid var(--border-subtle)' }}>
                    {([
                        { key: 'media' as TabType, label: '🖼️ Page Media', count: media.length },
                        { key: 'hero-videos' as TabType, label: '🎥 Hero Videos', count: heroVideos.length },
                    ]).map(tab => (
                        <button key={tab.key} onClick={() => setActiveTab(tab.key)} style={{
                            padding: '8px 16px', fontSize: '0.78rem', fontWeight: 600,
                            background: 'none', border: 'none', cursor: 'pointer',
                            color: activeTab === tab.key ? 'var(--accent-gold)' : 'var(--text-tertiary)',
                            borderBottom: activeTab === tab.key ? '2px solid var(--accent-gold)' : '2px solid transparent',
                            marginBottom: '-1px', transition: 'all 0.2s',
                        }}>
                            {tab.label} <span style={{ opacity: 0.6, fontSize: '0.7rem' }}>({tab.count})</span>
                        </button>
                    ))}
                </div>

                {/* ═══════════ PAGE MEDIA TAB ═══════════ */}
                {activeTab === 'media' && (
                    <>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--space-md)' }}>
                            {/* Filter pills */}
                            <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
                                <button onClick={() => setFilterPage('all')}
                                    style={{
                                        padding: '3px 10px', fontSize: '0.68rem', fontWeight: 600,
                                        borderRadius: 'var(--radius-full)', cursor: 'pointer', transition: 'all 0.15s',
                                        border: `1px solid ${filterPage === 'all' ? 'var(--accent-gold)' : 'var(--border-subtle)'}`,
                                        background: filterPage === 'all' ? 'rgba(212,168,83,0.12)' : 'transparent',
                                        color: filterPage === 'all' ? 'var(--accent-gold)' : 'var(--text-tertiary)',
                                    }}>All</button>
                                {PAGES.map(p => (
                                    <button key={p.value} onClick={() => setFilterPage(p.value)}
                                        style={{
                                            padding: '3px 10px', fontSize: '0.68rem', fontWeight: 600,
                                            borderRadius: 'var(--radius-full)', cursor: 'pointer', transition: 'all 0.15s',
                                            border: `1px solid ${filterPage === p.value ? 'var(--accent-gold)' : 'var(--border-subtle)'}`,
                                            background: filterPage === p.value ? 'rgba(212,168,83,0.12)' : 'transparent',
                                            color: filterPage === p.value ? 'var(--accent-gold)' : 'var(--text-tertiary)',
                                        }}>{p.label}</button>
                                ))}
                            </div>
                            <button onClick={() => { resetForm(); setShowForm(!showForm) }} className="btn btn-primary btn-sm" style={{ fontSize: '0.78rem' }}>
                                {showForm ? 'Cancel' : '+ Add Media'}
                            </button>
                        </div>

                        {showForm && (
                            <div style={{
                                background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)',
                                borderRadius: 'var(--radius-lg)', padding: 'var(--space-lg)', marginBottom: 'var(--space-lg)',
                            }}>
                                <h3 style={{ marginBottom: 'var(--space-md)', fontSize: '0.9rem', fontWeight: 700 }}>
                                    {editingId ? '✏️ Edit Media' : '🖼️ Add New Media'}
                                </h3>
                                <form onSubmit={handleSubmit}>
                                    <div className="grid-3col" style={{ marginBottom: 'var(--space-sm)', gap: 'var(--space-sm)' }}>
                                        <div>
                                            <label style={labelStyle}>Page</label>
                                            <select value={form.page} onChange={e => setForm({ ...form, page: e.target.value })} style={{ ...inputStyle, cursor: 'pointer' }}>
                                                {PAGES.map(p => <option key={p.value} value={p.value}>{p.label}</option>)}
                                            </select>
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Type</label>
                                            <select value={form.type} onChange={e => setForm({ ...form, type: e.target.value })} style={{ ...inputStyle, cursor: 'pointer' }}>
                                                <option value="background">Background</option>
                                            <option value="video">Video</option>
                                            <option value="gallery">Gallery</option>
                                            <option value="hero">Hero</option>
                                            </select>
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Sort Order</label>
                                            <input type="number" value={form.sortOrder} onChange={e => setForm({ ...form, sortOrder: Math.max(1, parseInt(e.target.value) || 1) })} min={1} style={inputStyle} />
                                        </div>
                                    </div>
                                    <div style={{ marginBottom: 'var(--space-sm)' }}>
                                        <label style={labelStyle}>Title / Label</label>
                                        <input type="text" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} style={inputStyle} />
                                    </div>
                                    <div className="form-grid-2col" style={{ marginBottom: 'var(--space-sm)', gap: 'var(--space-sm)' }}>
                                        <div>
                                            <label style={labelStyle}>Upload File</label>
                                            <input type="file" accept="image/*,video/*" ref={fileRef} onChange={handleUpload}
                                                style={{ ...inputStyle, padding: '0.35rem', fontSize: '0.78rem' }} />
                                            {uploading && <div style={{ fontSize: '0.72rem', color: 'var(--accent-gold)', marginTop: '3px' }}>Uploading...</div>}
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Or enter URL</label>
                                            <input type="text" value={form.url} onChange={e => setForm({ ...form, url: e.target.value })} style={inputStyle} />
                                        </div>
                                    </div>
                                    {form.url && (
                                        <div style={{ marginBottom: 'var(--space-sm)', borderRadius: 'var(--radius-md)', overflow: 'hidden', maxHeight: '100px' }}>
                                            <img src={form.url} alt="Preview" style={{ width: '100%', height: '100px', objectFit: 'cover' }} />
                                        </div>
                                    )}
                                    <button type="submit" className="btn btn-primary btn-sm" style={{ fontSize: '0.78rem' }}>
                                        {editingId ? 'Update Media' : 'Add Media'}
                                    </button>
                                </form>
                            </div>
                        )}

                        {/* ─── Compact Table Listing ─── */}
                        {media.length === 0 ? (
                            <div style={{ padding: 'var(--space-2xl)', textAlign: 'center', color: 'var(--text-tertiary)', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)', fontSize: '0.85rem' }}>
                                No media found. Click &quot;+ Add Media&quot; to upload.
                            </div>
                        ) : (
                            <div style={{
                                background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)',
                                borderRadius: 'var(--radius-lg)', overflow: 'hidden',
                            }}>
                                {/* Table header */}
                                <div style={{
                                    display: 'grid', gridTemplateColumns: '52px 1fr 90px 60px 50px 90px',
                                    gap: '8px', padding: '8px 12px', alignItems: 'center',
                                    borderBottom: '1px solid var(--border-subtle)', background: 'rgba(255,255,255,0.02)',
                                }}>
                                    <div style={thStyle}></div>
                                    <div style={thStyle}>Title</div>
                                    <div style={thStyle}>Page</div>
                                    <div style={thStyle}>Type</div>
                                    <div style={{ ...thStyle, textAlign: 'center' }}>Pos</div>
                                    <div style={{ ...thStyle, textAlign: 'right' }}>Actions</div>
                                </div>
                                {/* Rows */}
                                {media.map((item, idx) => (
                                    <div key={item.id} style={{
                                        display: 'grid', gridTemplateColumns: '52px 1fr 90px 60px 50px 90px',
                                        gap: '8px', padding: '6px 12px', alignItems: 'center',
                                        borderBottom: idx < media.length - 1 ? '1px solid rgba(255,255,255,0.03)' : 'none',
                                        opacity: item.active ? 1 : 0.45,
                                        transition: 'all 0.15s',
                                        background: 'transparent',
                                    }}
                                        onMouseEnter={e => (e.currentTarget.style.background = 'rgba(212,168,83,0.03)')}
                                        onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                                    >
                                        {/* Thumbnail */}
                                        <div style={{
                                            width: '48px', height: '32px', borderRadius: '4px', overflow: 'hidden',
                                            background: '#0a0a0a', flexShrink: 0,
                                        }}>
                                            <img src={item.url} alt={item.page || 'Media item'} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                        </div>
                                        {/* Title + status */}
                                        <div style={{ minWidth: 0 }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                                                <span style={{ fontSize: '0.78rem', fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                                    {item.title || 'Untitled'}
                                                </span>
                                                {!item.active && (
                                                    <span style={{
                                                        fontSize: '0.5rem', padding: '1px 4px', borderRadius: 'var(--radius-full)',
                                                        background: 'rgba(239,68,68,0.1)', color: '#f87171', fontWeight: 700,
                                                        border: '1px solid rgba(239,68,68,0.15)', textTransform: 'uppercase',
                                                    }}>Hidden</span>
                                                )}
                                            </div>
                                        </div>
                                        {/* Page */}
                                        <div>
                                            <span style={{
                                                fontSize: '0.6rem', padding: '2px 6px', borderRadius: 'var(--radius-full)',
                                                background: 'rgba(212,168,83,0.08)', border: '1px solid rgba(212,168,83,0.12)',
                                                color: 'var(--accent-gold)', fontWeight: 600, textTransform: 'capitalize',
                                            }}>{item.page}</span>
                                        </div>
                                        {/* Type */}
                                        <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)', textTransform: 'capitalize' }}>{item.type}</div>
                                        {/* Sort position */}
                                        <div style={{ textAlign: 'center' }}>
                                            <span style={{
                                                display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                                                width: '22px', height: '22px', borderRadius: '4px',
                                                background: 'rgba(255,255,255,0.04)', border: '1px solid var(--border-subtle)',
                                                fontSize: '0.65rem', fontWeight: 700, color: 'var(--text-secondary)',
                                            }}>{item.sortOrder}</span>
                                        </div>
                                        {/* Actions */}
                                        <div style={{ display: 'flex', gap: '3px', justifyContent: 'flex-end' }}>
                                            <button onClick={() => handleToggle(item)} title={item.active ? 'Hide' : 'Show'} style={compactBtnStyle}>
                                                {item.active ? '👁' : '👁‍🗨'}
                                            </button>
                                            <button onClick={() => handleEdit(item)} title="Edit" style={compactBtnStyle}>✏️</button>
                                            <button onClick={() => handleDelete(item.id)} title={confirmDeleteId === item.id ? 'Click again to confirm' : 'Delete'} style={{ ...compactBtnStyle, color: '#ef4444', background: confirmDeleteId === item.id ? 'rgba(239,68,68,0.15)' : 'none', minWidth: confirmDeleteId === item.id ? '48px' : '24px' }}>{confirmDeleteId === item.id ? 'Sure?' : '🗑'}</button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </>
                )}

                {/* ═══════════ HERO VIDEOS TAB ═══════════ */}
                {activeTab === 'hero-videos' && (
                    <>
                        <input ref={vidFileRef} type="file" accept="video/*" style={{ display: 'none' }}
                            onChange={e => handleVidFileUpload(e.target.files)} />

                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--space-md)' }}>
                            <p style={{ color: 'var(--text-tertiary)', fontSize: '0.75rem', margin: 0 }}>
                                {heroVideos.length} video{heroVideos.length !== 1 ? 's' : ''} · {heroVideos.filter(v => v.active).length} active
                            </p>
                            <button onClick={() => { resetVidForm(); openVidForm() }} className="btn btn-primary btn-sm" style={{ fontSize: '0.78rem' }}>+ Add Video</button>
                        </div>

                        {vidUploading && (
                            <div style={{
                                background: 'rgba(212,168,83,0.08)', border: '1px solid rgba(212,168,83,0.2)',
                                borderRadius: 'var(--radius-md)', padding: '6px 12px',
                                marginBottom: 'var(--space-md)', fontSize: '0.78rem', color: 'var(--accent-gold)', fontWeight: 600,
                            }}>{vidUploadMsg}</div>
                        )}

                        {/* Video Form */}
                        {showVidForm && (
                            <div ref={vidFormRef} style={{
                                background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)',
                                borderRadius: 'var(--radius-lg)', padding: 'var(--space-lg)', marginBottom: 'var(--space-lg)',
                            }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--space-md)' }}>
                                    <h3 style={{ fontSize: '0.9rem', fontWeight: 700, margin: 0 }}>
                                        {vidEditingId ? '✏️ Edit Video' : '🎬 Add Hero Video'}
                                    </h3>
                                    <button onClick={resetVidForm} style={{ background: 'none', border: 'none', color: 'var(--text-tertiary)', cursor: 'pointer', fontSize: '1rem' }}>✕</button>
                                </div>
                                <form onSubmit={handleVidSubmit}>
                                    {!vidEditingId && !vidForm.url && (
                                        <div onClick={() => vidFileRef.current?.click()} style={{
                                            border: '2px dashed var(--border-subtle)', borderRadius: 'var(--radius-md)',
                                            padding: 'var(--space-md)', textAlign: 'center', cursor: 'pointer',
                                            marginBottom: 'var(--space-md)', background: 'rgba(212,168,83,0.02)',
                                        }}>
                                            <div style={{ fontSize: '1.1rem', marginBottom: '2px' }}>📤</div>
                                            <div style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)' }}>
                                                Drop a video or <span style={{ color: 'var(--accent-gold)' }}>browse</span>
                                            </div>
                                            <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)', marginTop: '2px' }}>MP4, WebM, MOV</div>
                                        </div>
                                    )}
                                    {vidForm.url && !vidEditingId && (
                                        <div style={{
                                            display: 'flex', alignItems: 'center', gap: '6px',
                                            padding: '5px 10px', background: 'rgba(34,197,94,0.06)',
                                            border: '1px solid rgba(34,197,94,0.12)', borderRadius: 'var(--radius-sm)',
                                            marginBottom: 'var(--space-md)', fontSize: '0.72rem', color: '#22c55e',
                                        }}>
                                            ✓ <code style={{ color: 'var(--text-tertiary)', fontSize: '0.68rem' }}>{vidForm.url}</code>
                                            <button type="button" onClick={() => setVidForm(prev => ({ ...prev, url: '' }))}
                                                style={{ marginLeft: 'auto', background: 'none', border: 'none', color: 'var(--text-tertiary)', cursor: 'pointer', fontSize: '0.68rem' }}>Change</button>
                                        </div>
                                    )}
                                    <div className="form-grid-2col" style={{ gap: 'var(--space-sm)' }}>
                                        <div>
                                            <label style={labelStyle}>Label</label>
                                            <input type="text" value={vidForm.title} onChange={e => setVidForm({ ...vidForm, title: e.target.value })} style={inputStyle} />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Video URL *</label>
                                            <input type="text" value={vidForm.url} onChange={e => setVidForm({ ...vidForm, url: e.target.value })} required style={inputStyle} />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Duration (s)</label>
                                            <input type="number" value={vidForm.duration} onChange={e => setVidForm({ ...vidForm, duration: parseInt(e.target.value) || 10 })} min={3} max={120} style={inputStyle} />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Play Position</label>
                                            <input type="number" value={vidForm.sortOrder} onChange={e => setVidForm({ ...vidForm, sortOrder: Math.max(1, parseInt(e.target.value) || 1) })} min={1} style={inputStyle} />
                                        </div>
                                    </div>
                                    <div style={{ marginTop: 'var(--space-sm)' }}>
                                        <label style={labelStyle}>Show On Pages</label>
                                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '5px', marginTop: '3px' }}>
                                            {HERO_VIDEO_PAGES.map(opt => {
                                                const sel = vidForm.pages.includes(opt.value)
                                                return (
                                                    <button key={opt.value} type="button" onClick={() => togglePage(opt.value)} style={{
                                                        padding: '3px 9px', fontSize: '0.65rem', fontWeight: 600,
                                                        borderRadius: 'var(--radius-full)', cursor: 'pointer',
                                                        border: `1px solid ${sel ? 'var(--accent-gold)' : 'var(--border-subtle)'}`,
                                                        background: sel ? 'rgba(212,168,83,0.12)' : 'transparent',
                                                        color: sel ? 'var(--accent-gold)' : 'var(--text-tertiary)', transition: 'all 0.15s',
                                                    }}>{opt.label}</button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-md)', marginTop: 'var(--space-md)' }}>
                                        <label style={{ display: 'flex', alignItems: 'center', gap: '6px', cursor: 'pointer', fontSize: '0.78rem' }}>
                                            <input type="checkbox" checked={vidForm.active} onChange={e => setVidForm({ ...vidForm, active: e.target.checked })}
                                                style={{ width: '14px', height: '14px', accentColor: 'var(--accent-gold)' }} /> Active
                                        </label>
                                        <div style={{ flex: 1 }} />
                                        <button type="submit" className="btn btn-primary btn-sm" style={{ fontSize: '0.78rem' }}>
                                            {vidEditingId ? 'Save Changes' : 'Add Video'}
                                        </button>
                                        <button type="button" onClick={resetVidForm} className="btn btn-secondary btn-sm" style={{ fontSize: '0.78rem' }}>Cancel</button>
                                    </div>
                                </form>
                            </div>
                        )}

                        {/* Video listing */}
                        {heroVideos.length === 0 ? (
                            <div style={{
                                display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                                padding: 'var(--space-3xl) var(--space-xl)',
                                background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)',
                                border: '1px solid var(--border-subtle)', textAlign: 'center',
                            }}>
                                <div style={{ fontSize: '2rem', marginBottom: 'var(--space-sm)' }}>🎬</div>
                                <h3 style={{ fontSize: '1rem', margin: '0 0 6px 0' }}>No Hero Videos</h3>
                                <p style={{ color: 'var(--text-tertiary)', fontSize: '0.8rem', margin: '0 0 var(--space-md) 0' }}>Add your first background video.</p>
                                <button onClick={() => { resetVidForm(); openVidForm() }} className="btn btn-primary btn-sm" style={{ fontSize: '0.78rem' }}>+ Add Video</button>
                            </div>
                        ) : (
                            <div style={{
                                background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)',
                                borderRadius: 'var(--radius-lg)', overflow: 'hidden',
                            }}>
                                {heroVideos.map((v, idx) => (
                                    <div key={v.id} style={{
                                        display: 'flex', alignItems: 'center', gap: 'var(--space-md)',
                                        padding: '10px 14px',
                                        borderBottom: idx < heroVideos.length - 1 ? '1px solid rgba(255,255,255,0.03)' : 'none',
                                        opacity: v.active ? 1 : 0.55, transition: 'all 0.2s',
                                        background: 'transparent',
                                    }}
                                        onMouseEnter={e => (e.currentTarget.style.background = 'rgba(212,168,83,0.03)')}
                                        onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                                    >
                                        {/* Position badge */}
                                        <div style={{
                                            width: '24px', height: '24px', borderRadius: '6px', flexShrink: 0,
                                            background: 'rgba(212,168,83,0.08)', border: '1px solid rgba(212,168,83,0.15)',
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            fontSize: '0.7rem', fontWeight: 800, color: 'var(--accent-gold)',
                                        }}>{v.sortOrder}</div>

                                        {/* Thumbnail */}
                                        <div style={{ width: '80px', height: '48px', borderRadius: '6px', overflow: 'hidden', flexShrink: 0, background: '#0a0a0a' }}>
                                            <video src={v.url} muted playsInline style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                                onMouseEnter={e => (e.target as HTMLVideoElement).play()}
                                                onMouseLeave={e => { const el = e.target as HTMLVideoElement; el.pause(); el.currentTime = 0 }} />
                                        </div>

                                        {/* Info */}
                                        <div style={{ flex: 1, minWidth: 0 }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '3px' }}>
                                                <span style={{ fontSize: '0.82rem', fontWeight: 700, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                                    {v.title || 'Untitled'}
                                                </span>
                                                <span style={{
                                                    fontSize: '0.5rem', padding: '1px 5px', borderRadius: 'var(--radius-full)',
                                                    fontWeight: 700, textTransform: 'uppercase',
                                                    background: v.active ? 'rgba(34,197,94,0.12)' : 'rgba(239,68,68,0.1)',
                                                    color: v.active ? '#4ade80' : '#f87171',
                                                    border: `1px solid ${v.active ? 'rgba(34,197,94,0.2)' : 'rgba(239,68,68,0.15)'}`,
                                                }}>{v.active ? 'Live' : 'Paused'}</span>
                                            </div>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '6px', flexWrap: 'wrap' }}>
                                                <span style={{ fontSize: '0.62rem', color: 'var(--text-tertiary)' }}>{v.duration}s</span>
                                                <span style={{ fontSize: '0.5rem', color: 'var(--border-subtle)' }}>·</span>
                                                {/* Page pills */}
                                                {getPagePills(v.page).map((pill, i) => (
                                                    <span key={i} style={{
                                                        fontSize: '0.55rem', padding: '1px 6px', borderRadius: 'var(--radius-full)',
                                                        background: 'rgba(212,168,83,0.08)', border: '1px solid rgba(212,168,83,0.12)',
                                                        color: 'var(--accent-gold)', fontWeight: 600,
                                                    }}>{pill.icon} {pill.label}</span>
                                                ))}
                                            </div>
                                        </div>

                                        {/* Actions */}
                                        <div style={{ display: 'flex', gap: '3px', flexShrink: 0 }}>
                                            <button onClick={() => handleToggle(v)} title={v.active ? 'Pause' : 'Resume'} style={actionBtnStyle}>{v.active ? '⏸' : '▶'}</button>
                                            <button onClick={() => handleVidEdit(v)} title="Edit" style={actionBtnStyle}>✏️</button>
                                            <button onClick={() => handleDelete(v.id)} title={confirmDeleteId === v.id ? 'Click again to confirm' : 'Delete'} style={{ ...actionBtnStyle, color: '#ef4444', background: confirmDeleteId === v.id ? 'rgba(239,68,68,0.15)' : 'none', minWidth: confirmDeleteId === v.id ? '56px' : '28px' }}>{confirmDeleteId === v.id ? 'Sure?' : '🗑'}</button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}

                        <div style={{
                            marginTop: 'var(--space-lg)', padding: '8px 12px',
                            background: 'rgba(212,168,83,0.03)', border: '1px solid rgba(212,168,83,0.08)',
                            borderRadius: 'var(--radius-md)', fontSize: '0.7rem', color: 'var(--text-tertiary)',
                        }}>
                            <strong style={{ color: 'var(--accent-gold)' }}>💡</strong>{' '}
                            Drag videos here · Pause hides without deleting · Lower position plays first · Hover to preview
                        </div>
                    </>
                )}
            </main>
        </div>
    )
}

const thStyle: React.CSSProperties = {
    fontSize: '0.6rem', fontWeight: 700, textTransform: 'uppercase',
    letterSpacing: '0.08em', color: 'var(--text-tertiary)',
}

const compactBtnStyle: React.CSSProperties = {
    width: '24px', height: '24px', display: 'flex', alignItems: 'center', justifyContent: 'center',
    background: 'none', border: '1px solid var(--border-subtle)', borderRadius: '4px',
    cursor: 'pointer', fontSize: '0.6rem', transition: 'all 0.15s', color: 'var(--text-secondary)',
}

const actionBtnStyle: React.CSSProperties = {
    width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center',
    background: 'none', border: '1px solid var(--border-subtle)', borderRadius: 'var(--radius-sm)',
    cursor: 'pointer', fontSize: '0.7rem', transition: 'all 0.15s', color: 'var(--text-secondary)',
}

'use client'

import Link from 'next/link'
import { useState, useEffect } from 'react'
import FileUploader from '@/components/FileUploader'
import { transcribeVideo } from '@/lib/transcribe-client'
import { translateToAllLanguages, LANGUAGE_NAMES } from '@/lib/subtitle-translator'

/* ── Types ── */
type Project = {
    id: string; title: string; slug: string; tagline: string; description: string
    status: string; genre: string | null; year: string | null; duration: string | null
    featured: boolean; sortOrder: number; coverImage: string | null
    trailerUrl: string | null; filmUrl: string | null; projectType: string
    _count: { castingCalls: number }
}

type FormData = {
    title: string; slug: string; tagline: string; description: string
    status: string; genre: string; year: string; duration: string
    featured: boolean; coverImage: string
    trailerUrl: string; filmUrl: string; projectType: string
}

const EMPTY_FORM: FormData = {
    title: '', slug: '', tagline: '', description: '',
    status: 'upcoming', genre: '', year: '', duration: '',
    featured: false, coverImage: '',
    trailerUrl: '', filmUrl: '', projectType: 'movie',
}

const STATUSES = ['upcoming', 'in-production', 'completed']

const SIDEBAR_LINKS = [
    { href: '/admin/analytics', label: '📊 Analytics' },
    { href: '/admin/projects', label: '🎬 Projects', active: true },
    { href: '/admin/casting', label: '🎭 Casting' },
    { href: '/admin/applications', label: '📋 Applications' },
    { href: '/admin/media', label: '🖼️ Page Media' },
    { href: '/admin/sponsors', label: '🤝 Sponsors' },
    { href: '/admin/donations', label: '💰 Donations' },
    { href: '/admin/users', label: '👥 Users' },
    { href: '/admin/scripts', label: '✍️ Scripts' },
    { href: '/admin/training', label: '🎓 Training' },
    { href: '/admin/settings', label: '⚙️ Settings' },
]

const statusConfig: Record<string, { label: string; className: string }> = {
    completed: { label: 'Completed', className: 'badge-green' },
    'in-production': { label: 'In Production', className: 'badge-gold' },
    upcoming: { label: 'Upcoming', className: 'badge-blue' },
}

function slugify(text: string) {
    return text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')
}

export default function AdminProjectsPage() {
    const [projects, setProjects] = useState<Project[]>([])
    const [loading, setLoading] = useState(true)
    const [showModal, setShowModal] = useState(false)
    const [editingId, setEditingId] = useState<string | null>(null)
    const [form, setForm] = useState<FormData>(EMPTY_FORM)
    const [saving, setSaving] = useState(false)
    const [error, setError] = useState('')
    const [deleting, setDeleting] = useState<string | null>(null)
    const [subtitleStatus, setSubtitleStatus] = useState<Record<string, string>>({})
    const [subtitleProgress, setSubtitleProgress] = useState<Record<string, number>>({})

    useEffect(() => {
        fetch('/api/admin/projects')
            .then(r => { if (r.status === 401) { window.location.href = '/admin/login'; return [] } return r.json() })
            .then((data: Project[]) => {
                setProjects(data)
                // Check which projects already have subtitles
                data.forEach((p: Project) => {
                    if (p.filmUrl) {
                        fetch(`/api/subtitles/${p.id}?lang=en`)
                            .then(r => r.json())
                            .then(sub => {
                                if (sub.available && sub.available.length > 0) {
                                    setSubtitleStatus(s => ({ ...s, [p.id]: `✓ ${sub.available.length} lang` }))
                                }
                            })
                            .catch(() => {})
                    }
                })
            })
            .catch(() => setError('Failed to load projects'))
            .finally(() => setLoading(false))
    }, [])

    const openCreate = () => {
        setEditingId(null)
        setForm(EMPTY_FORM)
        setShowModal(true)
        setError('')
    }

    const openEdit = (p: Project) => {
        setEditingId(p.id)
        setForm({
            title: p.title,
            slug: p.slug,
            tagline: p.tagline || '',
            description: p.description,
            status: p.status,
            genre: p.genre || '',
            year: p.year || '',
            duration: p.duration || '',
            featured: p.featured,
            coverImage: p.coverImage || '',
            trailerUrl: p.trailerUrl || '',
            filmUrl: p.filmUrl || '',
            projectType: p.projectType || 'movie',
        })
        setShowModal(true)
        setError('')
    }

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!form.title || !form.description) {
            setError('Please fill in title and description')
            return
        }
        setSaving(true)
        setError('')
        try {
            const payload = {
                ...form,
                slug: form.slug || slugify(form.title),
            }
            const url = editingId ? `/api/admin/projects/${editingId}` : '/api/admin/projects'
            const method = editingId ? 'PUT' : 'POST'
            const res = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            })
            if (!res.ok) {
                const data = await res.json()
                throw new Error(data.error || 'Failed to save')
            }
            const saved = await res.json()
            if (editingId) {
                setProjects(prev => prev.map(p => p.id === editingId ? saved : p))
            } else {
                setProjects(prev => [...prev, saved])
            }
            setShowModal(false)
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to save')
        } finally {
            setSaving(false)
        }
    }

    const handleDelete = async (id: string, title: string) => {
        if (!confirm(`Delete "${title}"? This will also delete all its casting calls and applications.`)) return
        setDeleting(id)
        try {
            const res = await fetch(`/api/admin/projects/${id}`, { method: 'DELETE' })
            if (!res.ok) throw new Error()
            setProjects(prev => prev.filter(p => p.id !== id))
        } catch {
            alert('Failed to delete project')
        } finally {
            setDeleting(null)
        }
    }

    const updateField = (field: keyof FormData, value: string | boolean) =>
        setForm(f => ({ ...f, [field]: value }))

    return (
        <div className="admin-layout">
            <aside className="admin-sidebar">
                <div className="admin-sidebar-logo">
                    <Link href="/" style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 800 }}>
                        <span style={{ color: 'var(--accent-gold)' }}>AIM</span> Studio
                    </Link>
                    <div style={{ fontSize: '0.7rem', color: 'var(--text-tertiary)', marginTop: '2px' }}>Admin Panel</div>
                </div>
                <ul className="admin-sidebar-nav">
                    {SIDEBAR_LINKS.map(link => (
                        <li key={link.href}>
                            <Link href={link.href} className={link.active ? 'active' : ''}>{link.label}</Link>
                        </li>
                    ))}
                    <li style={{ borderTop: '1px solid var(--border-subtle)', marginTop: 'var(--space-md)', paddingTop: 'var(--space-md)' }}>
                        <Link href="/" style={{ color: 'var(--text-tertiary)' }}>← Back to Site</Link>
                    </li>
                </ul>
            </aside>

            <main className="admin-main">
                <div className="admin-header">
                    <h1 className="admin-page-title">Projects</h1>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-md)' }}>
                        <span style={{ fontSize: '0.85rem', color: 'var(--text-tertiary)' }}>{projects.length} total</span>
                        <button onClick={openCreate} className="btn btn-primary btn-sm">+ New Project</button>
                    </div>
                </div>

                {/* Stats */}
                <div className="grid-4" style={{ marginBottom: 'var(--space-2xl)' }}>
                    <div className="stat-card">
                        <div className="stat-card-label">Total Projects</div>
                        <div className="stat-card-value">{projects.length}</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-card-label">Completed</div>
                        <div className="stat-card-value" style={{ color: 'var(--success)' }}>
                            {projects.filter(p => p.status === 'completed').length}
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-card-label">In Production</div>
                        <div className="stat-card-value" style={{ color: 'var(--accent-gold)' }}>
                            {projects.filter(p => p.status === 'in-production').length}
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-card-label">Upcoming</div>
                        <div className="stat-card-value" style={{ color: 'var(--accent-blue, #60a5fa)' }}>
                            {projects.filter(p => p.status === 'upcoming').length}
                        </div>
                    </div>
                </div>

                {loading ? (
                    <div style={{ padding: 'var(--space-4xl)', textAlign: 'center', color: 'var(--text-tertiary)' }}>
                        <div className="loading-spinner" style={{ margin: '0 auto var(--space-md)' }} />
                        Loading projects...
                    </div>
                ) : projects.length === 0 ? (
                    <div style={{
                        padding: 'var(--space-4xl) var(--space-2xl)',
                        textAlign: 'center',
                        color: 'var(--text-tertiary)',
                        background: 'linear-gradient(180deg, var(--bg-secondary) 0%, rgba(13,15,20,0.6) 100%)',
                        borderRadius: 'var(--radius-xl)',
                        border: '1px solid var(--border-subtle)',
                        position: 'relative',
                        overflow: 'hidden',
                    }}>
                        {/* Decorative top gold line */}
                        <div style={{
                            position: 'absolute', top: 0, left: '25%', right: '25%', height: '2px',
                            background: 'linear-gradient(90deg, transparent, var(--accent-gold), transparent)',
                        }} />
                        <div style={{
                            fontSize: '3.5rem', marginBottom: 'var(--space-lg)',
                            filter: 'drop-shadow(0 4px 12px rgba(212,168,83,0.2))',
                        }}>🎬</div>
                        <h3 style={{
                            fontSize: '1.4rem', fontWeight: 800, color: 'var(--text-primary)',
                            marginBottom: 'var(--space-xs)',
                        }}>
                            Your <span style={{
                                fontFamily: 'var(--font-serif)', fontStyle: 'italic',
                                background: 'linear-gradient(135deg, var(--accent-gold-light), var(--accent-gold))',
                                WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
                                backgroundClip: 'text',
                            }}>stage</span> awaits
                        </h3>
                        <p style={{
                            maxWidth: '380px', margin: '0 auto', lineHeight: 1.7,
                            fontSize: '0.9rem', marginBottom: 'var(--space-xl)',
                        }}>
                            Every great studio starts with its first project. Add a film, series, or short and bring your vision to life.
                        </p>
                        <button onClick={openCreate} className="btn btn-primary btn-lg" style={{ gap: '6px' }}>
                            + Create Your First Project
                        </button>
                        <div style={{
                            fontSize: '0.72rem', color: 'var(--text-tertiary)', marginTop: 'var(--space-lg)',
                            opacity: 0.6, display: 'flex', justifyContent: 'center', alignItems: 'center',
                            gap: '4px', width: '100%',
                        }}>
                            💡 Tip: Add a cover image and trailer to make your project shine on the public site.
                        </div>
                    </div>
                ) : (
                    <div className="grid-auto-fill">
                        {projects.map((project) => {
                            const status = statusConfig[project.status] || statusConfig.upcoming
                            return (
                                <div key={project.id} className="glass-card" style={{ overflow: 'hidden', opacity: deleting === project.id ? 0.4 : 1, transition: 'opacity 0.3s' }}>
                                    {/* Cover Image */}
                                    <div style={{
                                        height: '160px',
                                        backgroundImage: project.coverImage ? `url(${project.coverImage})` : 'linear-gradient(135deg, var(--bg-tertiary), var(--bg-secondary))',
                                        backgroundSize: 'cover', backgroundPosition: 'center', position: 'relative',
                                    }}>
                                        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(180deg, transparent 50%, var(--bg-glass) 100%)' }} />
                                        <div style={{ position: 'absolute', top: 'var(--space-md)', right: 'var(--space-md)', display: 'flex', gap: '4px' }}>
                                            <span className={`badge ${status.className}`}>{status.label}</span>
                                            {project.featured && <span className="badge badge-gold">★ Featured</span>}
                                        </div>
                                    </div>

                                    {/* Content */}
                                    <div style={{ padding: 'var(--space-lg)' }}>
                                        <h3 style={{ marginBottom: '4px' }}>{project.title}</h3>
                                        <div style={{ fontSize: '0.8rem', color: 'var(--text-tertiary)', marginBottom: 'var(--space-md)' }}>
                                            {project.genre} {project.year ? `• ${project.year}` : ''} {project.duration ? `• ${project.duration}` : ''}
                                        </div>
                                        <p style={{ fontSize: '0.85rem', lineHeight: 1.6, marginBottom: 'var(--space-md)' }}>
                                            {project.description.length > 120 ? project.description.slice(0, 120) + '...' : project.description}
                                        </p>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                            <span style={{ fontSize: '0.75rem', color: 'var(--text-tertiary)' }}>
                                                {project._count.castingCalls} casting call{project._count.castingCalls !== 1 ? 's' : ''}
                                            </span>
                                            <div style={{ display: 'flex', gap: '4px', alignItems: 'center' }}>
                                                {/* CC / Subtitle button */}
                                                {project.filmUrl && (
                                                    <button
                                                        onClick={async () => {
                                                            if (subtitleStatus[project.id]?.startsWith('✓')) return
                                                            setSubtitleStatus(s => ({ ...s, [project.id]: '⏳ Loading engine...' }))
                                                            setSubtitleProgress(s => ({ ...s, [project.id]: 0 }))
                                                            try {
                                                                const result = await transcribeVideo(project.filmUrl!, (status, detail) => {
                                                                    setSubtitleStatus(s => ({ ...s, [project.id]: `⏳ ${detail || status}` }))
                                                                    const phaseProgress: Record<string, number> = {
                                                                        'loading-ffmpeg': 5, 'extracting-audio': 15,
                                                                        'loading-model': 25, 'transcribing': 40,
                                                                    }
                                                                    setSubtitleProgress(s => ({ ...s, [project.id]: phaseProgress[status] || s[project.id] || 0 }))
                                                                })
                                                                setSubtitleProgress(s => ({ ...s, [project.id]: 50 }))
                                                                setSubtitleStatus(s => ({ ...s, [project.id]: '🌐 Translating...' }))
                                                                const translations = await translateToAllLanguages(result.segments, 'en', (ts) => {
                                                                    setSubtitleStatus(s => ({ ...s, [project.id]: `🌐 ${ts.detail || ts.languageName}` }))
                                                                    setSubtitleProgress(s => ({ ...s, [project.id]: 50 + Math.round(ts.progress * 0.45) }))
                                                                })
                                                                setSubtitleProgress(s => ({ ...s, [project.id]: 97 }))
                                                                setSubtitleStatus(s => ({ ...s, [project.id]: '💾 Saving...' }))
                                                                await fetch('/api/admin/subtitles', {
                                                                    method: 'POST',
                                                                    headers: { 'Content-Type': 'application/json' },
                                                                    body: JSON.stringify({
                                                                        projectId: project.id,
                                                                        language: 'en',
                                                                        segments: result.segments,
                                                                        translations,
                                                                        status: 'completed',
                                                                    }),
                                                                })
                                                                setSubtitleProgress(s => ({ ...s, [project.id]: 100 }))
                                                                setSubtitleStatus(s => ({ ...s, [project.id]: '✓ Subtitles ready' }))
                                                            } catch (err) {
                                                                setSubtitleStatus(s => ({ ...s, [project.id]: '❌ Failed' }))
                                                                setSubtitleProgress(s => ({ ...s, [project.id]: 0 }))
                                                            }
                                                        }}
                                                        disabled={!!subtitleStatus[project.id]?.startsWith('⏳') || !!subtitleStatus[project.id]?.startsWith('🌐')}
                                                        className="btn btn-ghost btn-sm"
                                                        title="Generate multi-language subtitles"
                                                        style={{
                                                            fontSize: '0.65rem', fontWeight: 700,
                                                            color: subtitleStatus[project.id]?.startsWith('✓') ? 'var(--accent-gold)' : undefined,
                                                        }}
                                                    >
                                                        {subtitleStatus[project.id] || 'CC'}
                                                    </button>
                                                )}
                                                <button onClick={() => openEdit(project)} className="btn btn-ghost btn-sm">Edit</button>
                                                <button
                                                    onClick={() => handleDelete(project.id, project.title)}
                                                    disabled={deleting === project.id}
                                                    className="btn btn-ghost btn-sm"
                                                    style={{ color: 'var(--error)' }}
                                                >
                                                    {deleting === project.id ? '...' : '✕'}
                                                </button>
                                            </div>
                                        </div>
                                        {/* Progress bar for subtitle generation */}
                                        {subtitleProgress[project.id] > 0 && subtitleProgress[project.id] < 100 && (
                                            <div style={{ marginTop: '6px' }}>
                                                <div style={{
                                                    height: '4px', borderRadius: '2px',
                                                    background: 'rgba(255,255,255,0.08)',
                                                    overflow: 'hidden',
                                                }}>
                                                    <div style={{
                                                        height: '100%', borderRadius: '2px',
                                                        background: 'linear-gradient(90deg, var(--accent-gold), #e8c547)',
                                                        width: `${subtitleProgress[project.id]}%`,
                                                        transition: 'width 0.4s ease',
                                                        boxShadow: '0 0 8px rgba(212,168,83,0.4)',
                                                    }} />
                                                </div>
                                                <div style={{
                                                    fontSize: '0.6rem', color: 'var(--text-tertiary)',
                                                    marginTop: '2px', display: 'flex',
                                                    justifyContent: 'space-between',
                                                }}>
                                                    <span>{subtitleStatus[project.id]?.replace(/^[⏳🌐💾✓❌]\s?/, '')}</span>
                                                    <span>{subtitleProgress[project.id]}%</span>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )
                        })}
                    </div>
                )}
            </main>

            {/* ── Modal ── */}
            {showModal && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 1000,
                    background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    padding: 'var(--space-xl)',
                }} onClick={() => setShowModal(false)}>
                    <div
                        onClick={e => e.stopPropagation()}
                        style={{
                            background: 'var(--bg-secondary)',
                            border: '1px solid var(--border-subtle)',
                            borderRadius: 'var(--radius-xl)',
                            padding: 'var(--space-xl)',
                            width: '100%', maxWidth: '600px', maxHeight: '85vh', overflowY: 'auto',
                        }}
                    >
                        <h2 style={{ marginBottom: 'var(--space-lg)', fontSize: '1.2rem' }}>
                            {editingId ? '✏️ Edit Project' : '🎬 New Project'}
                        </h2>

                        <form onSubmit={handleSave}>
                            <div className="admin-form-stack" style={{ gap: 'var(--space-md)' }}>
                                {/* Title + Slug */}
                                <div className="admin-form-grid">
                                    <div>
                                        <label className="admin-label">Title *</label>
                                        <input className="admin-input" value={form.title}
                                            onChange={e => { updateField('title', e.target.value); if (!editingId) updateField('slug', slugify(e.target.value)) }}
                                            placeholder="e.g. Neon Saints" required />
                                    </div>
                                    <div>
                                        <label className="admin-label">Slug</label>
                                        <input className="admin-input" value={form.slug}
                                            onChange={e => updateField('slug', e.target.value)}
                                            placeholder="auto-generated" style={{ color: 'var(--text-tertiary)' }} />
                                    </div>
                                </div>

                                {/* Tagline */}
                                <div>
                                    <label className="admin-label">Tagline</label>
                                    <input className="admin-input" value={form.tagline}
                                        onChange={e => updateField('tagline', e.target.value)}
                                        placeholder="A short hook for the project..." />
                                </div>

                                {/* Description */}
                                <div>
                                    <label className="admin-label">Description *</label>
                                    <textarea className="admin-textarea" rows={4} value={form.description}
                                        onChange={e => updateField('description', e.target.value)}
                                        placeholder="Full synopsis or description of the project..." required />
                                </div>

                                {/* Genre, Year, Duration */}
                                <div className="admin-form-grid" style={{ gridTemplateColumns: '1fr 1fr 1fr' }}>
                                    <div>
                                        <label className="admin-label">Genre</label>
                                        <input className="admin-input" value={form.genre}
                                            onChange={e => updateField('genre', e.target.value)}
                                            placeholder="e.g. Sci-Fi Thriller" />
                                    </div>
                                    <div>
                                        <label className="admin-label">Year</label>
                                        <input className="admin-input" value={form.year}
                                            onChange={e => updateField('year', e.target.value)}
                                            placeholder="e.g. 2026" />
                                    </div>
                                    <div>
                                        <label className="admin-label">Duration</label>
                                        <input className="admin-input" value={form.duration}
                                            onChange={e => updateField('duration', e.target.value)}
                                            placeholder="e.g. 12 min" />
                                    </div>
                                </div>

                                {/* Status + Featured */}
                                <div className="admin-form-grid">
                                    <div>
                                        <label className="admin-label">Status</label>
                                        <select className="admin-input" value={form.status}
                                            onChange={e => updateField('status', e.target.value)}
                                            style={{ cursor: 'pointer', appearance: 'auto' }}>
                                            {STATUSES.map(s => (
                                                <option key={s} value={s}>
                                                    {s === 'in-production' ? 'In Production' : s.charAt(0).toUpperCase() + s.slice(1)}
                                                </option>
                                            ))}
                                        </select>
                                    </div>
                                    <div style={{ display: 'flex', alignItems: 'flex-end', paddingBottom: '8px' }}>
                                        <label style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-sm)', cursor: 'pointer', fontSize: '0.88rem', color: 'var(--text-secondary)' }}>
                                            <input type="checkbox" checked={form.featured}
                                                onChange={e => updateField('featured', e.target.checked)}
                                                style={{ width: '18px', height: '18px', accentColor: 'var(--accent-gold)' }} />
                                            ★ Featured on homepage
                                        </label>
                                    </div>
                                </div>

                                {/* Cover Image — Drag & Drop */}
                                <FileUploader
                                    label="Cover Image"
                                    accept="image/*"
                                    category="covers"
                                    currentUrl={form.coverImage}
                                    onUpload={url => updateField('coverImage', url)}
                                    maxSizeMB={10}
                                    compact
                                />

                                {/* Media Section */}
                                <div style={{ borderTop: '1px solid var(--border-subtle)', paddingTop: 'var(--space-md)' }}>
                                    <div style={{ fontSize: '0.72rem', fontWeight: 600, letterSpacing: '0.1em', textTransform: 'uppercase' as const, color: 'var(--accent-gold)', marginBottom: 'var(--space-md)' }}>
                                        Media & Content
                                    </div>
                                    <div className="admin-form-grid">
                                        <div>
                                            <label className="admin-label">Project Type</label>
                                            <select className="admin-input" value={form.projectType}
                                                onChange={e => updateField('projectType', e.target.value)}
                                                style={{ cursor: 'pointer', appearance: 'auto' }}>
                                                <option value="movie">Movie</option>
                                                <option value="series">Series</option>
                                            </select>
                                        </div>
                                        <div />
                                    </div>

                                    {/* Trailer — Drag & Drop */}
                                    <div style={{ marginTop: 'var(--space-md)' }}>
                                        <FileUploader
                                            label="Trailer (public)"
                                            accept="video/*"
                                            category="trailers"
                                            currentUrl={form.trailerUrl}
                                            onUpload={url => updateField('trailerUrl', url)}
                                            maxSizeMB={100}
                                            compact
                                        />
                                    </div>

                                    {/* Full Film — Drag & Drop */}
                                    <div style={{ marginTop: 'var(--space-md)' }}>
                                        <FileUploader
                                            label="Full Film (members only)"
                                            accept="video/*"
                                            category="films"
                                            currentUrl={form.filmUrl}
                                            onUpload={url => updateField('filmUrl', url)}
                                            maxSizeMB={500}
                                        />
                                        <div style={{ fontSize: '0.72rem', color: 'var(--text-tertiary)', marginTop: '4px' }}>
                                            When set, a &quot;Watch Now&quot; button appears on the project page (login required).
                                        </div>
                                    </div>
                                </div>

                                {error && (
                                    <div style={{
                                        fontSize: '0.85rem', fontWeight: 600, padding: '0.4rem 0.8rem', borderRadius: 'var(--radius-md)',
                                        color: 'var(--error)', background: 'rgba(239,68,68,0.1)',
                                    }}>✗ {error}</div>
                                )}

                                <div style={{ display: 'flex', gap: 'var(--space-md)', justifyContent: 'flex-end', paddingTop: 'var(--space-md)', borderTop: '1px solid var(--border-subtle)' }}>
                                    <button type="button" onClick={() => setShowModal(false)} className="btn btn-ghost">Cancel</button>
                                    <button type="submit" className="btn btn-primary" disabled={saving}>
                                        {saving ? 'Saving...' : editingId ? '💾 Update' : '🎬 Create'}
                                    </button>
                                </div>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'

interface ScriptCall {
    id: string
    title: string
    description: string
    genre: string | null
    targetLength: string | null
    status: string
    isPublic: boolean
    deadline: string | null
    maxSubmissions: number
    toneKeywords: string | null
    projectId: string | null
    project: { title: string } | null
    _count: { submissions: number }
    createdAt: string
}

interface Project { id: string; title: string }

const STATUS_META: Record<string, { color: string; bg: string; icon: string }> = {
    draft: { color: '#94a3b8', bg: 'rgba(148,163,184,0.08)', icon: '📝' },
    open: { color: '#34d399', bg: 'rgba(52,211,153,0.08)', icon: '📖' },
    closed: { color: '#f59e0b', bg: 'rgba(245,158,11,0.08)', icon: '🔒' },
    archived: { color: '#64748b', bg: 'rgba(100,116,139,0.08)', icon: '📦' },
}

const NAV = [
    { href: '/admin/analytics', label: '📊 Analytics' },
    { href: '/admin/projects', label: '🎬 Projects' },
    { href: '/admin/casting', label: '🎭 Casting' },
    { href: '/admin/applications', label: '📋 Applications' },
    { href: '/admin/media', label: '🖼️ Page Media' },
    { href: '/admin/sponsors', label: '🤝 Sponsors' },
    { href: '/admin/donations', label: '💰 Donations' },
    { href: '/admin/users', label: '👥 Users' },
    { href: '/admin/scripts', label: '✍️ Scripts' },
    { href: '/admin/training', label: '🎓 Training' },
    { href: '/admin/settings', label: '⚙️ Settings' },
]

export default function AdminScriptsPage() {
    const [calls, setCalls] = useState<ScriptCall[]>([])
    const [projects, setProjects] = useState<Project[]>([])
    const [loading, setLoading] = useState(true)
    const [showCreate, setShowCreate] = useState(false)
    const [form, setForm] = useState({
        title: '', description: '', genre: '', toneKeywords: '',
        targetLength: '', projectId: '', deadline: '',
        maxSubmissions: 100, isPublic: false, status: 'draft',
    })
    const [saving, setSaving] = useState(false)
    const [filter, setFilter] = useState<string>('all')
    const [scriptsEnabled, setScriptsEnabled] = useState(false)
    const [togglingScripts, setTogglingScripts] = useState(false)

    const fetchCalls = useCallback(async () => {
        const res = await fetch('/api/script-calls')
        if (res.ok) setCalls(await res.json())
        setLoading(false)
    }, [])

    useEffect(() => {
        fetchCalls()
        fetch('/api/admin/projects').then(r => r.json()).then(p => setProjects(Array.isArray(p) ? p : [])).catch(() => {})
        // Fetch scripts toggle
        fetch('/api/admin/toggles').then(r => r.json()).then(s => {
            if (typeof s.scriptCallsEnabled === 'boolean') setScriptsEnabled(s.scriptCallsEnabled)
        }).catch(() => {})
    }, [fetchCalls])

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault(); setSaving(true)
        const res = await fetch('/api/script-calls', {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ ...form, projectId: form.projectId || null, maxSubmissions: Number(form.maxSubmissions) }),
        })
        if (res.ok) {
            setShowCreate(false)
            setForm({ title: '', description: '', genre: '', toneKeywords: '', targetLength: '', projectId: '', deadline: '', maxSubmissions: 100, isPublic: false, status: 'draft' })
            fetchCalls()
        }
        setSaving(false)
    }

    const togglePublic = async (call: ScriptCall) => {
        await fetch(`/api/script-calls/${call.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ isPublic: !call.isPublic }) })
        fetchCalls()
    }

    const updateStatus = async (call: ScriptCall, status: string) => {
        await fetch(`/api/script-calls/${call.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ status }) })
        fetchCalls()
    }

    const deleteCall = async (id: string) => {
        if (!confirm('Delete this script call and all its submissions?')) return
        await fetch(`/api/script-calls/${id}`, { method: 'DELETE' })
        fetchCalls()
    }

    const filtered = filter === 'all' ? calls : calls.filter(c => c.status === filter)
    const totalSubs = calls.reduce((s, c) => s + c._count.submissions, 0)
    const openCount = calls.filter(c => c.status === 'open').length

    const inp: React.CSSProperties = {
        width: '100%', padding: '8px 12px', background: 'rgba(255,255,255,0.04)',
        border: '1px solid rgba(255,255,255,0.08)', borderRadius: '8px',
        color: 'var(--text-primary)', fontSize: '0.82rem', fontFamily: 'inherit',
    }
    const lbl: React.CSSProperties = {
        display: 'block', fontSize: '0.6rem', fontWeight: 700,
        textTransform: 'uppercase', letterSpacing: '0.08em',
        color: 'var(--text-tertiary)', marginBottom: '4px',
    }

    return (
        <div className="admin-layout">
            <aside className="admin-sidebar">
                <div className="admin-sidebar-logo">
                    <Link href="/" style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 800 }}>
                        <span style={{ color: 'var(--accent-gold)' }}>AIM</span> Studio
                    </Link>
                    <div style={{ fontSize: '0.7rem', color: 'var(--text-tertiary)', marginTop: '2px' }}>Admin Panel</div>
                </div>
                <ul className="admin-sidebar-nav">
                    {NAV.map(n => (
                        <li key={n.href}><Link href={n.href} className={n.href === '/admin/scripts' ? 'active' : ''}>{n.label}</Link></li>
                    ))}
                </ul>
            </aside>

            <main className="admin-main">
                {/* ─── HEADER ─── */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '20px', flexWrap: 'wrap', gap: '12px' }}>
                    <div>
                        <h1 style={{ fontSize: '1.3rem', fontWeight: 800, margin: 0 }}>✍️ Script Calls</h1>
                        <p style={{ fontSize: '0.75rem', color: 'var(--text-tertiary)', marginTop: '3px' }}>
                            Manage screenplay submission calls · AI-powered script analysis
                        </p>
                    </div>
                    <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                        <button
                            onClick={async () => {
                                setTogglingScripts(true)
                                try {
                                    const nv = !scriptsEnabled
                                    const res = await fetch('/api/admin/toggles', {
                                        method: 'PUT',
                                        headers: { 'Content-Type': 'application/json' },
                                        body: JSON.stringify({ scriptCallsEnabled: nv }),
                                    })
                                    if (res.ok) setScriptsEnabled(nv)
                                    else alert('Failed to toggle')
                                } catch { alert('Failed to toggle') }
                                setTogglingScripts(false)
                            }}
                            disabled={togglingScripts}
                            style={{
                                padding: '6px 16px', fontSize: '0.78rem', fontWeight: 700,
                                borderRadius: '8px', border: 'none', cursor: 'pointer',
                                background: scriptsEnabled ? 'rgba(52,211,153,0.12)' : 'rgba(239,68,68,0.12)',
                                color: scriptsEnabled ? '#34d399' : '#ef4444',
                                transition: 'all 0.2s',
                            }}
                        >
                            {togglingScripts ? '...' : scriptsEnabled ? '🟢 Scripts Live' : '🔴 Scripts Hidden'}
                        </button>
                        <button onClick={() => setShowCreate(!showCreate)} style={{
                            padding: '8px 18px', fontSize: '0.78rem', fontWeight: 700, borderRadius: '8px',
                            border: showCreate ? '1px solid rgba(239,68,68,0.3)' : '1px solid rgba(212,168,83,0.3)',
                            background: showCreate ? 'rgba(239,68,68,0.08)' : 'linear-gradient(135deg, rgba(212,168,83,0.15), rgba(212,168,83,0.05))',
                            color: showCreate ? '#ef4444' : 'var(--accent-gold)', cursor: 'pointer',
                        }}>
                            {showCreate ? '✕ Cancel' : '+ New Script Call'}
                        </button>
                    </div>
                </div>

                {/* ─── STATS BAR ─── */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '8px', marginBottom: '16px' }}>
                    {[
                        { label: 'Total Calls', value: calls.length, icon: '📜', color: 'var(--accent-gold)' },
                        { label: 'Open', value: openCount, icon: '📖', color: '#34d399' },
                        { label: 'Submissions', value: totalSubs, icon: '📄', color: '#60a5fa' },
                        { label: 'Projects Linked', value: calls.filter(c => c.projectId).length, icon: '🎬', color: '#a78bfa' },
                    ].map(s => (
                        <div key={s.label} style={{
                            padding: '12px', borderRadius: '10px', textAlign: 'center',
                            background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)',
                        }}>
                            <div style={{ fontSize: '0.9rem', marginBottom: '2px' }}>{s.icon}</div>
                            <div style={{ fontSize: '1.2rem', fontWeight: 800, color: s.color }}>{s.value}</div>
                            <div style={{ fontSize: '0.55rem', color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{s.label}</div>
                        </div>
                    ))}
                </div>

                {/* ─── FILTER TABS ─── */}
                <div style={{ display: 'flex', gap: '4px', marginBottom: '16px', overflowX: 'auto' }}>
                    {['all', 'draft', 'open', 'closed', 'archived'].map(f => (
                        <button key={f} onClick={() => setFilter(f)} style={{
                            padding: '5px 14px', fontSize: '0.68rem', fontWeight: 600, borderRadius: '6px',
                            border: 'none', cursor: 'pointer', textTransform: 'capitalize',
                            background: filter === f ? 'var(--accent-gold-glow)' : 'rgba(255,255,255,0.03)',
                            color: filter === f ? 'var(--accent-gold)' : 'var(--text-tertiary)',
                            borderBottom: filter === f ? '2px solid var(--accent-gold)' : '2px solid transparent',
                        }}>
                            {f === 'all' ? `All (${calls.length})` : `${f} (${calls.filter(c => c.status === f).length})`}
                        </button>
                    ))}
                </div>

                {/* ─── CREATE FORM ─── */}
                {showCreate && (
                    <form onSubmit={handleCreate} style={{
                        padding: '16px', marginBottom: '16px', borderRadius: '12px',
                        background: 'linear-gradient(135deg, rgba(212,168,83,0.04), rgba(139,92,246,0.03))',
                        border: '1px solid rgba(212,168,83,0.12)',
                    }}>
                        <div style={{ fontSize: '0.65rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--accent-gold)', marginBottom: '12px' }}>
                            📝 New Script Call
                        </div>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label style={lbl}>Title *</label>
                                <input style={inp} value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} required placeholder="e.g. Original Sci-Fi Short Film Screenplay" />
                            </div>
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label style={lbl}>Description *</label>
                                <textarea style={{ ...inp, minHeight: '70px', resize: 'vertical' }} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} required placeholder="Describe what you're looking for..." />
                            </div>
                            <div>
                                <label style={lbl}>Genre</label>
                                <input style={inp} value={form.genre} onChange={e => setForm(f => ({ ...f, genre: e.target.value }))} placeholder="e.g. Sci-Fi Thriller" />
                            </div>
                            <div>
                                <label style={lbl}>Target Length</label>
                                <input style={inp} value={form.targetLength} onChange={e => setForm(f => ({ ...f, targetLength: e.target.value }))} placeholder="e.g. Short Film 10-15 min" />
                            </div>
                            <div>
                                <label style={lbl}>Tone Keywords</label>
                                <input style={inp} value={form.toneKeywords} onChange={e => setForm(f => ({ ...f, toneKeywords: e.target.value }))} placeholder="dark, suspenseful, poetic" />
                            </div>
                            <div>
                                <label style={lbl}>Deadline</label>
                                <input style={inp} type="date" value={form.deadline} onChange={e => setForm(f => ({ ...f, deadline: e.target.value }))} />
                            </div>
                            <div>
                                <label style={lbl}>Linked Project</label>
                                <select style={inp} value={form.projectId} onChange={e => setForm(f => ({ ...f, projectId: e.target.value }))}>
                                    <option value="">None (general call)</option>
                                    {projects.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                                </select>
                            </div>
                            <div>
                                <label style={lbl}>Max Submissions</label>
                                <input style={inp} type="number" value={form.maxSubmissions} onChange={e => setForm(f => ({ ...f, maxSubmissions: Number(e.target.value) }))} />
                            </div>
                            <div style={{ gridColumn: '1 / -1', display: 'flex', alignItems: 'center', gap: '16px' }}>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '6px', cursor: 'pointer', fontSize: '0.78rem', color: 'var(--text-secondary)' }}>
                                    <input type="checkbox" checked={form.isPublic} onChange={e => setForm(f => ({ ...f, isPublic: e.target.checked }))} />
                                    Make Public
                                </label>
                                <select style={{ ...inp, width: 'auto', padding: '6px 12px' }} value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))}>
                                    <option value="draft">Draft</option>
                                    <option value="open">Open</option>
                                    <option value="closed">Closed</option>
                                </select>
                                <div style={{ flex: 1 }} />
                                <button type="submit" disabled={saving} style={{
                                    padding: '8px 20px', fontSize: '0.78rem', fontWeight: 700, borderRadius: '8px',
                                    border: '1px solid rgba(212,168,83,0.3)', cursor: 'pointer',
                                    background: 'linear-gradient(135deg, rgba(212,168,83,0.2), rgba(212,168,83,0.08))',
                                    color: 'var(--accent-gold)', opacity: saving ? 0.6 : 1,
                                }}>
                                    {saving ? 'Creating...' : '✨ Create'}
                                </button>
                            </div>
                        </div>
                    </form>
                )}

                {/* ─── CALLS LIST ─── */}
                {loading ? (
                    <div style={{ textAlign: 'center', padding: '40px', color: 'var(--text-tertiary)' }}>Loading...</div>
                ) : filtered.length === 0 ? (
                    <div style={{
                        textAlign: 'center', padding: '40px 20px', borderRadius: '12px',
                        background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)',
                    }}>
                        <div style={{ fontSize: '2rem', opacity: 0.3, marginBottom: '8px' }}>✍️</div>
                        <div style={{ fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '4px' }}>
                            {filter === 'all' ? 'No script calls yet' : `No ${filter} script calls`}
                        </div>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-tertiary)' }}>
                            {filter === 'all' ? 'Create your first script call to start receiving screenplay submissions.' : 'Try a different filter.'}
                        </div>
                    </div>
                ) : (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {filtered.map(call => {
                            const meta = STATUS_META[call.status] || STATUS_META.draft
                            const daysLeft = call.deadline ? Math.ceil((new Date(call.deadline).getTime() - Date.now()) / 86400000) : null

                            return (
                                <div key={call.id} style={{
                                    padding: '14px', borderRadius: '10px',
                                    background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)',
                                    transition: 'all 0.2s',
                                }}>
                                    {/* Top Row: Title + Badges */}
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '6px', flexWrap: 'wrap' }}>
                                        <Link href={`/admin/scripts/${call.id}`} style={{
                                            fontSize: '0.92rem', fontWeight: 700, color: 'var(--text-primary)',
                                            textDecoration: 'none', flex: 1, minWidth: 0,
                                        }}>
                                            {call.title}
                                        </Link>
                                        <span style={{
                                            fontSize: '0.52rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.04em',
                                            padding: '2px 8px', borderRadius: '4px',
                                            color: meta.color, background: meta.bg, border: `1px solid ${meta.color}25`,
                                        }}>
                                            {meta.icon} {call.status}
                                        </span>
                                        {call.isPublic && (
                                            <span style={{ fontSize: '0.52rem', fontWeight: 700, padding: '2px 8px', borderRadius: '4px', color: '#34d399', background: 'rgba(52,211,153,0.08)', border: '1px solid rgba(52,211,153,0.15)' }}>
                                                🌐 Public
                                            </span>
                                        )}
                                    </div>

                                    {/* Meta Row */}
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', fontSize: '0.72rem', color: 'var(--text-tertiary)', marginBottom: '8px', flexWrap: 'wrap' }}>
                                        {call.genre && <span>🎬 {call.genre}</span>}
                                        <span>📄 {call._count.submissions} submission{call._count.submissions !== 1 ? 's' : ''}</span>
                                        {call.project && <span>🎯 {call.project.title}</span>}
                                        {call.targetLength && <span>⏱️ {call.targetLength}</span>}
                                        {daysLeft !== null && (
                                            <span style={{ color: daysLeft <= 3 ? '#ef4444' : daysLeft <= 7 ? '#f59e0b' : 'var(--text-tertiary)' }}>
                                                ⏰ {daysLeft > 0 ? `${daysLeft}d left` : 'Expired'}
                                            </span>
                                        )}
                                        {call.toneKeywords && (
                                            <div style={{ display: 'flex', gap: '3px', flexWrap: 'wrap' }}>
                                                {call.toneKeywords.split(',').slice(0, 3).map((t, i) => (
                                                    <span key={i} style={{
                                                        fontSize: '0.58rem', padding: '1px 6px', borderRadius: '3px',
                                                        background: 'rgba(139,92,246,0.08)', color: '#a78bfa',
                                                    }}>{t.trim()}</span>
                                                ))}
                                            </div>
                                        )}
                                    </div>

                                    {/* Description preview */}
                                    {call.description && (
                                        <div style={{
                                            fontSize: '0.75rem', color: 'var(--text-secondary)', lineHeight: 1.5,
                                            maxHeight: '36px', overflow: 'hidden', marginBottom: '10px',
                                        }}>
                                            {call.description}
                                        </div>
                                    )}

                                    {/* Actions Row */}
                                    <div style={{ display: 'flex', gap: '6px', alignItems: 'center', flexWrap: 'wrap' }}>
                                        <Link href={`/admin/scripts/${call.id}`} style={{
                                            padding: '4px 12px', fontSize: '0.68rem', fontWeight: 600, borderRadius: '6px',
                                            background: 'rgba(212,168,83,0.08)', border: '1px solid rgba(212,168,83,0.15)',
                                            color: 'var(--accent-gold)', textDecoration: 'none',
                                        }}>
                                            View Submissions ({call._count.submissions})
                                        </Link>
                                        <button onClick={() => togglePublic(call)} style={{
                                            padding: '4px 10px', fontSize: '0.68rem', fontWeight: 600, borderRadius: '6px',
                                            background: call.isPublic ? 'rgba(52,211,153,0.06)' : 'rgba(255,255,255,0.02)',
                                            border: `1px solid ${call.isPublic ? 'rgba(52,211,153,0.15)' : 'rgba(255,255,255,0.06)'}`,
                                            color: call.isPublic ? '#34d399' : 'var(--text-tertiary)', cursor: 'pointer',
                                        }}>
                                            {call.isPublic ? '🌐 Public' : '🔒 Private'}
                                        </button>
                                        <select value={call.status} onChange={e => updateStatus(call, e.target.value)}
                                            style={{
                                                padding: '4px 8px', fontSize: '0.68rem', borderRadius: '6px',
                                                background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.06)',
                                                color: 'var(--text-secondary)', cursor: 'pointer',
                                            }}>
                                            <option value="draft">Draft</option>
                                            <option value="open">Open</option>
                                            <option value="closed">Closed</option>
                                            <option value="archived">Archived</option>
                                        </select>
                                        <div style={{ flex: 1 }} />
                                        <button onClick={() => deleteCall(call.id)} style={{
                                            padding: '4px 8px', fontSize: '0.68rem', fontWeight: 600, borderRadius: '6px',
                                            background: 'rgba(239,68,68,0.05)', border: '1px solid rgba(239,68,68,0.12)',
                                            color: '#ef4444', cursor: 'pointer',
                                        }}>✕</button>
                                    </div>
                                </div>
                            )
                        })}
                    </div>
                )}
            </main>
        </div>
    )
}

