                                            },
                                            {
                                                id: 'analytics', icon: '📊', title: 'Analytics Agent',
                                                desc: 'Generates traffic and engagement insights',
                                                keyCount: apiKeys.filter(k => k.isActive && (k.assignedAgent === 'analytics' || k.assignedAgent === 'all')).length,
