import { NextResponse } from 'next/server'
import { requireAdmin } from '@/lib/auth'
import { prisma } from '@/lib/db'
import { translateAndSave } from '@/lib/translate'

export async function GET() {
    try { await requireAdmin() } catch { return NextResponse.json({ error: 'Forbidden' }, { status: 403 }) }

    const courses = await prisma.course.findMany({
        orderBy: { sortOrder: 'asc' },
        include: {
            modules: {
                orderBy: { sortOrder: 'asc' },
                include: {
                    lessons: { orderBy: { sortOrder: 'asc' } },
                },
            },
            enrollments: true,
        },
    })

    const enriched = courses.map(c => ({
        ...c,
        totalModules: c.modules.length,
        totalLessons: c.modules.reduce((sum, m) => sum + m.lessons.length, 0),
        totalDuration: c.modules.reduce((sum, m) => sum + m.lessons.reduce((s, l) => s + (l.duration || 0), 0), 0),
        enrollmentCount: c.enrollments.length,
        completedCount: c.enrollments.filter(e => e.completedAt).length,
    }))

    return NextResponse.json(enriched)
}

export async function POST(req: Request) {
    try { await requireAdmin() } catch { return NextResponse.json({ error: 'Forbidden' }, { status: 403 }) }

    try {
        const body = await req.json()
        const slug = (body.title || 'course')
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, '-')
            .replace(/^-|-$/g, '') + '-' + Date.now().toString(36)

        const course = await prisma.course.create({
            data: {
                title: body.title || 'Untitled Course',
                slug,
                description: body.description || '',
                category: body.category || 'acting',
                level: body.level || 'beginner',
                thumbnail: body.thumbnail || null,
                published: false,
                sourceContent: body.sourceContent || null,
                translations: body.translations ? (typeof body.translations === 'string' ? body.translations : JSON.stringify(body.translations)) : null,
                modules: body.modules?.length ? {
                    create: body.modules.map((m: any, mi: number) => ({
                        title: m.title || `Module ${mi + 1}`,
                        description: m.description || null,
                        sortOrder: mi,
                        translations: m.translations ? (typeof m.translations === 'string' ? m.translations : JSON.stringify(m.translations)) : null,
                        lessons: m.lessons?.length ? {
                            create: m.lessons.map((l: any, li: number) => ({
                                title: l.title || `Lesson ${li + 1}`,
                                contentType: l.contentType || 'video',
                                contentUrl: l.contentUrl || null,
                                uploadPath: l.uploadPath || null,
                                description: l.description || null,
                                duration: l.duration ? parseInt(l.duration) || null : null,
                                sortOrder: li,
                                translations: l.translations ? (typeof l.translations === 'string' ? l.translations : JSON.stringify(l.translations)) : null,
                            })),
                        } : undefined,
                    })),
                } : undefined,
            },
            include: {
                modules: { include: { lessons: true } },
            },
        })

        // Fire-and-forget: auto-translate course content
        translateAndSave(
            { title: course.title, description: course.description },
            async (translations) => {
                await prisma.course.update({ where: { id: course.id }, data: { translations } })
            }
        )

        // Also translate each module and lesson
        for (const mod of course.modules) {
            if (mod.title || mod.description) {
                translateAndSave(
                    { title: mod.title, ...(mod.description ? { description: mod.description } : {}) },
                    async (translations) => {
                        await prisma.courseModule.update({ where: { id: mod.id }, data: { translations } })
                    }
                )
            }
            for (const lesson of mod.lessons) {
                if (lesson.title || lesson.description) {
                    translateAndSave(
                        { title: lesson.title, ...(lesson.description ? { description: lesson.description } : {}) },
                        async (translations) => {
                            await prisma.lesson.update({ where: { id: lesson.id }, data: { translations } })
                        }
                    )
                }
            }
        }

        return NextResponse.json(course, { status: 201 })
    } catch (err) {
        console.error('Training POST error:', err)
        return NextResponse.json({ error: 'Create failed', details: String(err) }, { status: 500 })
    }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/db'
import { createToken, createRefreshToken, setUserCookie } from '@/lib/auth'
import { cookies } from 'next/headers'
import * as jose from 'jose'

export async function POST(req: Request) {
    const formData = await req.formData()
    const code = formData.get('code') as string | null
    const idToken = formData.get('id_token') as string | null
    const userDataStr = formData.get('user') as string | null

    if (!code && !idToken) {
        return NextResponse.redirect(new URL('/login?error=no_code', req.url))
    }

    try {
        const settings = await prisma.siteSettings.findFirst()
        const s = settings as Record<string, string> | null
        const clientId = s?.appleClientId || ''
        const teamId = s?.appleTeamId || ''
        const keyId = s?.appleKeyId || ''
        const privateKey = s?.applePrivateKey || ''

        if (!clientId || !teamId || !keyId || !privateKey) {
            return NextResponse.redirect(new URL('/login?error=apple_not_configured', req.url))
        }

        let appleUserId = ''
        let email = ''
        let name = ''

        // Decode the id_token to get user info
        if (idToken) {
            const decoded = jose.decodeJwt(idToken)
            appleUserId = decoded.sub || ''
            email = (decoded.email as string) || ''
        }

        // Apple sends user data only on first authorization
        if (userDataStr) {
            try {
                const userData = JSON.parse(userDataStr)
                if (userData.name) {
                    name = `${userData.name.firstName || ''} ${userData.name.lastName || ''}`.trim()
                }
                if (userData.email) email = userData.email
            } catch { /* ignore parse errors */ }
        }

        if (!appleUserId) {
            return NextResponse.redirect(new URL('/login?error=apple_user_failed', req.url))
        }

        // Find or create user
        let user = await prisma.user.findFirst({
            where: {
                OR: [
                    { appleId: appleUserId },
                    ...(email ? [{ email }] : []),
                ],
            },
        })

        if (user) {
            if (!user.appleId) {
                user = await prisma.user.update({
                    where: { id: user.id },
                    data: { appleId: appleUserId },
                })
            }
        } else {
            user = await prisma.user.create({
                data: {
                    name: name || 'Apple User',
                    email: email || `apple_${appleUserId}@private.appleid.com`,
                    appleId: appleUserId,
                    role: 'member',
                },
            })
        }

        // Block admin/superadmin from using OAuth — they must log in with email + password
        if (user.role === 'admin' || user.role === 'superadmin') {
            return NextResponse.redirect(new URL('/login?error=admin_oauth_disallowed', req.url))
        }

        // Create session tokens
        const tokenPayload = {
            userId: user.id,
            role: user.role,
            email: user.email,
        }
        const token = await createToken(tokenPayload)
        const refresh = await createRefreshToken(tokenPayload)
        await setUserCookie(token, refresh)

        return NextResponse.redirect(new URL('/dashboard', req.url))
    } catch {
        return NextResponse.redirect(new URL('/login?error=apple_failed', req.url))
    }
}

/**
 * Integration tests for registration route logic.
 *
 * Because Next.js API route handlers have complex import chains,
 * we test the core business logic directly rather than importing
 * the route module itself. This matches the pattern used by auth.test.ts.
 */
