import { NextResponse } from 'next/server'
import { hash } from 'bcryptjs'
import { prisma } from '@/lib/db'
import { authLimiter } from '@/lib/rate-limit'
import { sendEmail } from '@/lib/mailer'
import { verificationEmail, welcomeEmailWithOverrides } from '@/lib/email-templates'
import { validatePassword } from '@/lib/validation'

export async function POST(request: Request) {
    const blocked = authLimiter.check(request)
    if (blocked) return blocked

    try {
        const { name, email, password } = await request.json()

        if (!name || !email || !password) {
            return NextResponse.json({ error: 'Name, email, and password are required' }, { status: 400 })
        }

        const pwCheck = validatePassword(password)
        if (!pwCheck.valid) {
            return NextResponse.json({ error: pwCheck.message }, { status: 400 })
        }

        // Check if user exists
        const existing = await prisma.user.findUnique({ where: { email } })
        if (existing) {
            // If they exist but never verified, resend a new code
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            if (!(existing as any).emailVerified) {
                const code = Math.floor(100000 + Math.random() * 900000).toString()
                const expiry = new Date(Date.now() + 15 * 60 * 1000).toISOString()
                const passwordHash = await hash(password, 12)
                await prisma.user.update({
                    where: { email },
                    data: {
                        name,                              // ← use the NEW submitted name
                        passwordHash,                      // ← update to the new password
                        verificationCode: code,
                        verificationExpiry: new Date(expiry),
                    } as any,
                })
                void sendEmail({ to: email, subject: 'Verify your AIM Studio account', html: verificationEmail(name, code) }).catch(() => {})
                if (process.env.NODE_ENV !== 'production') {
                    console.log(`[DEV] Re-sent verification code for ${email}: ${code}`)
                }
                return NextResponse.json({ requiresVerification: true, email }, { status: 200 })
            }
            return NextResponse.json({ error: 'An account with this email already exists' }, { status: 409 })
        }

        // Generate 6-digit OTP
        const code = Math.floor(100000 + Math.random() * 900000).toString()
        const expiry = new Date(Date.now() + 15 * 60 * 1000).toISOString()

        // Create user with core fields (avoids stale type-cache issues with new columns)
        const passwordHash = await hash(password, 12)
        const newUser = await prisma.user.create({
            data: {
                name,
                email,
                passwordHash,
                role: 'member',
            },
        })

        // Set verification fields via Prisma update
        await prisma.user.update({
            where: { id: newUser.id },
            data: {
                emailVerified: false,
                verificationCode: code,
                verificationExpiry: new Date(expiry),
            } as any,
        })

        // Send verification email (fire-and-forget)
        sendEmail({
            to: email,
            subject: 'Verify your AIM Studio account',
            html: verificationEmail(name, code),
        })

        // Log verification code in development so it works without SMTP
        if (process.env.NODE_ENV !== 'production') {
            console.log(`[DEV] Email verification code for ${email}: ${code}`)
        }

        return NextResponse.json({ requiresVerification: true, email })
    } catch (error) {
        console.error('Registration error:', error)
        return NextResponse.json({ error: 'Registration failed' }, { status: 500 })
    }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/db'
import { getSession } from '@/lib/auth'

async function isAdmin() {
    const session = await getSession()
    return session?.role === 'admin' || session?.role === 'superadmin'
}

// POST — admin triggers AI analysis for a specific submission
export async function POST(req: Request, { params }: { params: Promise<{ id: string }> }) {
    if (!await isAdmin()) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

    const { submissionId } = await req.json()
    if (!submissionId) return NextResponse.json({ error: 'submissionId required' }, { status: 400 })

    // Get the submission + call details
    const submission = await prisma.scriptSubmission.findUnique({
        where: { id: submissionId },
        include: { scriptCall: true },
    })

    if (!submission) return NextResponse.json({ error: 'Submission not found' }, { status: 404 })

    // Get settings for model preference
    const settings = await prisma.siteSettings.findFirst()

    // Get API keys scoped to "scripts" agent with rotation
    let keys = await prisma.apiKey.findMany({
        where: {
            isActive: true,
            provider: 'gemini',
            assignedAgent: { in: ['scripts', 'all'] },
        },
        orderBy: { lastUsed: 'asc' },
    })
    // Fallback: any active gemini key
    if (keys.length === 0) {
        keys = await prisma.apiKey.findMany({
            where: { isActive: true, provider: 'gemini' },
            orderBy: { lastUsed: 'asc' },
        })
    }
    // Last resort: settings key
    if (keys.length === 0 && settings?.geminiApiKey) {
        keys = [{ id: 'settings', key: settings.geminiApiKey, label: 'Settings Key' } as typeof keys[0]]
    }

    if (keys.length === 0) {
        return NextResponse.json({ error: 'No API keys configured. Go to Admin > Settings > API Keys.' }, { status: 400 })
    }

    // Mark as analyzing
    await prisma.scriptSubmission.update({
        where: { id: submissionId },
        data: { status: 'analyzing' },
    })

    try {
        const prompt = buildAnalysisPrompt(submission, submission.scriptCall)
        const aiModel = settings?.aiModel || 'gemini-2.5-flash'
        let lastError = ''

        for (const keyInfo of keys) {
            try {
                const response = await fetch(
                    `https://generativelanguage.googleapis.com/v1beta/models/${aiModel}:generateContent?key=${keyInfo.key}`,
                    {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({
                            contents: [{ parts: [{ text: prompt }] }],
                            generationConfig: {
                                responseMimeType: 'application/json',
                                temperature: 0.3,
                            },
                        }),
                    }
                )

                if (!response.ok) {
                    const err = await response.text()
                    lastError = `Gemini API error (${response.status}): ${err.slice(0, 200)}`
                    if (keyInfo.id !== 'settings') {
                        await prisma.apiKey.update({
                            where: { id: keyInfo.id },
                            data: { lastError: lastError.slice(0, 200), lastUsed: new Date() },
                        }).catch(() => {})
                    }
                    continue
                }

                // Record success
                if (keyInfo.id !== 'settings') {
                    await prisma.apiKey.update({
                        where: { id: keyInfo.id },
                        data: { usageCount: { increment: 1 }, lastUsed: new Date(), lastError: null },
                    }).catch(() => {})
                }

                const data = await response.json()
                const text = data.candidates?.[0]?.content?.parts?.[0]?.text
                if (!text) {
                    lastError = 'No response from AI'
                    continue
                }

                const analysis = JSON.parse(text)

                // Calculate overall score (weighted average)
                const overallScore = (
                    (analysis.originalityScore || 0) * 0.20 +
                    (analysis.structureScore || 0) * 0.20 +
                    (analysis.dialogueScore || 0) * 0.15 +
                    (analysis.visualPotentialScore || 0) * 0.15 +
                    (analysis.themeAlignmentScore || 0) * 0.15 +
                    (analysis.feasibilityScore || 0) * 0.15
                )

                // Upsert analysis
                await prisma.scriptAnalysis.upsert({
                    where: { submissionId },
                    create: {
                        submissionId,
                        originalityScore: analysis.originalityScore || 0,
                        structureScore: analysis.structureScore || 0,
                        dialogueScore: analysis.dialogueScore || 0,
                        visualPotentialScore: analysis.visualPotentialScore || 0,
                        themeAlignmentScore: analysis.themeAlignmentScore || 0,
                        feasibilityScore: analysis.feasibilityScore || 0,
                        overallScore: Math.round(overallScore * 10) / 10,
                        strengths: analysis.strengths || '',
                        concerns: analysis.concerns || '',
                        recommendation: analysis.recommendation || '',
                        rawReport: text,
                    },
                    update: {
                        originalityScore: analysis.originalityScore || 0,
                        structureScore: analysis.structureScore || 0,
                        dialogueScore: analysis.dialogueScore || 0,
                        visualPotentialScore: analysis.visualPotentialScore || 0,
                        themeAlignmentScore: analysis.themeAlignmentScore || 0,
                        feasibilityScore: analysis.feasibilityScore || 0,
                        overallScore: Math.round(overallScore * 10) / 10,
                        strengths: analysis.strengths || '',
                        concerns: analysis.concerns || '',
                        recommendation: analysis.recommendation || '',
                        rawReport: text,
                        analyzedAt: new Date(),
                    },
                })

                // Update submission status
                await prisma.scriptSubmission.update({
                    where: { id: submissionId },
                    data: { status: 'analyzed' },
                })

                return NextResponse.json({ success: true, overallScore: Math.round(overallScore * 10) / 10 })
            } catch (keyErr) {
                lastError = keyErr instanceof Error ? keyErr.message : String(keyErr)
                if (keyInfo.id !== 'settings') {
                    await prisma.apiKey.update({
                        where: { id: keyInfo.id },
                        data: { lastError: lastError.slice(0, 200), lastUsed: new Date() },
                    }).catch(() => {})
                }
                continue
            }
        }

        // All keys exhausted
        throw new Error(lastError || 'All API keys failed')
    } catch (error: unknown) {
        // Revert status on failure
        await prisma.scriptSubmission.update({
            where: { id: submissionId },
            data: { status: 'submitted' },
        })
        const message = process.env.NODE_ENV === 'development'
            ? (error instanceof Error ? error.message : 'Analysis failed')
            : 'Analysis failed'
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

function buildAnalysisPrompt(
    submission: { title: string; logline: string; synopsis: string; scriptText: string | null; genre: string | null; estimatedDuration: string | null },
    call: { title: string; description: string; genre: string | null; toneKeywords: string | null; targetLength: string | null }
) {
    return `You are an expert script analyst for AIM Studio, an AI-powered filmmaking company. Analyze the following screenplay submission for a script call.

SCRIPT CALL BRIEF:
- Call: "${call.title}"
- Brief: ${call.description}
- Desired Genre: ${call.genre || 'Any'}
- Tone: ${call.toneKeywords || 'Not specified'}
- Target Length: ${call.targetLength || 'Not specified'}

SUBMISSION:
- Title: "${submission.title}"
- Logline: ${submission.logline}
- Genre: ${submission.genre || 'Not specified'}
- Estimated Duration: ${submission.estimatedDuration || 'Not specified'}
- Synopsis: ${submission.synopsis}
${submission.scriptText ? `\n- Full Script:\n${submission.scriptText.slice(0, 15000)}` : ''}

Score each category from 0 to 100:

1. originalityScore — How unique/fresh is the premise? Does it avoid clichés?
2. structureScore — Does it follow solid 3-act structure? Good pacing, character arcs?
3. dialogueScore — Natural dialogue? Distinct character voices?
4. visualPotentialScore — Is it visually filmable with AI tools? Strong visual storytelling?
5. themeAlignmentScore — How well does it match the call's genre, tone, and brief?
6. feasibilityScore — Can AIM Studio realistically produce this with AI filmmaking?

Also provide:
- strengths: 2-3 bullet points of what's great about this script (as a single string with newlines)
- concerns: 2-3 bullet points of weaknesses or risks (as a single string with newlines)
- recommendation: A short 2-3 sentence recommendation (SELECT, CONSIDER, or PASS) with reasoning

Respond in this exact JSON format:
{
  "originalityScore": number,
  "structureScore": number,
  "dialogueScore": number,
  "visualPotentialScore": number,
  "themeAlignmentScore": number,
  "feasibilityScore": number,
  "strengths": "string",
  "concerns": "string",
  "recommendation": "string"
}`
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db'

// GET /api/subtitles/[projectId]?lang=es&episodeId=xxx
export async function GET(
    req: NextRequest,
    { params }: { params: Promise<{ projectId: string }> }
) {
    const { projectId } = await params
    const { searchParams } = new URL(req.url)
    const lang = searchParams.get('lang') || 'en'
    const episodeId = searchParams.get('episodeId') || null

    const subtitle = await (prisma as any).filmSubtitle.findFirst({
        where: {
            projectId,
            episodeId: episodeId || null,
        },
    })

    if (!subtitle) {
        return NextResponse.json({ segments: null, available: [] })
    }

    // Parse the stored data
    let segments: { start: number; end: number; text: string }[] = []
    const available: string[] = [subtitle.language] // original language is always available

    // Get original segments
    try {
        segments = JSON.parse(subtitle.segments)
    } catch {
        return NextResponse.json({ segments: null, available })
    }

    // Parse translations to find available languages
    let translations: Record<string, { start: number; end: number; text: string }[]> = {}
    if (subtitle.translations) {
        try {
            translations = JSON.parse(subtitle.translations)
            available.push(...Object.keys(translations))
        } catch { /* ignore */ }
    }

    // If requested language is a translation, return those segments
    if (lang !== subtitle.language && translations[lang]) {
        segments = translations[lang]
    }

    return NextResponse.json({
        segments,
        language: lang,
        originalLanguage: subtitle.language,
        available: [...new Set(available)],
        status: subtitle.status,
    })
}

'use client'

import Link from 'next/link'
import { useState, useMemo } from 'react'

interface Application {
    id: string
    fullName: string
    email: string
    phone: string | null
    age: string | null
    gender: string | null
    status: string
    aiScore: number | null
    aiFitLevel: string | null
    headshotPath: string | null
    selfTapePath: string | null
    createdAt: string
    castingCall: {
        roleName: string
        roleType: string
        project: { title: string }
    }
}

const FILTERS = [
    { key: 'all', label: 'All', icon: '📋' },
    { key: 'pending', label: 'Pending', icon: '📥' },
    { key: 'shortlisted', label: 'Shortlisted', icon: '⭐' },
    { key: 'approved', label: 'Approved', icon: '✅' },
    { key: 'rejected', label: 'Denied', icon: '❌' },
]

const STATUS_STYLES: Record<string, { label: string; bg: string; color: string }> = {
    pending: { label: 'Pending', bg: 'rgba(245,158,11,0.12)', color: '#f59e0b' },
    submitted: { label: 'Pending', bg: 'rgba(245,158,11,0.12)', color: '#f59e0b' },
    shortlisted: { label: 'Shortlisted', bg: 'rgba(59,130,246,0.12)', color: '#60a5fa' },
    approved: { label: 'Approved', bg: 'rgba(34,197,94,0.12)', color: '#22c55e' },
    rejected: { label: 'Denied', bg: 'rgba(107,114,128,0.12)', color: '#9ca3af' },
    reviewed: { label: 'Reviewed', bg: 'rgba(139,92,246,0.12)', color: '#a78bfa' },
    under_review: { label: 'Reviewed', bg: 'rgba(139,92,246,0.12)', color: '#a78bfa' },
}

export default function AdminApplicationsClient({ applications: initialApps }: { applications: Application[] }) {
    const [applications, setApplications] = useState(initialApps)
    const [selected, setSelected] = useState<Set<string>>(new Set())
    const [loading, setLoading] = useState<string | null>(null)
    const [filter, setFilter] = useState('all')
    const [search, setSearch] = useState('')

    const filtered = useMemo(() => {
        let list = applications
        if (filter !== 'all') list = list.filter(a => a.status === filter)
        if (search.trim()) {
            const q = search.toLowerCase()
            list = list.filter(a =>
                a.fullName.toLowerCase().includes(q) ||
                a.email.toLowerCase().includes(q) ||
                a.castingCall.roleName.toLowerCase().includes(q) ||
                a.castingCall.project.title.toLowerCase().includes(q)
            )
        }
        return list
    }, [applications, filter, search])

    const counts = useMemo(() => {
        const c: Record<string, number> = { all: applications.length }
        for (const app of applications) c[app.status] = (c[app.status] || 0) + 1
        return c
    }, [applications])

    const allFilteredSelected = filtered.length > 0 && filtered.every(a => selected.has(a.id))

    const toggleAll = () => {
        if (allFilteredSelected) {
            setSelected(prev => { const n = new Set(prev); filtered.forEach(a => n.delete(a.id)); return n })
        } else {
            setSelected(prev => { const n = new Set(prev); filtered.forEach(a => n.add(a.id)); return n })
        }
    }

    const toggleOne = (id: string) => {
        setSelected(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n })
    }

    const handleDownload = async () => {
        if (selected.size === 0) return
        setLoading('download')
        try {
            const res = await fetch('/api/admin/applications/download', {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ applicationIds: Array.from(selected) }),
            })
            if (!res.ok) throw new Error('Download failed')
            const blob = await res.blob()
            const url = URL.createObjectURL(blob)
            const a = document.createElement('a')
            a.href = url
            a.download = `AIM_Applications_${new Date().toISOString().slice(0, 10)}.zip`
            a.click()
            URL.revokeObjectURL(url)
        } catch { alert('Download failed.') } finally { setLoading(null) }
    }

    const handleBulkStatus = async (status: string) => {
        if (selected.size === 0) return
        const labels: Record<string, string> = { approved: 'approve', rejected: 'deny', shortlisted: 'shortlist', pending: 'reset' }
        if (!confirm(`${labels[status] || status} ${selected.size} application(s)?`)) return
        setLoading(status)
        try {
            const res = await fetch('/api/admin/applications/bulk-status', {
                method: 'PATCH', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ applicationIds: Array.from(selected), status }),
            })
            if (!res.ok) throw new Error('Failed')
            setApplications(prev => prev.map(app => selected.has(app.id) ? { ...app, status } : app))
            setSelected(new Set())
        } catch { alert('Failed to update.') } finally { setLoading(null) }
    }

    const handleBulkDelete = async () => {
        if (selected.size === 0) return
        if (!confirm(`⚠️ PERMANENTLY delete ${selected.size} application(s)?`)) return
        if (!confirm(`Are you absolutely sure?`)) return
        setLoading('delete')
        try {
            const res = await fetch('/api/admin/applications/bulk-delete', {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ applicationIds: Array.from(selected) }),
            })
            if (!res.ok) throw new Error('Failed')
            setApplications(prev => prev.filter(app => !selected.has(app.id)))
            setSelected(new Set())
        } catch { alert('Failed to delete.') } finally { setLoading(null) }
    }

    const handleBulkAI = async () => {
        if (selected.size === 0) return
        if (!confirm(`Run AI analysis on ${selected.size} application(s)?`)) return
        setLoading('ai')
        let success = 0, failed = 0
        for (const appId of Array.from(selected)) {
            try {
                const res = await fetch(`/api/admin/applications/${appId}/audit`, { method: 'POST' })
                if (res.ok) {
                    const data = await res.json()
                    setApplications(prev => prev.map(app => app.id === appId ? {
                        ...app, aiScore: data.report?.overallScore ?? app.aiScore,
                        aiFitLevel: data.report?.recommendation ?? app.aiFitLevel,
                    } : app))
                    success++
                } else { failed++ }
            } catch { failed++ }
        }
        setSelected(new Set()); setLoading(null)
        alert(`AI Analysis: ${success} done, ${failed} failed`)
    }

    const getPhotoCount = (p: string | null) => {
        if (!p) return 0; try { return JSON.parse(p).length } catch { return 1 }
    }

    return (
        <>
            {/* ═══ FILTER TABS + SEARCH ═══ */}
            <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                gap: '12px', marginBottom: '20px', flexWrap: 'wrap',
            }}>
                <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
                    {FILTERS.map(f => (
                        <button key={f.key}
                            onClick={() => { setFilter(f.key); setSelected(new Set()) }}
                            style={{
                                padding: '7px 16px', fontSize: '0.8rem', fontWeight: 600,
                                borderRadius: '8px', border: 'none', cursor: 'pointer',
                                background: filter === f.key ? 'var(--accent-gold)' : 'rgba(255,255,255,0.04)',
                                color: filter === f.key ? '#000' : 'var(--text-secondary)',
                                transition: 'all 0.2s',
                            }}>
                            {f.icon} {f.label}
                            <span style={{ marginLeft: '6px', fontSize: '0.68rem', opacity: 0.6 }}>
                                {counts[f.key] || 0}
                            </span>
                        </button>
                    ))}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    {filtered.length > 0 && (
                        <label style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.78rem', color: 'var(--text-tertiary)', cursor: 'pointer' }}>
                            <input type="checkbox" checked={allFilteredSelected} onChange={toggleAll}
                                style={{ accentColor: 'var(--accent-gold)', width: '14px', height: '14px', cursor: 'pointer' }} />
                            Select all
                        </label>
                    )}
                    <input type="text" placeholder="Search..." value={search}
                        onChange={e => setSearch(e.target.value)}
                        style={{
                            width: '200px', padding: '7px 14px', fontSize: '0.82rem',
                            background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)',
                            borderRadius: '8px', color: 'var(--text-primary)', outline: 'none',
                        }} />
                </div>
            </div>

            {/* ═══ FLOATING ACTION BAR ═══ */}
            {selected.size > 0 && (
                <div className="bulk-action-bar">
                    <span className="bulk-count">{selected.size} selected</span>
                    <div className="bulk-divider" />
                    <button onClick={handleDownload} disabled={loading === 'download'} className="bulk-btn">
                        {loading === 'download' ? '⏳' : '📦'} Download
                    </button>
                    <button onClick={handleBulkAI} disabled={loading === 'ai'} className="bulk-btn">
                        {loading === 'ai' ? '⏳' : '🧠'} AI Analysis
                    </button>
                    <div className="bulk-divider" />
                    <button onClick={() => handleBulkStatus('approved')} disabled={!!loading} className="bulk-btn bulk-approve">✓ Approve</button>
                    <button onClick={() => handleBulkStatus('shortlisted')} disabled={!!loading} className="bulk-btn bulk-shortlist">⭐ Shortlist</button>
                    <button onClick={() => handleBulkStatus('rejected')} disabled={!!loading} className="bulk-btn bulk-deny">✗ Deny</button>
                    <button onClick={() => handleBulkStatus('pending')} disabled={!!loading} className="bulk-btn">🔄 Reset</button>
                    <div className="bulk-divider" />
                    <button onClick={handleBulkDelete} disabled={loading === 'delete'} className="bulk-btn bulk-delete">
                        {loading === 'delete' ? '⏳' : '🗑️'} Delete
                    </button>
                    <button onClick={() => setSelected(new Set())} className="bulk-btn" style={{ opacity: 0.5 }}>Clear</button>
                </div>
            )}

            {/* ═══ APPLICATION CARDS ═══ */}
            {filtered.length === 0 ? (
                <div style={{ padding: '60px 20px', textAlign: 'center', color: 'var(--text-tertiary)', background: 'rgba(255,255,255,0.02)', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.04)' }}>
                    <div style={{ fontSize: '2.5rem', marginBottom: '12px' }}>
                        {filter === 'all' ? '📋' : FILTERS.find(f => f.key === filter)?.icon || '📋'}
                    </div>
                    <h3 style={{ fontSize: '1rem', marginBottom: '6px' }}>{filter === 'all' ? 'No applications yet' : `No ${filter} applications`}</h3>
                    <p style={{ fontSize: '0.85rem' }}>
                        {filter === 'all' ? 'Applications will appear once candidates apply.' : 'Try a different filter.'}
                    </p>
                    {filter !== 'all' && (
                        <button onClick={() => setFilter('all')} className="bulk-btn" style={{ marginTop: '12px' }}>Show all</button>
                    )}
                </div>
            ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    {filtered.map((app) => {
                        const photoCount = getPhotoCount(app.headshotPath)
                        const isSelected = selected.has(app.id)
                        const statusStyle = STATUS_STYLES[app.status] || STATUS_STYLES.pending
                        const scoreColor = (app.aiScore ?? 0) >= 70 ? '#22c55e' : (app.aiScore ?? 0) >= 40 ? '#f59e0b' : '#ef4444'

                        return (
                            <div key={app.id}
                                className={`app-card ${isSelected ? 'app-card-selected' : ''}`}
                                onClick={(e) => {
                                    if ((e.target as HTMLElement).closest('a, button, input')) return
                                    toggleOne(app.id)
                                }}
                            >
                                {/* Checkbox */}
                                <div className="app-checkbox">
                                    <input type="checkbox" checked={isSelected}
                                        onChange={() => toggleOne(app.id)}
                                        style={{ accentColor: 'var(--accent-gold)', width: '16px', height: '16px', cursor: 'pointer' }} />
                                </div>

                                {/* Main Info */}
                                <div className="app-info">
                                    <div className="app-name">{app.fullName}</div>
                                    <div className="app-meta">
                                        <span>{app.email}</span>
                                        {app.phone && <><span className="app-dot">·</span><span>{app.phone}</span></>}
                                    </div>
                                </div>

                                {/* Role & Project */}
                                <div className="app-role">
                                    <div style={{ fontWeight: 600, fontSize: '0.82rem' }}>{app.castingCall.roleName}</div>
                                    <div style={{ fontSize: '0.72rem', color: 'var(--text-tertiary)' }}>{app.castingCall.project.title}</div>
                                </div>

                                {/* Attachments */}
                                <div className="app-attachments">
                                    <span className={`app-tag ${photoCount >= 4 ? 'tag-good' : 'tag-warn'}`}>
                                        📷 {photoCount}
                                    </span>
                                    <span className={`app-tag ${app.selfTapePath ? 'tag-good' : 'tag-bad'}`}>
                                        🎤 {app.selfTapePath ? '✓' : '✗'}
                                    </span>
                                </div>

                                {/* AI Score */}
                                <div className="app-score">
                                    {app.aiScore !== null ? (
                                        <>
                                            <div style={{ fontSize: '1.2rem', fontWeight: 800, color: scoreColor, lineHeight: 1 }}>
                                                {app.aiScore}
                                            </div>
                                            {app.aiFitLevel && (
                                                <div style={{
                                                    fontSize: '0.58rem', fontWeight: 700,
                                                    textTransform: 'uppercase', letterSpacing: '0.03em',
                                                    color: scoreColor, opacity: 0.8,
                                                }}>
                                                    {app.aiFitLevel.replace('_', ' ')}
                                                </div>
                                            )}
                                        </>
                                    ) : (
                                        <div style={{ fontSize: '0.75rem', color: 'var(--text-tertiary)' }}>—</div>
                                    )}
                                </div>

                                {/* Status */}
                                <div className="app-status">
                                    <span style={{
                                        padding: '4px 12px', fontSize: '0.7rem', fontWeight: 700,
                                        borderRadius: '20px', textTransform: 'uppercase', letterSpacing: '0.04em',
                                        background: statusStyle.bg, color: statusStyle.color,
                                        border: `1px solid ${statusStyle.color}20`,
                                    }}>
                                        {statusStyle.label}
                                    </span>
                                </div>

                                {/* Actions */}
                                <Link href={`/admin/applications/${app.id}`} className="app-view-btn">
                                    View
                                </Link>
                            </div>
                        )
                    })}
                </div>
            )}

            <style jsx>{`
                .app-card {
                    display: grid;
                    grid-template-columns: 36px 1fr 140px 80px 60px 100px 50px;
                    align-items: center;
                    gap: 12px;
                    padding: 14px 16px;
                    background: rgba(255,255,255,0.02);
                    border: 1px solid rgba(255,255,255,0.05);
                    border-radius: 10px;
                    cursor: pointer;
                    transition: all 0.15s ease;
                }
                .app-card:hover {
                    background: rgba(255,255,255,0.04);
                    border-color: rgba(255,255,255,0.1);
                }
                .app-card-selected {
                    background: rgba(228,185,90,0.06) !important;
                    border-color: rgba(228,185,90,0.2) !important;
                }
                .app-checkbox { display: flex; align-items: center; justify-content: center; }
                .app-info { min-width: 0; }
                .app-name { font-weight: 700; font-size: 0.9rem; color: var(--text-primary); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
                .app-meta { display: flex; gap: 4px; align-items: center; font-size: 0.75rem; color: var(--text-tertiary); margin-top: 2px; flex-wrap: wrap; }
                .app-dot { opacity: 0.4; }
                .app-role { min-width: 0; }
                .app-attachments { display: flex; gap: 4px; }
                .app-tag { padding: 2px 8px; font-size: 0.7rem; font-weight: 600; border-radius: 6px; }
                .tag-good { background: rgba(34,197,94,0.1); color: #22c55e; }
                .tag-warn { background: rgba(245,158,11,0.1); color: #f59e0b; }
                .tag-bad { background: rgba(239,68,68,0.1); color: #ef4444; }
                .app-score { text-align: center; }
                .app-status { text-align: center; }
                .app-view-btn {
                    font-size: 0.78rem; color: var(--text-secondary); text-decoration: none;
                    padding: 4px 10px; border-radius: 6px; font-weight: 600;
                    transition: all 0.15s;
                }
                .app-view-btn:hover { color: var(--accent-gold); background: rgba(228,185,90,0.08); }

                /* Bulk Action Bar */
                .bulk-action-bar {
                    position: fixed; bottom: 20px; left: 50%; transform: translateX(-50%);
                    background: rgba(10,12,16,0.96); backdrop-filter: blur(24px);
                    border: 1px solid rgba(228,185,90,0.3); border-radius: 14px;
                    padding: 8px 16px; display: flex; align-items: center; gap: 6px;
                    z-index: 1000; box-shadow: 0 16px 48px rgba(0,0,0,0.6);
                    animation: barSlideUp 0.25s ease;
                }
                .bulk-count { font-size: 0.78rem; font-weight: 700; color: var(--accent-gold); white-space: nowrap; padding: 0 4px; }
                .bulk-divider { width: 1px; height: 20px; background: rgba(255,255,255,0.08); }
                .bulk-btn {
                    font-size: 0.75rem; font-weight: 600; padding: 5px 12px;
                    border-radius: 7px; border: none; cursor: pointer;
                    background: rgba(255,255,255,0.05); color: var(--text-secondary);
                    white-space: nowrap; transition: all 0.15s;
                }
                .bulk-btn:hover { background: rgba(255,255,255,0.1); color: var(--text-primary); }
                .bulk-btn:disabled { opacity: 0.4; cursor: not-allowed; }
                .bulk-approve { background: rgba(34,197,94,0.15); color: #22c55e; }
                .bulk-approve:hover { background: rgba(34,197,94,0.25); }
                .bulk-shortlist { background: rgba(59,130,246,0.15); color: #60a5fa; }
                .bulk-shortlist:hover { background: rgba(59,130,246,0.25); }
                .bulk-deny { background: rgba(239,68,68,0.15); color: #ef4444; }
                .bulk-deny:hover { background: rgba(239,68,68,0.25); }
                .bulk-delete { color: #ef4444; }

                @keyframes barSlideUp {
                    from { transform: translateX(-50%) translateY(16px); opacity: 0; }
                    to { transform: translateX(-50%) translateY(0); opacity: 1; }
                }

                @media (max-width: 900px) {
                    .app-card {
                        grid-template-columns: 32px 1fr auto;
                        gap: 8px;
                    }
                    .app-role, .app-attachments, .app-score { display: none; }
                    .app-status { grid-column: 2; }
                    .app-view-btn { grid-column: 3; }
                }
            `}</style>
        </>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import AICastingReport from '@/components/application/AICastingReport'

interface Props {
    application: {
        id: string
        fullName: string
        email: string
        phone: string | null
        age: number | null
        gender: string | null
        location: string | null
        status: string
        aiScore: number | null
        aiFitLevel: string | null
        adminNotes: string | null
        createdAt: string
        resultVisibleAt: string | null
        statusNote: string | null
    }
    castingCall: {
        roleName: string
        roleType: string
        roleDescription: string
        requirements: string
        projectTitle: string
    }
    photos: string[]
    voicePath: string | null
    experienceData: {
        text: string
        specialSkills: string
        personality: {
            describe_yourself: string
            why_acting: string
            dream_role: string
            unique_quality: string
        }
    }
    socialData: {
        primary: { platform: string; username: string }
        secondary: { platform: string; username: string } | null
    }
    aiReport: {
        overallScore: number
        roleFitScore: number
        strengths: string[]
        concerns: string[]
        recommendation: string
        notes: string
        screeningSkipped?: boolean
    } | null
}

const PIPELINE = [
    { key: 'submitted', label: 'Received', icon: '📥' },
    { key: 'under_review', label: 'Reviewing', icon: '🔍' },
    { key: 'shortlisted', label: 'Shortlisted', icon: '⭐' },
    { key: 'callback', label: 'Callback', icon: '✉️' },
    { key: 'final_review', label: 'Final Review', icon: '🎭' },
    { key: 'selected', label: 'Cast', icon: '🏆' },
]

export default function ApplicationDetailClient({ application, castingCall, photos, voicePath, experienceData, socialData, aiReport }: Props) {
    const router = useRouter()
    const [runningAI, setRunningAI] = useState(false)
    const [updatingStatus, setUpdatingStatus] = useState(false)
    const [currentReport, setCurrentReport] = useState(aiReport)
    const [aiError, setAiError] = useState('')
    const [lightboxIdx, setLightboxIdx] = useState<number | null>(null)
    const [editingFeedback, setEditingFeedback] = useState(application.statusNote || '')
    const [savingFeedback, setSavingFeedback] = useState(false)
    const [feedbackSaved, setFeedbackSaved] = useState(false)

    // Notification log
    const [notifOpen, setNotifOpen] = useState(false)
    const [notifLoading, setNotifLoading] = useState(false)
    const [notifications, setNotifications] = useState<Array<{
        id: string; createdAt: string; type: string; subject: string;
        recipientEmail: string; status: string;
    }>>([])
    const [notifPage, setNotifPage] = useState(1)
    const [notifTotal, setNotifTotal] = useState(0)
    const NOTIF_SIZE = 10

    const loadNotifications = async (page = 1) => {
        setNotifLoading(true)
        try {
            const res = await fetch(`/api/admin/applications/${application.id}/notifications?page=${page}&size=${NOTIF_SIZE}`)
            if (res.ok) {
                const data = await res.json()
                setNotifications(data.notifications)
                setNotifTotal(data.pagination.total)
                setNotifPage(page)
            }
        } catch { /* */ }
        finally { setNotifLoading(false) }
    }

    useEffect(() => {
        if (notifOpen && notifications.length === 0) {
            loadNotifications(1)
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [notifOpen])

    // Compute delivery status
    const resultVisibleAt = application.resultVisibleAt ? new Date(application.resultVisibleAt) : null
    const now = new Date()
    const isDelivered = resultVisibleAt ? now >= resultVisibleAt : false
    const hoursLeft = resultVisibleAt && !isDelivered ? Math.max(0, Math.ceil((resultVisibleAt.getTime() - now.getTime()) / (1000 * 60 * 60))) : 0
    const minutesLeft = resultVisibleAt && !isDelivered ? Math.max(0, Math.ceil((resultVisibleAt.getTime() - now.getTime()) / (1000 * 60))) : 0

    const saveFeedback = async () => {
        setSavingFeedback(true)
        try {
            await fetch(`/api/admin/applications/${application.id}/status`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ statusNote: editingFeedback }),
            })
            setFeedbackSaved(true)
            setTimeout(() => setFeedbackSaved(false), 2000)
        } catch { /* */ }
        finally { setSavingFeedback(false) }
    }

    const runAIAudit = async () => {
        setRunningAI(true); setAiError('')
        try {
            const res = await fetch(`/api/admin/applications/${application.id}/audit`, { method: 'POST' })
            const data = await res.json()
            if (res.ok) {
                setCurrentReport(data.report)
                // Update the editable feedback with the new AI-generated message
                if (data.report?.applicantFeedback) {
                    setEditingFeedback(data.report.applicantFeedback)
                }
                router.refresh()
            }
            else setAiError(data.error || 'AI analysis failed.')
        } catch { setAiError('Network error.') }
        finally { setRunningAI(false) }
    }

    const updateStatus = async (newStatus: string) => {
        setUpdatingStatus(true)
        try {
            await fetch(`/api/admin/applications/${application.id}/status`, {
                method: 'PATCH', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus }),
            })
            router.refresh()
        } catch { /* */ }
        finally { setUpdatingStatus(false) }
    }

    const stageOrder = PIPELINE.map(s => s.key)
    const currentIdx = stageOrder.indexOf(application.status)
    const isRejected = application.status === 'rejected' || application.status === 'not_selected'

    return (
        <div>
            {/* ─── HEADER BAR ─── */}
            <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                marginBottom: '20px', flexWrap: 'wrap', gap: '12px',
            }}>
                <div>
                    <h1 style={{ fontSize: '1.3rem', fontWeight: 800, margin: 0 }}>{application.fullName}</h1>
                    <div style={{ fontSize: '0.78rem', color: 'var(--text-tertiary)', marginTop: '3px' }}>
                        <span style={{ color: 'var(--accent-gold)' }}>{castingCall.roleName}</span> · {castingCall.projectTitle}
                        · Applied {new Date(application.createdAt).toLocaleDateString()}
                    </div>
                </div>
                <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                    {isRejected && (
                        <span style={{ padding: '4px 14px', fontSize: '0.72rem', fontWeight: 700, borderRadius: '20px', background: 'rgba(239,68,68,0.12)', color: 'var(--color-error)', border: '1px solid rgba(239,68,68,0.2)' }}>
                            NOT SELECTED
                        </span>
                    )}
                    <button onClick={runAIAudit} disabled={runningAI}
                        style={{
                            padding: '6px 16px', fontSize: '0.78rem', fontWeight: 700, borderRadius: '8px',
                            border: '1px solid rgba(212,168,83,0.3)', cursor: 'pointer',
                            background: 'linear-gradient(135deg, rgba(212,168,83,0.15), rgba(212,168,83,0.05))',
                            color: 'var(--accent-gold)', transition: 'all 0.2s',
                        }}>
                        {runningAI ? '⏳ Analyzing...' : '🤖 AI Audit'}
                    </button>
                    {!isRejected && (
                        <button onClick={() => updateStatus('not_selected')} disabled={updatingStatus}
                            style={{
                                padding: '6px 14px', fontSize: '0.75rem', fontWeight: 600, borderRadius: '8px',
                                border: '1px solid rgba(239,68,68,0.2)', background: 'rgba(239,68,68,0.06)',
                                color: 'var(--color-error)', cursor: 'pointer',
                            }}>
                            ✗ Deny
                        </button>
                    )}
                </div>
            </div>

            {/* ─── PIPELINE BAR ─── */}
            <div style={{
                display: 'flex', gap: '2px', marginBottom: '20px',
                padding: '4px', background: 'rgba(255,255,255,0.02)', borderRadius: '10px',
                border: '1px solid rgba(255,255,255,0.05)',
            }}>
                {PIPELINE.map((stage, i) => {
                    const stageIdx = stageOrder.indexOf(stage.key)
                    const isActive = application.status === stage.key
                    const isPast = !isRejected && currentIdx >= 0 && stageIdx < currentIdx
                    const isFuture = !isRejected && currentIdx >= 0 && stageIdx > currentIdx

                    return (
                        <button key={stage.key}
                            onClick={() => updateStatus(stage.key)}
                            disabled={updatingStatus || isActive}
                            style={{
                                flex: 1, padding: '8px 4px', borderRadius: '8px', border: 'none',
                                cursor: isActive ? 'default' : 'pointer',
                                background: isActive ? 'var(--accent-gold-glow)' : isPast ? 'rgba(16,185,129,0.06)' : 'transparent',
                                borderBottom: isActive ? '2px solid var(--accent-gold)' : isPast ? '2px solid rgba(16,185,129,0.4)' : '2px solid transparent',
                                transition: 'all 0.2s', textAlign: 'center',
                                opacity: isFuture && isRejected ? 0.3 : 1,
                            }}
                        >
                            <div style={{ fontSize: '0.85rem', marginBottom: '2px' }}>{isPast ? '✓' : stage.icon}</div>
                            <div style={{
                                fontSize: '0.62rem', fontWeight: isActive ? 700 : 500, letterSpacing: '0.02em',
                                color: isActive ? 'var(--accent-gold)' : isPast ? 'var(--color-success)' : 'var(--text-tertiary)',
                            }}>{stage.label}</div>
                            {isActive && <div style={{
                                width: '4px', height: '4px', borderRadius: '50%',
                                background: 'var(--accent-gold)', margin: '3px auto 0',
                            }} />}
                        </button>
                    )
                })}
            </div>

            {/* ─── VISION SCREENING SKIPPED WARNING ─── */}
            {currentReport?.screeningSkipped && (
                <div style={{
                    display: 'flex', alignItems: 'center', gap: '8px',
                    padding: '8px 14px', marginBottom: '16px', borderRadius: '8px',
                    background: 'rgba(245,158,11,0.08)',
                    border: '1px solid rgba(245,158,11,0.25)',
                    fontSize: '0.75rem', fontWeight: 600,
                    color: 'hsl(38, 92%, 50%)',
                }}>
                    <span style={{ fontSize: '1rem' }}>⚠️</span>
                    <span>Vision screening was skipped — photos were not validated by AI. A <strong>−5 point</strong> penalty has been applied.</span>
                </div>
            )}

            {/* ─── MAIN GRID ─── */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: '16px', alignItems: 'start' }}>
                {/* LEFT COLUMN */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    {/* Photo Gallery — Compact Filmstrip */}
                    <div style={{
                        padding: '14px', background: 'rgba(255,255,255,0.02)', borderRadius: '10px',
                        border: '1px solid rgba(255,255,255,0.05)',
                    }}>
                        <div style={{ fontSize: '0.68rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--accent-gold)', marginBottom: '10px' }}>
                            📸 Photos ({photos.length})
                        </div>
                        {photos.length > 0 ? (
                            <div style={{ display: 'flex', gap: '6px', overflowX: 'auto', paddingBottom: '4px' }}>
                                {photos.map((photo, i) => (
                                    <div key={i}
                                        onClick={() => setLightboxIdx(i)}
                                        style={{
                                            width: '80px', height: '106px', flexShrink: 0,
                                            borderRadius: '6px', overflow: 'hidden', cursor: 'pointer',
                                            border: '2px solid transparent', transition: 'border 0.2s',
                                        }}
                                        onMouseEnter={e => (e.currentTarget.style.borderColor = 'var(--accent-gold)')}
                                        onMouseLeave={e => (e.currentTarget.style.borderColor = 'transparent')}
                                    >
                                        {/* eslint-disable-next-line @next/next/no-img-element */}
                                        <img src={photo} alt={`Photo ${i + 1}`} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div style={{ padding: '16px', textAlign: 'center', color: 'var(--text-tertiary)', fontSize: '0.8rem' }}>No photos</div>
                        )}
                    </div>

                    {/* Voice + Experience — Side by Side */}
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                        {/* Voice */}
                        <div style={{
                            padding: '14px', background: 'rgba(255,255,255,0.02)', borderRadius: '10px',
                            border: '1px solid rgba(255,255,255,0.05)',
                        }}>
                            <div style={{ fontSize: '0.68rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--accent-gold)', marginBottom: '10px' }}>
                                🎙️ Voice Tape
                            </div>
                            {voicePath ? (
                                <audio controls style={{ width: '100%', height: '32px' }}>
                                    <source src={voicePath} />
                                </audio>
                            ) : (
                                <div style={{ padding: '10px', textAlign: 'center', color: 'var(--text-tertiary)', fontSize: '0.78rem', background: 'rgba(255,255,255,0.02)', borderRadius: '6px' }}>No recording</div>
                            )}
                        </div>

                        {/* Skills */}
                        <div style={{
                            padding: '14px', background: 'rgba(255,255,255,0.02)', borderRadius: '10px',
