type TabItem = { href: string; label: string; icon: React.ReactNode }
type SearchMode = 'idle' | 'search-bar' | 'search-focused'
type SearchResult = {
    category: string
    icon: string
    title: string
    subtitle: string
    href: string
}

/* ── Custom debounce hook ── */
function useDebounce<T>(value: T, delay: number): T {
    const [debounced, setDebounced] = useState(value)
    useEffect(() => {
        const timer = setTimeout(() => setDebounced(value), delay)
        return () => clearTimeout(timer)
    }, [value, delay])
    return debounced
}

export default function MobileTabBar() {
    const pathname = usePathname()
    const router = useRouter()
    const settings = useSiteSettings()
    const t = useTranslations('nav')
    const tSearch = useTranslations('search')
    const locale = useLocale()

    const [collapsed, setCollapsed] = useState(false)
    const [searchMode, setSearchMode] = useState<SearchMode>('idle')
    const [searchQuery, setSearchQuery] = useState('')
    const [results, setResults] = useState<SearchResult[]>([])
    const [loading, setLoading] = useState(false)
    const [focusedIndex, setFocusedIndex] = useState(-1)

    const lastScrollY = useRef(0)
    const scrollThreshold = 60
    const searchInputRef = useRef<HTMLInputElement>(null)
    const barRef = useRef<HTMLDivElement>(null)
    const suggestionsRef = useRef<HTMLDivElement>(null)

    const debouncedQuery = useDebounce(searchQuery, 300)

    const isActive = (href: string) => {
        if (href === '/') return pathname === '/'
        return pathname.startsWith(href)
    }

    const castingEnabled = settings?.castingCallsEnabled ?? true
    const trainingEnabled = settings?.trainingEnabled ?? false

    /* ── Build the 4 main tabs ── */
    const tabs: TabItem[] = [
        { href: '/', label: t('home'), icon: icons.home },
        { href: '/works', label: t('works'), icon: icons.works },
        { href: '/upcoming', label: t('upcoming'), icon: icons.upcoming },
    ]

    if (castingEnabled) {
        tabs.push({ href: '/casting', label: t('casting'), icon: icons.casting })
    } else if (trainingEnabled) {
        tabs.push({ href: '/training', label: t('training'), icon: icons.training })
    }

    /* ── Scroll collapse/expand logic (only in idle mode) ── */
    const handleScroll = useCallback(() => {
        if (searchMode !== 'idle') return // Don't collapse during search
        const currentY = window.scrollY

        if (currentY <= scrollThreshold) {
            setCollapsed(false)
        } else if (currentY > lastScrollY.current + 8) {
            setCollapsed(true)
        } else if (currentY < lastScrollY.current - 8) {
            setCollapsed(false)
        }

        lastScrollY.current = currentY
    }, [searchMode])

    useEffect(() => {
        window.addEventListener('scroll', handleScroll, { passive: true })
        return () => window.removeEventListener('scroll', handleScroll)
    }, [handleScroll])

    /* ── Home icon tap toggles collapsed state ── */
    const handleHomeTap = (e: React.MouseEvent) => {
        if (collapsed) {
            e.preventDefault()
            setCollapsed(false)
        }
    }

    /* ═══ SEARCH STATE MACHINE ═══ */

    // Phase 1: Tap search pill → morph to search bar
    const openSearchBar = () => {
        setCollapsed(true) // collapse tabs behind Home
        setSearchMode('search-bar')
        // Focus input after animation
        setTimeout(() => {
            searchInputRef.current?.focus()
        }, 100)
    }

    // Phase 2: Tap input → full-width focused mode
    const focusSearch = () => {
        setSearchMode('search-focused')
    }

    // Cancel: reverse everything
    const cancelSearch = () => {
        setSearchMode('idle')
        setSearchQuery('')
        setResults([])
        setFocusedIndex(-1)
        setLoading(false)
        // Let scroll position dictate collapse state
        if (window.scrollY <= scrollThreshold) {
            setCollapsed(false)
        }
    }

    // Navigate to result
    const selectResult = (href: string) => {
        cancelSearch()
        router.push(href)
    }

    /* ── Fetch suggestions ── */
    useEffect(() => {
        if (debouncedQuery.length < 2) {
            setResults([])
            setLoading(false)
            return
        }

        setLoading(true)
        const controller = new AbortController()

        fetch(`/api/search?q=${encodeURIComponent(debouncedQuery)}&locale=${locale}`, {
            signal: controller.signal,
        })
            .then(r => r.json())
            .then(data => {
                setResults(data.results || [])
                setLoading(false)
                setFocusedIndex(-1)
            })
            .catch(err => {
                if (err.name !== 'AbortError') {
                    setLoading(false)
                }
            })

        return () => controller.abort()
    }, [debouncedQuery, locale])

    /* ── Keyboard navigation ── */
    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Escape') {
            cancelSearch()
            return
        }
        if (e.key === 'ArrowDown') {
            e.preventDefault()
            setFocusedIndex(prev => Math.min(prev + 1, results.length - 1))
        }
        if (e.key === 'ArrowUp') {
            e.preventDefault()
            setFocusedIndex(prev => Math.max(prev - 1, -1))
        }
        if (e.key === 'Enter' && focusedIndex >= 0 && results[focusedIndex]) {
            e.preventDefault()
            selectResult(results[focusedIndex].href)
        }
    }

    /* ── Keyboard-aware positioning ── */
    useEffect(() => {
        if (searchMode !== 'search-focused') return
        const vv = window.visualViewport
        if (!vv) return

        const onResize = () => {
            const keyboardHeight = window.innerHeight - vv.height - vv.offsetTop
            if (barRef.current && keyboardHeight > 50) {
                barRef.current.style.bottom = `${keyboardHeight + 8}px`
            } else if (barRef.current) {
                barRef.current.style.bottom = '12px'
            }
        }

        vv.addEventListener('resize', onResize)
        vv.addEventListener('scroll', onResize)
        onResize() // initial position
        return () => {
            vv.removeEventListener('resize', onResize)
            vv.removeEventListener('scroll', onResize)
        }
    }, [searchMode])

    /* ── Close search on Escape (global) ── */
    useEffect(() => {
        const handleKey = (e: KeyboardEvent) => {
            if (e.key === 'Escape' && searchMode !== 'idle') cancelSearch()
        }
        window.addEventListener('keydown', handleKey)
        return () => window.removeEventListener('keydown', handleKey)
    }, [searchMode])

    /* ── Scroll focused suggestion into view ── */
    useEffect(() => {
        if (focusedIndex >= 0 && suggestionsRef.current) {
            const items = suggestionsRef.current.querySelectorAll('.search-suggestion-item')
            items[focusedIndex]?.scrollIntoView({ block: 'nearest', behavior: 'smooth' })
        }
    }, [focusedIndex])

    /* ── Group results by category ── */
    const groupedResults = results.reduce<Record<string, SearchResult[]>>((acc, r) => {
        if (!acc[r.category]) acc[r.category] = []
        acc[r.category].push(r)
        return acc
    }, {})

    /* ═══ RENDER ═══ */
    const isSearchActive = searchMode !== 'idle'

    // Build CSS class for the bar
    const barClasses = [
        'mobile-tab-bar',
        collapsed ? 'collapsed' : '',
        searchMode === 'search-bar' ? 'search-mode' : '',
        searchMode === 'search-focused' ? 'search-mode search-focused-mode' : '',
    ].filter(Boolean).join(' ')

    return (
        <>
            {/* ── Suggestion panel (above the bar) ── */}
            {isSearchActive && searchMode === 'search-focused' && (
                <div className="search-suggestions-backdrop" onClick={cancelSearch}>
                    <div
                        ref={suggestionsRef}
                        className="search-suggestions-panel"
                        onClick={(e) => e.stopPropagation()}
                        role="listbox"
                        aria-label={tSearch('suggestions')}
                    >
                        {/* Loading skeletons */}
                        {loading && (
                            <div className="search-suggestions-loading">
                                {[0, 1, 2].map(i => (
                                    <div key={i} className="search-suggestion-skeleton" style={{ animationDelay: `${i * 0.1}s` }}>
                                        <div className="skeleton-icon" />
                                        <div className="skeleton-text">
                                            <div className="skeleton-title" />
                                            <div className="skeleton-subtitle" />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* Results */}
                        {!loading && results.length > 0 && (
                            <div className="search-suggestions-results">
                                {Object.entries(groupedResults).map(([category, items]) => (
                                    <div key={category} className="search-suggestion-group">
                                        <div className="search-suggestion-group-header">
                                            <span>{items[0].icon}</span>
                                            <span>{category}</span>
                                        </div>
                                        {items.map((item, idx) => {
                                            const globalIdx = results.indexOf(item)
                                            return (
                                                <button
                                                    key={`${item.href}-${idx}`}
                                                    className={`search-suggestion-item ${globalIdx === focusedIndex ? 'focused' : ''}`}
                                                    onClick={() => selectResult(item.href)}
                                                    role="option"
                                                    aria-selected={globalIdx === focusedIndex}
                                                >
                                                    <span className="suggestion-icon">{item.icon}</span>
                                                    <div className="suggestion-content">
                                                        <span className="suggestion-title">{item.title}</span>
                                                        <span className="suggestion-subtitle">{item.subtitle}</span>
                                                    </div>
                                                    <svg className="suggestion-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                        <polyline points="9 18 15 12 9 6" />
                                                    </svg>
                                                </button>
                                            )
                                        })}
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* Empty state */}
                        {!loading && results.length === 0 && debouncedQuery.length >= 2 && (
                            <div className="search-empty-state">
                                <div className="search-empty-icon">
                                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                        <circle cx="11" cy="11" r="8" />
                                        <line x1="21" y1="21" x2="16.65" y2="16.65" />
                                        <line x1="8" y1="11" x2="14" y2="11" />
                                    </svg>
                                </div>
                                <p className="search-empty-title">{tSearch('noResults', { query: debouncedQuery })}</p>
                                <p className="search-empty-subtitle">{tSearch('tryDifferent')}</p>
                                <div className="search-empty-links">
                                    <button onClick={() => selectResult('/works')} className="search-empty-link">🎬 {t('works')}</button>
                                    {castingEnabled && <button onClick={() => selectResult('/casting')} className="search-empty-link">🎭 {t('casting')}</button>}
                                    <button onClick={() => selectResult('/about')} className="search-empty-link">📄 {tSearch('about')}</button>
                                </div>
                            </div>
                        )}

                        {/* Quick access (when input empty) */}
                        {!loading && debouncedQuery.length < 2 && (
                            <div className="search-quick-access">
                                <div className="search-suggestion-group-header">
                                    <span>⚡</span>
                                    <span>{tSearch('quickAccess')}</span>
                                </div>
                                <button className="search-suggestion-item" onClick={() => selectResult('/works')}>
                                    <span className="suggestion-icon">🎬</span>
                                    <div className="suggestion-content">
                                        <span className="suggestion-title">{t('works')}</span>
                                        <span className="suggestion-subtitle">{tSearch('browseAll')}</span>
                                    </div>
                                    <svg className="suggestion-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 18 15 12 9 6" /></svg>
                                </button>
                                <button className="search-suggestion-item" onClick={() => selectResult('/upcoming')}>
                                    <span className="suggestion-icon">⏳</span>
                                    <div className="suggestion-content">
                                        <span className="suggestion-title">{t('upcoming')}</span>
                                        <span className="suggestion-subtitle">{tSearch('comingSoon')}</span>
                                    </div>
                                    <svg className="suggestion-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 18 15 12 9 6" /></svg>
                                </button>
                                {castingEnabled && (
                                    <button className="search-suggestion-item" onClick={() => selectResult('/casting')}>
                                        <span className="suggestion-icon">🎭</span>
                                        <div className="suggestion-content">
                                            <span className="suggestion-title">{t('casting')}</span>
                                            <span className="suggestion-subtitle">{tSearch('openRoles')}</span>
                                        </div>
                                        <svg className="suggestion-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 18 15 12 9 6" /></svg>
                                    </button>
                                )}
                                {trainingEnabled && (
                                    <button className="search-suggestion-item" onClick={() => selectResult('/training')}>
                                        <span className="suggestion-icon">📚</span>
                                        <div className="suggestion-content">
                                            <span className="suggestion-title">{t('training')}</span>
                                            <span className="suggestion-subtitle">{tSearch('learnSkills')}</span>
                                        </div>
                                        <svg className="suggestion-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 18 15 12 9 6" /></svg>
                                    </button>
                                )}
                                <button className="search-suggestion-item" onClick={() => selectResult('/donate')}>
                                    <span className="suggestion-icon">❤️</span>
                                    <div className="suggestion-content">
                                        <span className="suggestion-title">{t('donate')}</span>
                                        <span className="suggestion-subtitle">{tSearch('supportUs')}</span>
                                    </div>
                                    <svg className="suggestion-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 18 15 12 9 6" /></svg>
                                </button>
                                <button className="search-suggestion-item" onClick={() => selectResult('/about')}>
                                    <span className="suggestion-icon">ℹ️</span>
                                    <div className="suggestion-content">
                                        <span className="suggestion-title">{tSearch('about')}</span>
                                        <span className="suggestion-subtitle">{tSearch('ourStory')}</span>
                                    </div>
                                    <svg className="suggestion-arrow" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 18 15 12 9 6" /></svg>
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* ── Tab Bar ── */}
            <nav ref={barRef} className={barClasses} aria-label="Mobile navigation" role="search">
                {/* Main nav pill */}
                <div className={`tab-pill tab-pill-nav ${isSearchActive ? 'search-active' : ''}`}>
                    {tabs.map((tab, index) => (
                        <Link
                            key={tab.href}
                            href={tab.href}
                            className={`tab-item ${isActive(tab.href) ? 'tab-active' : ''} ${index === 0 ? 'tab-home' : 'tab-collapsible'}`}
                            onClick={index === 0 ? handleHomeTap : undefined}
                        >
                            <span className="tab-icon-wrap">{tab.icon}</span>
                            <span className="tab-label">{tab.label}</span>
                        </Link>
                    ))}
                </div>

                {/* Search pill / Search bar */}
                {searchMode === 'idle' ? (
                    <button
                        className="tab-pill tab-pill-search"
                        onClick={openSearchBar}
                        aria-label={tSearch('searchButton')}
                    >
                        <span className="tab-icon-wrap">{icons.search}</span>
                    </button>
                ) : (
                    <div className={`tab-pill tab-search-bar ${searchMode === 'search-focused' ? 'full-width' : ''}`}>
                        <div className="search-bar-inner">
                            <span className="search-bar-icon">{icons.search}</span>
                            <input
                                ref={searchInputRef}
                                type="text"
                                className="search-bar-input"
                                placeholder={tSearch('placeholder')}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                onFocus={focusSearch}
                                onKeyDown={handleKeyDown}
                                autoComplete="off"
                                autoCorrect="off"
                                spellCheck={false}
                                aria-label={tSearch('placeholder')}
                                aria-controls="search-suggestions"
                                aria-activedescendant={focusedIndex >= 0 ? `suggestion-${focusedIndex}` : undefined}
                            />
                            {loading && (
                                <span className="search-bar-spinner" />
                            )}
                            <button
                                className="search-bar-cancel"
                                onClick={cancelSearch}
                                aria-label={tSearch('cancel')}
                            >
                                {icons.close}
                            </button>
                        </div>
                    </div>
                )}
            </nav>
        </>
    )
}

'use client'

import { useState, useEffect } from 'react'
import Link from 'next/link'
import { usePathname, useRouter } from '@/i18n/navigation'
import { useAuth } from '@/components/AuthProvider'
import { useSiteSettings } from '@/context/SiteSettingsContext';
import { SearchBar } from '@/components/search/SearchBar';
import { SearchOverlay } from '@/components/search/SearchOverlay';
import { useTranslations, useLocale } from 'next-intl';
import { locales, localeNames, type Locale } from '@/i18n/routing'

export default function Navbar() {
    const [scrolled, setScrolled] = useState(false)
    const [searchOpen, setSearchOpen] = useState(false)
    const [mobileOpen, setMobileOpen] = useState(false)
    const [userMenuOpen, setUserMenuOpen] = useState(false)
    const [langMenuOpen, setLangMenuOpen] = useState(false)
    const settings = useSiteSettings();
    const brandName = settings?.siteName ? (() => {
        const parts = settings.siteName.split(' ');
        return { accent: parts[0] || 'AIM', rest: parts.slice(1).join(' ') || 'Studio' };
    })() : { accent: 'AIM', rest: 'Studio' };
    const logoUrl = settings?.logoUrl ?? '';
    const sections = {
        casting: settings?.castingCallsEnabled ?? true,
        scripts: settings?.scriptCallsEnabled ?? false,
        training: settings?.trainingEnabled ?? false,
        donations: settings?.donationsEnabled ?? true,
    };
    const pathname = usePathname()
    const router = useRouter()
    const { user, loading, logout } = useAuth()
    const t = useTranslations('nav')



    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 50)
        window.addEventListener('scroll', handleScroll)
        return () => window.removeEventListener('scroll', handleScroll)
    }, [])

    // Close user menu when clicking outside
    useEffect(() => {
        const handleClick = () => setUserMenuOpen(false)
        if (userMenuOpen) {
            document.addEventListener('click', handleClick)
            return () => document.removeEventListener('click', handleClick)
        }
    }, [userMenuOpen])

    const links = [
        { href: '/', label: t('home') },
        { href: '/works', label: t('works') },
        { href: '/upcoming', label: t('upcoming') },
        ...(sections.casting ? [{ href: '/casting', label: t('casting') }] : []),
        ...(sections.scripts ? [{ href: '/scripts', label: t('scripts') }] : []),
        ...(sections.training ? [{ href: '/training', label: t('training') }] : []),
        ...(sections.donations ? [{ href: '/donate', label: t('donate') }] : []),
    ]

    // Get current locale from next-intl
    const currentLocale = useLocale()

    const switchLocale = (newLocale: Locale) => {
        router.replace(pathname, { locale: newLocale })
        setLangMenuOpen(false)
    }

    return (
        <>
            <nav className={`navbar ${scrolled ? 'scrolled' : ''}`} aria-label="Main navigation">
                <div className="navbar-inner">
                    <Link href="/" className="navbar-logo">
                        {logoUrl && (
                            <img
                                src={logoUrl}
                                alt="logo"
                                style={{ height: '28px', width: 'auto', objectFit: 'contain', display: 'block' }}
                                onError={() => {}}
                            />
                        )}
                        <span className="logo-accent">{brandName.accent}</span>
                        <span>{brandName.rest}</span>
                        <span className="logo-dot"></span>
                    </Link>

                    <ul className="navbar-links">
                        {links.map((link) => (
                            <li key={link.href}>
                                <Link
                                    href={link.href}
                                    className={pathname === link.href ? 'active' : ''}
                                >
                                    {link.label}
                                </Link>
                            </li>
                        ))}
                    </ul>

                    {/* Desktop Search Bar */}
                    {settings?.searchBetaEnabled && (
                      <div className="navbar-desktop-only mr-4">
                        <SearchBar />
                      </div>
                    )}

                    {/* Right actions — Bell + Language hidden on mobile via CSS */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                        {/* Bell — desktop only */}
                        <Link href="/subscribe" title={t('notifications')} className="navbar-desktop-only" style={{
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            color: 'var(--text-secondary)', transition: 'color 0.2s',
                            textDecoration: 'none',
                        }}>
                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9" />
                                <path d="M13.73 21a2 2 0 0 1-3.46 0" />
                            </svg>
                        </Link>
                        {/* Mobile Search Button */}
                        {settings?.searchBetaEnabled && (
                          <button
                            onClick={() => setSearchOpen(true)}
                            className="navbar-mobile-only"
                            style={{
                              background: 'transparent',
                              border: 'none',
                              color: 'var(--text-primary)',
                              fontSize: '1.2rem',
                              cursor: 'pointer',
                            }}
                            aria-label="Search"
                          >
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                              <circle cx="11" cy="11" r="8" />
                              <line x1="21" y1="21" x2="16.65" y2="16.65" />
                            </svg>
                          </button>
                        )}
                        {/* Auth — always visible (avatar on mobile, full pill on desktop) */}
                        {loading ? null : user ? (
                            <div style={{ position: 'relative' }}>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation()
                                        setUserMenuOpen(!userMenuOpen)
                                    }}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '8px',
                                        background: 'rgba(212,168,83,0.1)',
                                        border: '1px solid rgba(212,168,83,0.2)',
                                        borderRadius: 'var(--radius-full)',
                                        padding: '0.35rem 0.9rem 0.35rem 0.5rem',
                                        cursor: 'pointer',
                                        transition: 'all 0.2s ease',
                                        color: 'var(--text-primary)',
                                    }}
                                >
                                    <div style={{
                                        width: '28px',
                                        height: '28px',
                                        borderRadius: '50%',
                                        background: 'linear-gradient(135deg, var(--accent-gold), var(--accent-gold-dark))',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        fontSize: '0.75rem',
                                        fontWeight: 700,
                                        color: 'var(--bg-primary)',
                                    }}>
                                        {user.name.charAt(0).toUpperCase()}
                                    </div>
                                    <span className="navbar-desktop-only" style={{ fontSize: '0.8rem', fontWeight: 600 }}>{user.name.split(' ')[0]}</span>
                                </button>

                                {userMenuOpen && (
                                    <div style={{
                                        position: 'absolute',
                                        top: 'calc(100% + 8px)',
                                        insetInlineEnd: 0,
                                        background: 'var(--bg-secondary)',
                                        border: '1px solid var(--border-subtle)',
                                        borderRadius: 'var(--radius-lg)',
                                        padding: 'var(--space-xs)',
                                        minWidth: '180px',
                                        maxWidth: '90vw',
                                        boxShadow: 'var(--shadow-lg)',
                                        zIndex: 100,
                                    }}>
                                        <Link href="/dashboard" style={{
                                            display: 'block', padding: '0.6rem 1rem',
                                            fontSize: '0.85rem', borderRadius: 'var(--radius-md)',
                                            transition: 'background 0.2s',
                                            color: 'var(--text-primary)',
                                        }}>
                                            {t('dashboard')}
                                        </Link>
                                        <button onClick={logout} style={{
                                            display: 'block', width: '100%', textAlign: 'left',
                                            padding: '0.6rem 1rem', fontSize: '0.85rem',
                                            borderRadius: 'var(--radius-md)', background: 'none',
                                            border: 'none', cursor: 'pointer',
                                            color: 'var(--text-tertiary)',
                                            transition: 'color 0.2s',
                                        }}>
                                            {t('signOut')}
                                        </button>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <Link href="/login" style={{
                                padding: '0.4rem 1.2rem',
                                background: 'var(--bg-glass-light)',
                                border: '1px solid var(--border-medium)',
                                borderRadius: 'var(--radius-full)',
                                color: 'var(--text-primary)',
                                fontSize: '0.8rem',
                                fontWeight: 600,
                                textDecoration: 'none',
                                transition: 'all 0.2s',
                                letterSpacing: '0.02em',
                            }}>
                                {t('signIn')}
                            </Link>
                        )}
                        {/* Language Switcher — desktop only */}
                        <div style={{ position: 'relative' }} className="navbar-desktop-only">
                            <button
                                onClick={(e) => { e.stopPropagation(); setLangMenuOpen(!langMenuOpen) }}
                                title={t('language')}
                                style={{
                                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                                    background: 'none', border: 'none', cursor: 'pointer',
                                    color: 'var(--text-secondary)', transition: 'color 0.2s',
                                    padding: '4px',
                                }}
                            >
                                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <circle cx="12" cy="12" r="10" />
                                    <ellipse cx="12" cy="12" rx="4" ry="10" />
                                    <path d="M2 12h20" />
                                </svg>
                            </button>
                            {langMenuOpen && (
                                <div style={{
                                    position: 'absolute',
                                    top: 'calc(100% + 8px)',
                                    insetInlineEnd: 0,
                                    background: 'var(--bg-secondary)',
                                    border: '1px solid var(--border-subtle)',
                                    borderRadius: 'var(--radius-lg)',
                                    padding: 'var(--space-xs)',
                                    minWidth: '160px',
                                    maxWidth: '90vw',
                                    maxHeight: '320px',
                                    overflowY: 'auto',
                                    boxShadow: 'var(--shadow-lg)',
                                    zIndex: 100,
                                }}>
                                    {locales.map((loc) => (
                                        <button
                                            key={loc}
                                            onClick={() => switchLocale(loc)}
                                            style={{
                                                display: 'block', width: '100%', textAlign: 'left',
                                                padding: '0.5rem 0.8rem', fontSize: '0.82rem',
                                                borderRadius: 'var(--radius-md)', background: currentLocale === loc ? 'rgba(212,168,83,0.1)' : 'none',
                                                border: 'none', cursor: 'pointer',
                                                color: currentLocale === loc ? 'var(--accent-gold)' : 'var(--text-primary)',
                                                fontWeight: currentLocale === loc ? 600 : 400,
                                                transition: 'background 0.2s',
                                            }}
                                        >
                                            {localeNames[loc]}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>

                    <button
                        className="navbar-menu-btn"
                        onClick={() => setMobileOpen(!mobileOpen)}
                        aria-label="Toggle menu"
                    >
                        <span></span>
                        <span></span>
                        <span></span>
                    </button>
                </div>
            </nav>

            {/* ═══ MOBILE SIDE DRAWER ═══ */}
            {/* Backdrop overlay */}
            {mobileOpen && (
                <div
                    className="mobile-drawer-backdrop"
                    onClick={() => setMobileOpen(false)}
                    aria-hidden="true"
                />
            )}
            <div className={`mobile-drawer ${mobileOpen ? 'open' : ''}`}>
                {/* ── Profile Section ── */}
                <div className="drawer-profile">
                    {user ? (
                        <>
                            <div className="drawer-avatar-wrap">
                                <div className="drawer-avatar">
                                    {user.name.charAt(0).toUpperCase()}
                                </div>
                                <span className="drawer-status-dot" />
                            </div>
                            <div className="drawer-user-info">
                                <span className="drawer-user-name">{user.name}</span>
                                <span className="drawer-user-role">
                                    {user.role === 'admin' || user.role === 'superadmin' ? `👑 ${t('admin')}` : `🎬 ${t('member')}`}
                                </span>
                            </div>
                        </>
                    ) : (
                        <>
                            <div className="drawer-avatar-wrap">
                                <div className="drawer-avatar" style={{ background: 'var(--bg-glass-light)' }}>
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
                                        <circle cx="12" cy="7" r="4" />
                                    </svg>
                                </div>
                            </div>
                            <div className="drawer-user-info">
                                <span className="drawer-user-name">{t('guest')}</span>
                                <Link href="/login" onClick={() => setMobileOpen(false)}
                                    className="drawer-sign-in-link">
                                    {t('signIn')} →
                                </Link>
                            </div>
                        </>
                    )}
                    <button
                        onClick={() => setMobileOpen(false)}
                        aria-label="Close menu"
                        className="drawer-close"
                    >
                        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <line x1="18" y1="6" x2="6" y2="18" />
                            <line x1="6" y1="6" x2="18" y2="18" />
                        </svg>
                    </button>
                </div>

                {/* ── Quick Actions — Glass Card Grid (Smart Priority) ── */}
                {(() => {
                    // Slot 1 = Home (always). Slots 2 & 3 = priority: Training/Scripts first, then Works/Casting
                    type QCard = { href: string; label: string; path: string; icon: React.ReactNode };
                    const pool: QCard[] = [];
                    if (sections.training) pool.push({
                        href: '/training', label: t('training'), path: '/training',
                        icon: <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z" /><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z" /></svg>
                    });
                    if (sections.scripts) pool.push({
                        href: '/scripts', label: t('scripts'), path: '/scripts',
                        icon: <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" /><line x1="16" y1="13" x2="8" y2="13" /><line x1="16" y1="17" x2="8" y2="17" /></svg>
                    });
                    // Fill remaining slots with Works, then Casting
                    if (pool.length < 2) pool.push({
                        href: '/works', label: t('works'), path: '/works',
                        icon: <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="2" width="20" height="20" rx="2.18" ry="2.18" /><line x1="7" y1="2" x2="7" y2="22" /><line x1="17" y1="2" x2="17" y2="22" /><line x1="2" y1="12" x2="22" y2="12" /><line x1="2" y1="7" x2="7" y2="7" /><line x1="2" y1="17" x2="7" y2="17" /><line x1="17" y1="7" x2="22" y2="7" /><line x1="17" y1="17" x2="22" y2="17" /></svg>
                    });
                    if (pool.length < 2 && sections.casting) pool.push({
                        href: '/casting', label: t('casting'), path: '/casting',
                        icon: <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M23 7l-7 5 7 5V7z" /><rect x="1" y="5" width="15" height="14" rx="2" ry="2" /></svg>
                    });
                    if (pool.length < 2) pool.push({
                        href: '/upcoming', label: t('upcoming'), path: '/upcoming',
                        icon: <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10" /><polyline points="12 6 12 12 16 14" /></svg>
                    });
                    const slots = pool.slice(0, 2);

                    return (
                        <div className="drawer-quick-actions">
                            {/* Slot 1: Home — Always */}
                            <Link href="/" onClick={() => setMobileOpen(false)}
                                className={`drawer-quick-card ${pathname === '/' ? 'active-page' : ''}`}>
                                <span className="quick-icon">
                                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                        <path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z" />
                                        <polyline points="9 22 9 12 15 12 15 22" />
                                    </svg>
                                </span>
                                <span className="quick-label">{t('home')}</span>
                            </Link>
                            {/* Slots 2 & 3: Dynamic priority */}
                            {slots.map((card) => (
                                <Link key={card.href} href={card.href} onClick={() => setMobileOpen(false)}
                                    className={`drawer-quick-card ${pathname === card.path ? 'active-page' : ''}`}>
                                    <span className="quick-icon">{card.icon}</span>
                                    <span className="quick-label">{card.label}</span>
                                </Link>
                            ))}
                        </div>
                    );
                })()}

                {/* ── Account Actions ── */}
                {user && (
                    <div className="drawer-section">
                        <Link href="/dashboard" onClick={() => setMobileOpen(false)}
                            className={`drawer-item ${pathname === '/dashboard' ? 'active-page' : ''}`}>
                            <span className="drawer-icon-badge">
                                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                    <rect x="3" y="3" width="7" height="7" />
                                    <rect x="14" y="3" width="7" height="7" />
                                    <rect x="14" y="14" width="7" height="7" />
                                    <rect x="3" y="14" width="7" height="7" />
                                </svg>
                            </span>
                            {t('dashboard')}
                        </Link>
                    </div>
                )}

                {/* ── Discover Section ── */}
                <div className="drawer-section">
                    <span className="drawer-section-label">{t('discover')}</span>
                    <Link href="/about" onClick={() => setMobileOpen(false)}
