        </>
    );
}

'use client'

import { usePathname } from 'next/navigation'
import { useEffect, useRef, useState } from 'react'

export default function PageTransition({ children }: { children: React.ReactNode }) {
    const pathname = usePathname()
    const [displayChildren, setDisplayChildren] = useState(children)
    const [stage, setStage] = useState<'in' | 'out'>('in')
    const prevPathname = useRef(pathname)
    const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null)

    useEffect(() => {
        if (pathname === prevPathname.current) {
            setDisplayChildren(children)
            return
        }

        // Path changed: start fade-out
        setStage('out')
        if (timerRef.current) clearTimeout(timerRef.current)

        timerRef.current = setTimeout(() => {
            // After fade-out, swap content and fade in
            prevPathname.current = pathname
            setDisplayChildren(children)
            setStage('in')
        }, 80) // short 80ms fade-out

        return () => {
            if (timerRef.current) clearTimeout(timerRef.current)
        }
    }, [pathname, children])

    return (
        <div
            style={{
                opacity: stage === 'out' ? 0 : 1,
                transition: stage === 'out' ? 'opacity 80ms ease-out' : 'opacity 200ms ease-in',
                minHeight: '100vh',
                background: 'var(--bg-primary)',
            }}
        >
            {displayChildren}
        </div>
    )
}

'use client'

import { useEffect, useRef, type ReactNode, type CSSProperties } from 'react'
import ScrollReveal3D from '@/components/ScrollReveal3D'
import TiltCard3D from '@/components/TiltCard3D'

interface ProjectDetail3DProps {
    children: ReactNode
}

/* ─── Parallax Hero Background ─── */
export function ParallaxHeroBg({ imageUrl, fallback }: { imageUrl?: string | null; fallback?: string }) {
    const bgRef = useRef<HTMLDivElement>(null)

    useEffect(() => {
        const el = bgRef.current
        if (!el) return

        let rafId: number
        const handleMouseMove = (e: MouseEvent) => {
            rafId = requestAnimationFrame(() => {
                const x = (e.clientX / window.innerWidth - 0.5) * 15
                const y = (e.clientY / window.innerHeight - 0.5) * 10
                el.style.transform = `translate3d(${x}px, ${y}px, 0) scale(1.08)`
            })
        }

        window.addEventListener('mousemove', handleMouseMove)
        return () => {
            window.removeEventListener('mousemove', handleMouseMove)
            cancelAnimationFrame(rafId)
        }
    }, [])

    return (
        <div
            ref={bgRef}
            className="project-hero-bg"
            style={{
                backgroundImage: imageUrl
                    ? `url(${imageUrl})`
                    : fallback || 'linear-gradient(135deg, var(--bg-tertiary), var(--bg-secondary))',
                transition: 'transform 0.3s ease-out',
                willChange: 'transform',
            }}
        />
    )
}

/* ─── 3D Content Section ─── */
export function ContentReveal3D({ children, direction = 'up', delay = 0 }: {
    children: ReactNode
    direction?: 'up' | 'left' | 'right'
    delay?: number
}) {
    return (
        <ScrollReveal3D direction={direction} delay={delay} distance={50} rotate={6}>
            {children}
        </ScrollReveal3D>
    )
}

/* ─── 3D Sidebar Card ─── */
export function SidebarCard3D({ children, delay = 0 }: { children: ReactNode; delay?: number }) {
    return (
        <ScrollReveal3D direction="right" delay={delay} distance={40} rotate={5}>
            <TiltCard3D intensity={8} scale={1.02} perspective={1000}>
                {children}
            </TiltCard3D>
        </ScrollReveal3D>
    )
}

'use client'

import { useRef, useState, useEffect } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { useTranslations, useLocale } from 'next-intl'

interface CastingCall {
    id: string
    roleName: string
    roleType: string
    ageRange: string | null
    gender: string | null
    translations: string | null
}

interface Episode {
    id: string
    title: string
    number: number
    season: number
    videoUrl: string | null
    duration: string | null
}

interface ProjectData {
    id: string
    title: string
    slug: string
    tagline: string
    description: string
    status: string
    projectType: string
    coverImage: string | null
    trailerUrl: string | null
    filmUrl: string | null
    genre: string | null
    year: string | null
    duration: string | null
    castingCalls: CastingCall[]
    episodes: Episode[]
    translations: string | null
}

const statusColors: Record<string, { color: string; bg: string }> = {
    completed: { color: 'var(--color-success)', bg: 'rgba(52,211,153,0.12)' },
    'in-production': { color: 'var(--accent-gold)', bg: 'rgba(212,168,83,0.12)' },
    upcoming: { color: 'var(--color-info)', bg: 'rgba(96,165,250,0.12)' },
}

const statusLabelKeys: Record<string, string> = {
    completed: 'completed',
    'in-production': 'inProduction',
    upcoming: 'comingSoon',
}

export default function ProjectDetailClient({ project }: { project: ProjectData }) {
    const t = useTranslations('projectDetail')
    const locale = useLocale()
    const trailerRef = useRef<HTMLDivElement>(null)
    const videoRef = useRef<HTMLVideoElement>(null)
    const [isTrailerVisible, setIsTrailerVisible] = useState(false)
    const [user, setUser] = useState<{ id: string; name: string } | null>(null)
    const [checkingAuth, setCheckingAuth] = useState(false)
    const [isSaved, setIsSaved] = useState(false)
    const router = useRouter()
    const colors = statusColors[project.status] || statusColors.upcoming
    const statusLabel = t(statusLabelKeys[project.status] || 'comingSoon')
    const status = { label: statusLabel, ...colors }

    // Parse translations for current locale
    const tr = (() => {
        if (locale === 'en' || !project.translations) return null
        try { return JSON.parse(project.translations)?.[locale] || null } catch { return null }
    })()
    const title = tr?.title || project.title
    const tagline = tr?.tagline || project.tagline
    const description = tr?.description || project.description
    const genre = tr?.genre || project.genre

    // Check user session + watchlist status
    useEffect(() => {
        fetch('/api/auth/me')
            .then(r => r.ok ? r.json() : null)
            .then(data => {
                if (data?.user) {
                    setUser(data.user)
                    // Check if project is in watchlist
                    fetch(`/api/watchlist?projectId=${project.id}`)
                        .then(r => r.json())
                        .then(d => { if (d?.saved) setIsSaved(true) })
                        .catch(() => { })
                }
            })
            .catch(() => { })
    }, [])

    // Handle hash scrolling on mount
    useEffect(() => {
        if (window.location.hash === '#trailer' && trailerRef.current) {
            setTimeout(() => {
                trailerRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' })
            }, 500)
        }
    }, [])

    const scrollToTrailer = () => {
        setIsTrailerVisible(true)
        setTimeout(() => {
            trailerRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' })
            // Auto-play when scrolled to
            setTimeout(() => {
                videoRef.current?.play().catch(() => { })
            }, 600)
        }, 100)
        // Record watch history for trailer view
        if (user) {
            fetch('/api/dashboard/history', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ projectId: project.id, progress: 0 }),
            }).catch(() => { })
        }
    }

    const handleWatchNow = () => {
        setCheckingAuth(true)
        fetch('/api/auth/me')
            .then(r => r.ok ? r.json() : null)
            .then(data => {
                if (data?.user) {
                    // User is logged in, play the film
                    if (project.filmUrl) {
                        router.push(`/works/${project.slug}/watch`)
                    } else {
                        // Fallback: fullscreen the trailer
                        const vid = videoRef.current
                        if (vid) {
                            vid.play().catch(() => { })
                            if (vid.requestFullscreen) vid.requestFullscreen()
                        }
                    }
                } else {
                    // Not logged in, redirect to login
                    router.push(`/login?redirect=/works/${project.slug}/watch`)
                }
            })
            .catch(() => {
                router.push(`/login?redirect=/works/${project.slug}/watch`)
            })
            .finally(() => setCheckingAuth(false))
    }

    const isVideoFile = (url: string) => url.endsWith('.mp4') || url.endsWith('.webm') || url.endsWith('.mov')

    return (
        <>
            {/* ═══ CINEMATIC POSTER HERO ═══ */}
            <section style={{
                position: 'relative',
                height: '85vh',
                minHeight: '550px',
                maxHeight: '800px',
                overflow: 'hidden',
                display: 'flex',
                alignItems: 'flex-end',
            }}>
                {/* Background poster */}
                <div style={{
                    position: 'absolute',
                    inset: 0,
                    backgroundImage: project.coverImage
                        ? `url(${project.coverImage})`
                        : 'linear-gradient(135deg, var(--bg-tertiary), var(--bg-primary))',
                    backgroundSize: 'cover',
                    backgroundPosition: 'center top',
                    transform: 'scale(1.05)',
                    filter: 'brightness(0.8) contrast(1.1)',
                }} />

                {/* Gradient overlays for text readability */}
                <div style={{
                    position: 'absolute',
                    inset: 0,
                    background: `
                        linear-gradient(180deg,
                            rgba(13,15,20,0.1) 0%,
                            rgba(13,15,20,0.0) 25%,
                            rgba(13,15,20,0.2) 55%,
                            rgba(13,15,20,0.75) 78%,
                            rgba(13,15,20,1) 100%
                        )
                    `,
                }} />
                {/* Side vignette */}
                <div style={{
                    position: 'absolute',
                    inset: 0,
                    background: 'linear-gradient(90deg, rgba(13,15,20,0.3) 0%, transparent 25%, transparent 75%, rgba(13,15,20,0.3) 100%)',
                }} />

                {/* Film grain texture */}
                <div style={{
                    position: 'absolute',
                    inset: 0,
                    opacity: 0.03,
                    backgroundImage: 'url("data:image/svg+xml,%3Csvg viewBox=\'0 0 256 256\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noise\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.65\' numOctaves=\'3\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noise)\'/%3E%3C/svg%3E")',
                    pointerEvents: 'none',
                }} />

                {/* Content */}
                <div className="container" style={{
                    position: 'relative',
                    zIndex: 2,
                    paddingBottom: 'var(--space-3xl)',
                }}>
                    <div style={{ maxWidth: '680px' }}>
                        {/* Status badge */}
                        <div className="animate-fade-in-up" style={{ marginBottom: 'var(--space-md)' }}>
                            <span style={{
                                display: 'inline-flex', alignItems: 'center', gap: '6px',
                                fontSize: '0.65rem', fontWeight: 600, letterSpacing: '0.14em',
                                textTransform: 'uppercase',
                                color: status.color,
                                background: status.bg,
                                padding: '4px 12px',
                                borderRadius: 'var(--radius-full)',
                                border: `1px solid ${status.color}33`,
                            }}>
                                <span style={{
                                    width: '6px', height: '6px', borderRadius: '50%',
                                    background: status.color,
                                }} />
                                {status.label}
                            </span>
                            {project.projectType === 'series' && (
                                <span style={{
                                    display: 'inline-flex', marginLeft: '8px',
                                    fontSize: '0.65rem', fontWeight: 600, letterSpacing: '0.14em',
                                    textTransform: 'uppercase',
                                    color: 'var(--color-info)',
                                    background: 'rgba(96,165,250,0.12)',
                                    padding: '4px 12px',
                                    borderRadius: 'var(--radius-full)',
                                    border: '1px solid rgba(96,165,250,0.25)',
                                }}>{t('series')}</span>
                            )}
                        </div>

                        {/* Title */}
                        <h1 className="animate-fade-in-up delay-1" style={{
                            fontSize: 'clamp(2.4rem, 6vw, 4rem)',
                            fontWeight: 800,
                            lineHeight: 1.05,
                            marginBottom: 'var(--space-sm)',
                        }}>
                            {title}
                        </h1>

                        {/* Tagline */}
                        {tagline && (
                            <p className="animate-fade-in-up delay-1" style={{
                                fontFamily: 'var(--font-serif)',
                                fontStyle: 'italic',
                                fontSize: '1.2rem',
                                color: 'var(--text-secondary)',
                                marginBottom: 'var(--space-lg)',
                            }}>
                                {tagline}
                            </p>
                        )}

                        {/* Meta row */}
                        <div className="animate-fade-in-up delay-2" style={{
                            display: 'flex', alignItems: 'center', gap: 'var(--space-lg)',
                            marginBottom: 'var(--space-xl)',
                            fontSize: '0.85rem', color: 'var(--text-tertiary)',
                        }}>
                            {genre && (
                                <span style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <path d="M7 4v16M17 4v16M3 8h4m10 0h4M3 12h18M3 16h4m10 0h4M4 20h16a1 1 0 001-1V5a1 1 0 00-1-1H4a1 1 0 00-1 1v14a1 1 0 001 1z" />
                                    </svg>
                                    {genre}
                                </span>
                            )}
                            {project.year && <span>{project.year}</span>}
                            {project.duration && <span>{project.duration}</span>}
                            {project.projectType === 'series' && project.episodes.length > 0 && (
                                <span>{project.episodes.length} {project.episodes.length !== 1 ? t('episodes') : t('episode')}</span>
                            )}
                        </div>

                        {/* ─── Action Buttons ─── */}
                        <div className="animate-fade-in-up delay-3" style={{
                            display: 'flex', flexWrap: 'wrap', gap: 'var(--space-md)',
                        }}>
                            {project.trailerUrl && (
                                <button
                                    onClick={scrollToTrailer}
                                    className="btn btn-primary btn-lg"
                                    style={{
                                        display: 'inline-flex', alignItems: 'center', gap: '8px',
                                        cursor: 'pointer',
                                    }}
                                >
                                    <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
                                        <polygon points="5,3 19,12 5,21" />
                                    </svg>
                                    {t('watchTrailer')}
                                </button>
                            )}
                            {project.filmUrl && (
                                <button
                                    onClick={handleWatchNow}
                                    disabled={checkingAuth}
                                    className="btn btn-lg"
                                    style={{
                                        display: 'inline-flex', alignItems: 'center', gap: '8px',
                                        cursor: checkingAuth ? 'wait' : 'pointer',
                                        background: 'linear-gradient(135deg, rgba(212,168,83,0.2), rgba(212,168,83,0.08))',
                                        border: '1px solid rgba(212,168,83,0.35)',
                                        color: 'var(--accent-gold)',
                                        fontWeight: 600,
                                        minWidth: '180px',
                                        opacity: checkingAuth ? 0.7 : 1,
                                        transition: 'opacity 0.2s ease',
                                    }}
                                >
                                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <rect x="2" y="2" width="20" height="20" rx="2.18" ry="2.18" />
                                        <path d="M10 8l6 4-6 4V8z" fill="currentColor" />
                                    </svg>
                                    {user ? t('watchFull') : t('watchNow')}
