                    style={{
                        scrollMarginTop: '1rem',
                        padding: 'var(--space-3xl) 0',
                        background: 'linear-gradient(180deg, var(--bg-primary), var(--bg-secondary) 50%, var(--bg-primary))',
                    }}
                >
                    <div className="container">
                        <div style={{ textAlign: 'center', marginBottom: 'var(--space-xl)' }}>
                            <span style={{
                                fontSize: '0.65rem', fontWeight: 600, letterSpacing: '0.14em',
                                textTransform: 'uppercase', color: 'var(--accent-gold)',
                            }}>
                                {t('officialTrailer')}
                            </span>
                            <h2 style={{ marginTop: '4px', fontSize: '1.6rem' }}>
                                {project.title}
                            </h2>
                        </div>

                        <div style={{
                            maxWidth: '960px',
                            margin: '0 auto',
                            borderRadius: 'var(--radius-xl)',
                            overflow: 'hidden',
                            border: '1px solid var(--border-subtle)',
                            boxShadow: '0 20px 60px rgba(0,0,0,0.5), 0 0 0 1px rgba(212,168,83,0.05)',
                            background: '#000',
                            position: 'relative',
                        }}>
                            {isVideoFile(project.trailerUrl) ? (
                                <video
                                    ref={videoRef}
                                    src={project.trailerUrl}
                                    controls
                                    controlsList="nodownload"
                                    onContextMenu={(e) => e.preventDefault()}
                                    poster={project.coverImage || undefined}
                                    style={{
                                        width: '100%',
                                        aspectRatio: '16/9',
                                        display: 'block',
                                        objectFit: 'contain',
                                        background: '#000',
                                    }}
                                />
                            ) : (
                                <iframe
                                    src={project.trailerUrl}
                                    style={{
                                        width: '100%',
                                        aspectRatio: '16/9',
                                        display: 'block',
                                        border: 'none',
                                    }}
                                    allowFullScreen
                                />
                            )}
                        </div>

                        <div style={{
                            textAlign: 'center', marginTop: 'var(--space-lg)',
                            fontSize: '0.75rem', color: 'var(--text-tertiary)',
                        }}>
                            {t('fullscreenTip')}
                        </div>
                    </div>
                </section>
            )}

            {/* ═══ CONTENT SECTION ═══ */}
            <section style={{ padding: 'var(--space-2xl) 0 var(--space-xl)' }}>
                <div className="container" style={{ maxWidth: '100%', boxSizing: 'border-box' }}>
                    <div className="responsive-grid-2-1" style={{ maxWidth: '100%', overflow: 'hidden' }}>
                        {/* Main Content */}
                        <div>
                            <h2 style={{ marginBottom: 'var(--space-lg)' }}>{t('synopsis')}</h2>
                            <div className="divider" />
                            <p style={{ fontSize: '1.05rem', lineHeight: 1.8, overflowWrap: 'break-word', wordBreak: 'break-word' }}>{description}</p>

                            {/* Episodes list for series */}
                            {project.projectType === 'series' && project.episodes.length > 0 && (
                                <div id="episodes" style={{ marginTop: 'var(--space-3xl)', scrollMarginTop: '2rem' }}>
                                    <h3 style={{ marginBottom: 'var(--space-lg)' }}>
                                        {t('episodes')}
                                        <span style={{
                                            fontSize: '0.8rem', fontWeight: 400,
                                            color: 'var(--text-tertiary)', marginLeft: '8px',
                                        }}>
                                            ({project.episodes.length})
                                        </span>
                                    </h3>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-sm)' }}>
                                        {project.episodes.map((ep) => (
                                            <div key={ep.id} style={{
                                                display: 'flex', alignItems: 'center', gap: 'var(--space-sm)',
                                                padding: 'var(--space-sm) var(--space-md)',
                                                background: 'rgba(255,255,255,0.02)',
                                                borderRadius: 'var(--radius-md)',
                                                border: '1px solid var(--border-subtle)',
                                                transition: 'all 0.2s',
                                            }}>
                                                <span style={{
                                                    fontFamily: 'var(--font-display)',
                                                    fontSize: '1.1rem', fontWeight: 700,
                                                    color: 'var(--accent-gold)',
                                                    minWidth: '28px',
                                                }}>
                                                    {ep.number}
                                                </span>
                                                <div style={{ flex: 1 }}>
                                                    <div style={{ fontWeight: 600, fontSize: '0.9rem' }}>{ep.title}</div>
                                                    {ep.duration && (
                                                        <span style={{ fontSize: '0.75rem', color: 'var(--text-tertiary)' }}>
                                                            S{ep.season} • {ep.duration}
                                                        </span>
                                                    )}
                                                </div>
                                                {ep.videoUrl && (
                                                    <span style={{
                                                        fontSize: '0.6rem', fontWeight: 600,
                                                        color: 'var(--color-success)',
                                                        background: 'rgba(52,211,153,0.1)',
                                                        padding: '3px 8px',
                                                        borderRadius: 'var(--radius-full)',
                                                        border: '1px solid rgba(52,211,153,0.2)',
                                                    }}>▶ {t('watch')}</span>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Sidebar */}
                        <div>
                            {/* Compact Project Info */}
                            <div className="glass-card" style={{ padding: 'var(--space-md)', marginBottom: 'var(--space-lg)', maxWidth: '100%', boxSizing: 'border-box' }}>
                                <div style={{
                                    display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 'var(--space-sm)',
                                }}>
                                    {genre && (
                                        <div>
                                            <div style={{ fontSize: '0.6rem', textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-tertiary)', marginBottom: '1px' }}>{t('genre')}</div>
                                            <div style={{ fontSize: '0.85rem', color: 'var(--text-primary)' }}>{genre}</div>
                                        </div>
                                    )}
                                    <div>
                                        <div style={{ fontSize: '0.6rem', textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-tertiary)', marginBottom: '1px' }}>{t('status')}</div>
                                        <span style={{
                                            display: 'inline-flex', alignItems: 'center', gap: '4px',
                                            fontSize: '0.8rem', fontWeight: 600, color: status.color,
                                        }}>
                                            <span style={{ width: '5px', height: '5px', borderRadius: '50%', background: status.color }} />
                                            {status.label}
                                        </span>
                                    </div>
                                    {project.year && (
                                        <div>
                                            <div style={{ fontSize: '0.6rem', textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-tertiary)', marginBottom: '1px' }}>{t('year')}</div>
                                            <div style={{ fontSize: '0.85rem', color: 'var(--text-primary)' }}>{project.year}</div>
                                        </div>
                                    )}
                                    {project.duration && (
                                        <div>
                                            <div style={{ fontSize: '0.6rem', textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-tertiary)', marginBottom: '1px' }}>{t('duration')}</div>
                                            <div style={{ fontSize: '0.85rem', color: 'var(--text-primary)' }}>{project.duration}</div>
                                        </div>
                                    )}
                                </div>
                            </div>

                            {/* Casting Calls */}
                            {project.castingCalls.length > 0 && (
                                <div className="glass-card" style={{ padding: 'var(--space-md)', border: '1px solid var(--border-accent)', maxWidth: '100%', boxSizing: 'border-box' }}>
                                    <h4 style={{ color: 'var(--accent-gold)', marginBottom: 'var(--space-md)', fontSize: '0.9rem' }}>
                                        🎭 {t('openCasting')}
                                    </h4>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-sm)' }}>
                                        {project.castingCalls.map((call) => (
                                            <div key={call.id} style={{ paddingBottom: 'var(--space-sm)', borderBottom: '1px solid var(--border-subtle)' }}>
                                                <div style={{ fontWeight: 600, marginBottom: '2px', fontSize: '0.85rem' }}>{call.roleName}</div>
                                                <div style={{ fontSize: '0.7rem', color: 'var(--text-tertiary)', marginBottom: 'var(--space-xs)' }}>
                                                    {(() => { const rk: Record<string, string> = { lead: 'roleTypeLead', supporting: 'roleTypeSupporting', extra: 'roleTypeExtra' }; return t(rk[call.roleType.toLowerCase()] || 'roleTypeLead'); })()} • {call.ageRange || t('anyAge')} • {call.gender || t('anyGender')}
                                                </div>
                                                <Link href={`/casting/${call.id}/apply`} className="btn btn-primary btn-sm" style={{ width: '100%' }}>
                                                    {t('applyNow')}
                                                </Link>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </section>
        </>
    )
}

'use client'

import { useRef, useCallback, type ReactNode, type CSSProperties } from 'react'

interface TiltCard3DProps {
    children: ReactNode
    className?: string
    style?: CSSProperties
    href?: string
    intensity?: number       // tilt strength in degrees (default 12)
    glare?: boolean          // show glare highlight
    scale?: number           // hover scale (default 1.04)
    perspective?: number     // perspective distance (default 800)
}

export default function TiltCard3D({
    children,
    className = '',
    style,
    href,
    intensity = 12,
    glare = true,
    scale = 1.04,
    perspective = 800,
}: TiltCard3DProps) {
    const cardRef = useRef<HTMLDivElement>(null)
    const glareRef = useRef<HTMLDivElement>(null)
    const rafRef = useRef<number | null>(null)

    const targetRef = useRef({ x: 0, y: 0 })
    const currentRef = useRef({ x: 0, y: 0 })
    const animatingRef = useRef(false)

    const targetScaleRef = useRef(1)
    const currentScaleRef = useRef(1)

    // Smooth animation loop — lerp toward target rotation
    const animate = useCallback(() => {
        const card = cardRef.current
        if (!card) return

        const lerp = 0.08 // smoothing factor — lower = smoother
        currentRef.current.x += (targetRef.current.x - currentRef.current.x) * lerp
        currentRef.current.y += (targetRef.current.y - currentRef.current.y) * lerp
        currentScaleRef.current += (targetScaleRef.current - currentScaleRef.current) * lerp

        const s = currentScaleRef.current
        card.style.transform = `perspective(${perspective}px) rotateX(${currentRef.current.x}deg) rotateY(${currentRef.current.y}deg) scale3d(${s}, ${s}, ${s})`

        // Keep animating if still far from target
        const dx = Math.abs(targetRef.current.x - currentRef.current.x)
        const dy = Math.abs(targetRef.current.y - currentRef.current.y)
        const ds = Math.abs(targetScaleRef.current - currentScaleRef.current)
        if (dx > 0.01 || dy > 0.01 || ds > 0.001) {
            rafRef.current = requestAnimationFrame(animate)
        } else {
            animatingRef.current = false
        }
    }, [perspective])

    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
        const card = cardRef.current
        if (!card) return

        const rect = card.getBoundingClientRect()
        const x = e.clientX - rect.left
        const y = e.clientY - rect.top
        const centerX = rect.width / 2
        const centerY = rect.height / 2

        targetRef.current.x = ((y - centerY) / centerY) * -intensity
        targetRef.current.y = ((x - centerX) / centerX) * intensity
        targetScaleRef.current = scale

        if (glareRef.current) {
            const glareX = (x / rect.width) * 100
            const glareY = (y / rect.height) * 100
            glareRef.current.style.background = `radial-gradient(circle at ${glareX}% ${glareY}%, rgba(212,168,83,0.15) 0%, transparent 60%)`
            glareRef.current.style.opacity = '1'
        }

        if (!animatingRef.current) {
            animatingRef.current = true
            rafRef.current = requestAnimationFrame(animate)
        }
    }, [intensity, animate])

    const handleMouseLeave = useCallback(() => {
        targetRef.current = { x: 0, y: 0 }
        targetScaleRef.current = 1

        if (glareRef.current) {
            glareRef.current.style.opacity = '0'
        }

        // Start smooth return animation if not already animating
        if (!animatingRef.current) {
            animatingRef.current = true
            rafRef.current = requestAnimationFrame(animate)
        }
    }, [animate])

    const Tag = href ? 'a' : 'div'

    return (
        <div
            className="tilt-card-wrapper"
            style={{ perspective: `${perspective}px` }}
        >
            <div
                ref={cardRef}
                className={`tilt-card-3d ${className}`}
                style={{
                    ...style,
                    transition: 'transform 0.4s cubic-bezier(0.03, 0.98, 0.52, 0.99)',
                    willChange: 'transform',
                }}
                onMouseMove={handleMouseMove}
                onMouseLeave={handleMouseLeave}
            >
                {children}

                {/* 3D depth shadow */}
                <div className="tilt-card-shadow" style={{ pointerEvents: 'none' }} />

                {/* Glare overlay */}
                {glare && (
                    <div
                        ref={glareRef}
                        className="tilt-card-glare"
                        style={{ pointerEvents: 'none' }}
                    />
                )}

                {/* Edge light effect */}
                <div className="tilt-card-edge-light" style={{ pointerEvents: 'none' }} />
            </div>
        </div>
    )
}

'use client'

import { useState, useRef, useEffect, useCallback } from 'react'
import Link from 'next/link'
import type { TranscriptSegment } from '@/lib/transcribe-client'
import { LANGUAGE_NAMES } from '@/lib/subtitle-translator'

interface Episode {
    id: string
    title: string
    number: number
    season: number
    videoUrl: string | null
    duration: string | null
}

interface WatchProject {
    id: string
    title: string
    slug: string
    tagline: string
    description: string
    genre: string | null
    year: string | null
    duration: string | null
    coverImage: string | null
    filmUrl: string | null
    trailerUrl: string | null
    projectType: string
    status: string
    episodes: Episode[]
}

export default function WatchPlayer({ project }: { project: WatchProject }) {
    const videoRef = useRef<HTMLVideoElement>(null)
    const [isPlaying, setIsPlaying] = useState(false)
    const [currentTime, setCurrentTime] = useState(0)
    const [totalDuration, setTotalDuration] = useState(0)
    const [isFullscreen, setIsFullscreen] = useState(false)
    const [showControls, setShowControls] = useState(true)
    const [activeEpisode, setActiveEpisode] = useState<Episode | null>(null)
    const controlsTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
    const containerRef = useRef<HTMLDivElement>(null)

    const isSeries = project.projectType === 'series' && project.episodes.length > 0
    const currentVideoUrl = activeEpisode?.videoUrl || project.filmUrl

    // ── Subtitle state ──
    const [ccEnabled, setCcEnabled] = useState(false)
    const [showLangMenu, setShowLangMenu] = useState(false)
    const [ccSegments, setCcSegments] = useState<TranscriptSegment[]>([])
    const [ccLang, setCcLang] = useState('en')
    const [ccAvailable, setCcAvailable] = useState<string[]>([])
    const [ccLoading, setCcLoading] = useState(false)
    const [ccStatusText, setCcStatusText] = useState('')
    const [activeSubtitle, setActiveSubtitle] = useState('')

    // Find current subtitle based on video time
    useEffect(() => {
        if (!ccEnabled || ccSegments.length === 0) { setActiveSubtitle(''); return }
        const seg = ccSegments.find(s => currentTime >= s.start && currentTime <= s.end)
        setActiveSubtitle(seg?.text || '')
    }, [currentTime, ccEnabled, ccSegments])

    // Fetch subtitles from DB on mount
    useEffect(() => {
        const episodeId = activeEpisode?.id || ''
        const url = `/api/subtitles/${project.id}?lang=en${episodeId ? `&episodeId=${episodeId}` : ''}`
        fetch(url)
            .then(r => r.json())
            .then(data => {
                if (data.available && data.available.length > 0) {
                    setCcAvailable(data.available)
                }
            })
            .catch(() => {})
    }, [project.id, activeEpisode])

    // Load subtitles for a specific language
    const loadSubtitles = useCallback(async (lang: string) => {
        setCcLoading(true)
        setCcStatusText(`Loading ${LANGUAGE_NAMES[lang] || lang}...`)
        const episodeId = activeEpisode?.id || ''
        try {
            const url = `/api/subtitles/${project.id}?lang=${lang}${episodeId ? `&episodeId=${episodeId}` : ''}`
            const res = await fetch(url)
            const data = await res.json()
            if (data.segments && data.segments.length > 0) {
                setCcSegments(data.segments)
                setCcLang(lang)
                setCcEnabled(true)
                setCcStatusText('')
            } else {
                setCcStatusText('No subtitles available')
                setTimeout(() => setCcStatusText(''), 2000)
            }
        } catch {
            setCcStatusText('Failed to load subtitles')
            setTimeout(() => setCcStatusText(''), 2000)
        }
        setCcLoading(false)
    }, [project.id, activeEpisode])

    // Toggle CC button — only shows language menu (no in-browser processing)
    const toggleCC = useCallback(() => {
        if (ccEnabled) {
            setCcEnabled(false)
            setShowLangMenu(false)
            return
        }
        if (ccAvailable.length > 0) {
            setShowLangMenu(!showLangMenu)
        }
    }, [ccEnabled, ccAvailable, showLangMenu])

    useEffect(() => {
        if (isSeries && project.episodes.length > 0) {
            setActiveEpisode(project.episodes[0])
        }
    }, [isSeries, project.episodes])

    // Auto-hide controls after 3s of inactivity
    const resetControlsTimer = () => {
        setShowControls(true)
        if (controlsTimerRef.current) clearTimeout(controlsTimerRef.current)
        controlsTimerRef.current = setTimeout(() => {
            if (isPlaying) setShowControls(false)
        }, 3000)
    }

    useEffect(() => resetControlsTimer(), [isPlaying])

    const togglePlay = () => {
        const vid = videoRef.current
        if (!vid) return
        if (vid.paused) {
            vid.play().catch(() => { })
            setIsPlaying(true)
        } else {
            vid.pause()
            setIsPlaying(false)
        }
    }

    const toggleFullscreen = () => {
        const el = containerRef.current
        if (!el) return
        if (document.fullscreenElement) {
            document.exitFullscreen()
            setIsFullscreen(false)
        } else {
            el.requestFullscreen().catch(() => { })
            setIsFullscreen(true)
        }
    }

    const handleTimeUpdate = () => {
        const vid = videoRef.current
        if (vid) setCurrentTime(vid.currentTime)
    }

    const handleLoadedMetadata = () => {
        const vid = videoRef.current
        if (vid) setTotalDuration(vid.duration)
    }

    const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
        const vid = videoRef.current
        if (vid) {
            vid.currentTime = Number(e.target.value)
            setCurrentTime(vid.currentTime)
        }
    }

    const formatTime = (s: number) => {
        const mins = Math.floor(s / 60)
        const secs = Math.floor(s % 60)
        return `${mins}:${secs.toString().padStart(2, '0')}`
    }

    const playEpisode = (ep: Episode) => {
        setActiveEpisode(ep)
        setIsPlaying(false)
        setCurrentTime(0)
        setTimeout(() => {
            const vid = videoRef.current
            if (vid && ep.videoUrl) {
                vid.src = ep.videoUrl
                vid.load()
                vid.play().catch(() => { })
                setIsPlaying(true)
            }
        }, 100)
    }

    const progress = totalDuration > 0 ? (currentTime / totalDuration) * 100 : 0

    return (
        <div style={{ minHeight: '100vh', background: 'var(--bg-primary)', paddingTop: '80px' }}>
            <div className="container" style={{ maxWidth: '1200px', padding: '0 var(--space-lg)' }}>

                {/* Back button */}
                <Link
                    href={`/works/${project.slug}`}
                    style={{
                        display: 'inline-flex', alignItems: 'center', gap: '6px',
                        fontSize: '0.85rem', color: 'var(--text-tertiary)',
                        marginBottom: 'var(--space-lg)', transition: 'color 0.2s',
                    }}
                    onMouseEnter={e => { e.currentTarget.style.color = 'var(--accent-gold)' }}
                    onMouseLeave={e => { e.currentTarget.style.color = 'var(--text-tertiary)' }}
                >
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5M12 19l-7-7 7-7" />
                    </svg>
                    Back to {project.title}
                </Link>

                {/* Video Player */}
                <div
                    ref={containerRef}
                    onMouseMove={resetControlsTimer}
                    onClick={togglePlay}
                    style={{
                        position: 'relative',
                        aspectRatio: '16/9',
                        background: '#000',
                        borderRadius: isFullscreen ? 0 : 'var(--radius-xl)',
                        overflow: 'hidden',
                        cursor: showControls ? 'default' : 'none',
                        border: isFullscreen ? 'none' : '1px solid var(--border-subtle)',
                    }}
                >
                    {currentVideoUrl ? (
                        <video
                            ref={videoRef}
                            src={currentVideoUrl}
                            onTimeUpdate={handleTimeUpdate}
                            onLoadedMetadata={handleLoadedMetadata}
                            onPlay={() => setIsPlaying(true)}
                            onPause={() => setIsPlaying(false)}
                            onEnded={() => setIsPlaying(false)}
                            controlsList="nodownload"
                            onContextMenu={(e) => e.preventDefault()}
                            style={{ width: '100%', height: '100%', objectFit: 'contain' }}
                            playsInline
                        />
                    ) : (
                        <div style={{
                            display: 'flex', flexDirection: 'column',
                            alignItems: 'center', justifyContent: 'center',
                            height: '100%', color: 'var(--text-tertiary)',
                        }}>
                            <div style={{ fontSize: '3rem', marginBottom: 'var(--space-md)', opacity: 0.3 }}>🎬</div>
                            <p>Video not available</p>
                        </div>
                    )}

                    {/* Play overlay */}
                    {!isPlaying && currentVideoUrl && (
                        <div style={{
                            position: 'absolute', inset: 0,
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            background: 'rgba(0,0,0,0.4)',
                            pointerEvents: 'none',
                        }}>
                            <div style={{
                                width: '70px', height: '70px',
                                borderRadius: '50%',
                                background: 'rgba(212,168,83,0.9)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                boxShadow: '0 0 30px rgba(212,168,83,0.3)',
                            }}>
                                <svg width="28" height="28" viewBox="0 0 24 24" fill="#000">
                                    <polygon points="8,5 19,12 8,19" />
                                </svg>
                            </div>
                        </div>
                    )}

                    {/* ── Subtitle overlay ── */}
                    {ccEnabled && (
                        <div style={{
                            position: 'absolute', bottom: '80px', left: '10%', right: '10%',
                            display: 'flex', flexDirection: 'column', alignItems: 'center',
                            pointerEvents: 'none', zIndex: 5, gap: '6px',
                        }}>
                            {ccLoading && ccStatusText && (
                                <div style={{
                                    background: 'rgba(0,0,0,0.75)', borderRadius: '8px',
                                    padding: '8px 16px', fontSize: '0.8rem',
                                    color: 'var(--accent-gold)', textAlign: 'center',
                                }}>
                                    ⏳ {ccStatusText}
                                </div>
                            )}
                            {activeSubtitle && (
                                <div style={{
                                    background: 'rgba(0,0,0,0.8)', borderRadius: '6px',
                                    padding: '6px 18px', fontSize: 'clamp(0.9rem, 2vw, 1.15rem)',
                                    color: '#fff', textAlign: 'center', lineHeight: 1.5,
                                    maxWidth: '80%', textShadow: '0 1px 3px rgba(0,0,0,0.5)',
                                    overflow: 'hidden',
                                    display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' as const,
                                }}>
                                    {activeSubtitle.length > 120 ? activeSubtitle.slice(0, 120) + '...' : activeSubtitle}
                                </div>
                            )}
                        </div>
                    )}

                    {/* Controls bar */}
                    {currentVideoUrl && (
                        <div
                            onClick={e => e.stopPropagation()}
                            style={{
                                position: 'absolute', bottom: 0, left: 0, right: 0,
                                background: 'linear-gradient(transparent, rgba(0,0,0,0.85))',
                                padding: 'var(--space-xl) var(--space-lg) var(--space-md)',
                                opacity: showControls ? 1 : 0,
                                transition: 'opacity 0.3s',
                                pointerEvents: showControls ? 'auto' : 'none',
                            }}
                        >
                            {/* Progress bar */}
                            <div style={{ position: 'relative', marginBottom: 'var(--space-sm)' }}>
                                <div style={{
                                    height: '4px', background: 'rgba(255,255,255,0.15)',
                                    borderRadius: '2px', overflow: 'hidden',
                                }}>
                                    <div style={{
                                        height: '100%', width: `${progress}%`,
                                        background: 'var(--accent-gold)',
                                        borderRadius: '2px',
                                        transition: 'width 0.1s linear',
                                    }} />
                                </div>
                                <input
                                    type="range" min="0" max={totalDuration || 0}
                                    value={currentTime} onChange={handleSeek}
                                    style={{
                                        position: 'absolute', top: '-6px', left: 0,
                                        width: '100%', height: '16px',
                                        opacity: 0, cursor: 'pointer',
                                    }}
                                />
                            </div>

                            {/* Controls row */}
                            <div style={{
                                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                            }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-md)' }}>
                                    <button onClick={togglePlay} style={{
                                        background: 'none', border: 'none', color: 'white',
                                        cursor: 'pointer', padding: '4px',
                                    }}>
                                        {isPlaying ? (
                                            <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                                                <rect x="6" y="4" width="4" height="16" />
                                                <rect x="14" y="4" width="4" height="16" />
                                            </svg>
                                        ) : (
                                            <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                                                <polygon points="8,5 19,12 8,19" />
                                            </svg>
                                        )}
                                    </button>
                                    <span style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.7)', fontFamily: 'var(--font-mono, monospace)' }}>
                                        {formatTime(currentTime)} / {formatTime(totalDuration)}
                                    </span>
                                </div>

                                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-sm)' }}>
                                    <span style={{
                                        fontSize: '0.65rem', fontWeight: 600, letterSpacing: '0.1em',
                                        textTransform: 'uppercase',
                                        color: 'var(--accent-gold)',
                                        opacity: 0.7,
                                    }}>AIM Studio</span>
                                    {/* CC Button + Language Menu — only shown when subtitles exist */}
                                    {ccAvailable.length > 0 && (
                                    <div style={{ position: 'relative' }}>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); toggleCC() }}
                                            title={ccEnabled ? 'Turn off subtitles' : 'Turn on subtitles'}
                                            style={{
                                                background: ccEnabled ? 'rgba(212,168,83,0.25)' : 'none',
                                                border: ccEnabled ? '1px solid rgba(212,168,83,0.5)' : '1px solid transparent',
                                                color: ccEnabled ? 'var(--accent-gold)' : 'white',
                                                cursor: 'pointer', padding: '3px 6px',
                                                borderRadius: '4px', fontSize: '0.7rem',
                                                fontWeight: 700, letterSpacing: '0.05em',
                                                transition: 'all 0.2s',
                                            }}
                                        >
                                            CC{ccEnabled && ccLang !== 'en' ? ` (${ccLang.toUpperCase()})` : ''}
                                        </button>
                                        {/* Language dropdown */}
                                        {showLangMenu && ccAvailable.length > 0 && (
                                            <div style={{
                                                position: 'absolute', bottom: '100%', right: 0,
                                                marginBottom: '8px', background: 'rgba(13,15,20,0.95)',
                                                border: '1px solid rgba(212,168,83,0.3)',
                                                borderRadius: '8px', padding: '4px',
                                                minWidth: '140px', backdropFilter: 'blur(10px)',
                                                boxShadow: '0 8px 32px rgba(0,0,0,0.5)',
                                            }}>
                                                <div style={{
                                                    fontSize: '0.6rem', fontWeight: 600,
                                                    textTransform: 'uppercase', letterSpacing: '0.1em',
                                                    color: 'var(--accent-gold)', padding: '6px 10px 4px',
                                                }}>Subtitles</div>
                                                {ccAvailable.map(lang => (
                                                    <button
                                                        key={lang}
                                                        onClick={(e) => {
                                                            e.stopPropagation()
                                                            loadSubtitles(lang)
                                                            setShowLangMenu(false)
                                                        }}
                                                        style={{
                                                            display: 'block', width: '100%',
                                                            padding: '6px 10px', textAlign: 'left',
                                                            background: ccLang === lang && ccEnabled ? 'rgba(212,168,83,0.15)' : 'transparent',
                                                            border: 'none', borderRadius: '4px',
                                                            color: ccLang === lang && ccEnabled ? 'var(--accent-gold)' : 'var(--text-secondary)',
                                                            fontSize: '0.8rem', cursor: 'pointer',
                                                            transition: 'background 0.15s',
                                                        }}
                                                        onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.08)' }}
                                                        onMouseLeave={e => { e.currentTarget.style.background = ccLang === lang && ccEnabled ? 'rgba(212,168,83,0.15)' : 'transparent' }}
                                                    >
                                                        {LANGUAGE_NAMES[lang] || lang}
                                                        {ccLang === lang && ccEnabled && ' ✓'}
                                                    </button>
                                                ))}
                                                <div style={{ height: '1px', background: 'rgba(255,255,255,0.08)', margin: '4px 6px' }} />
                                                <button
                                                    onClick={(e) => {
                                                        e.stopPropagation()
                                                        setCcEnabled(false)
                                                        setShowLangMenu(false)
                                                    }}
                                                    style={{
                                                        display: 'block', width: '100%',
                                                        padding: '6px 10px', textAlign: 'left',
                                                        background: !ccEnabled ? 'rgba(255,255,255,0.06)' : 'transparent',
                                                        border: 'none', borderRadius: '4px',
                                                        color: 'var(--text-tertiary)', fontSize: '0.8rem', cursor: 'pointer',
                                                    }}
                                                    onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.08)' }}
                                                    onMouseLeave={e => { e.currentTarget.style.background = 'transparent' }}
                                                >
                                                    Off
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                    )}
                                    <button onClick={toggleFullscreen} style={{
                                        background: 'none', border: 'none', color: 'white',
                                        cursor: 'pointer', padding: '4px',
                                    }}>
                                        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                            {isFullscreen ? (
                                                <>
                                                    <polyline points="4 14 10 14 10 20" />
                                                    <polyline points="20 10 14 10 14 4" />
                                                    <line x1="14" y1="10" x2="21" y2="3" />
                                                    <line x1="3" y1="21" x2="10" y2="14" />
                                                </>
                                            ) : (
                                                <>
                                                    <polyline points="15 3 21 3 21 9" />
                                                    <polyline points="9 21 3 21 3 15" />
                                                    <line x1="21" y1="3" x2="14" y2="10" />
                                                    <line x1="3" y1="21" x2="10" y2="14" />
                                                </>
                                            )}
                                        </svg>
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Project Info + Episodes */}
                <div style={{
                    display: 'flex', gap: 'var(--space-2xl)',
                    marginTop: 'var(--space-xl)',
                    marginBottom: 'var(--space-2xl)',
                    flexWrap: 'wrap',
                }}>
                    {/* Info */}
                    <div style={{ flex: '1 1 400px', minWidth: 0 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-sm)', marginBottom: 'var(--space-xs)' }}>
                            {project.genre && (
                                <span style={{
                                    fontSize: '0.6rem', fontWeight: 600, letterSpacing: '0.12em',
                                    textTransform: 'uppercase', color: 'var(--accent-gold)',
                                }}>{project.genre}</span>
                            )}
                            {project.year && (
                                <span style={{ fontSize: '0.7rem', color: 'var(--text-tertiary)' }}>• {project.year}</span>
                            )}
                            {project.duration && (
                                <span style={{ fontSize: '0.7rem', color: 'var(--text-tertiary)' }}>• {project.duration}</span>
                            )}
                        </div>
                        <h1 style={{
                            fontSize: 'clamp(1.4rem, 3vw, 2rem)',
                            fontWeight: 800,
                            marginBottom: 'var(--space-xs)',
                        }}>
                            {activeEpisode
                                ? `${project.title} — S${activeEpisode.season}E${activeEpisode.number}: ${activeEpisode.title}`
                                : project.title}
                        </h1>
                        {project.tagline && (
                            <p style={{
                                fontSize: '0.95rem', fontStyle: 'italic',
                                color: 'var(--text-secondary)', marginBottom: 'var(--space-md)',
                            }}>{project.tagline}</p>
                        )}
                        <p style={{
                            fontSize: '0.85rem', lineHeight: 1.7,
                            color: 'var(--text-tertiary)',
                        }}>{project.description}</p>
                    </div>

                    {/* Episode list (series only) */}
                    {isSeries && (
                        <div style={{
                            flex: '0 0 280px',
                            background: 'var(--bg-secondary)',
                            borderRadius: 'var(--radius-lg)',
                            border: '1px solid var(--border-subtle)',
                            padding: 'var(--space-lg)',
                            maxHeight: '400px',
                            overflowY: 'auto',
                        }}>
                            <h3 style={{
                                fontSize: '0.75rem', fontWeight: 600,
                                textTransform: 'uppercase', letterSpacing: '0.1em',
                                color: 'var(--accent-gold)',
                                marginBottom: 'var(--space-md)',
                            }}>Episodes</h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                                {project.episodes.map(ep => (
                                    <button
                                        key={ep.id}
                                        onClick={() => playEpisode(ep)}
                                        style={{
                                            display: 'flex', alignItems: 'center', gap: 'var(--space-sm)',
                                            padding: '0.6rem 0.8rem',
                                            background: activeEpisode?.id === ep.id ? 'var(--accent-gold-glow)' : 'transparent',
                                            border: activeEpisode?.id === ep.id ? '1px solid rgba(212,168,83,0.3)' : '1px solid transparent',
                                            borderRadius: 'var(--radius-md)',
                                            cursor: ep.videoUrl ? 'pointer' : 'not-allowed',
                                            opacity: ep.videoUrl ? 1 : 0.4,
                                            textAlign: 'left',
                                            width: '100%',
                                            transition: 'all 0.2s',
                                            color: 'var(--text-primary)',
                                        }}
                                    >
                                        <span style={{
                                            fontSize: '0.7rem', fontWeight: 700,
                                            color: activeEpisode?.id === ep.id ? 'var(--accent-gold)' : 'var(--text-tertiary)',
                                            minWidth: '28px',
                                        }}>E{ep.number}</span>
                                        <div style={{ flex: 1, minWidth: 0 }}>
                                            <div style={{
                                                fontSize: '0.8rem', fontWeight: 600,
                                                overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                                            }}>{ep.title}</div>
                                            {ep.duration && (
                                                <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)' }}>{ep.duration}</div>
                                            )}
                                        </div>
                                        {activeEpisode?.id === ep.id && (
                                            <div style={{
                                                width: '6px', height: '6px',
                                                borderRadius: '50%',
                                                background: 'var(--accent-gold)',
                                            }} />
                                        )}
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import Link from 'next/link'
import Scene3D from '@/components/Scene3D'
import ScrollReveal3D from '@/components/ScrollReveal3D'
import TiltCard3D from '@/components/TiltCard3D'
import { useTranslations, useLocale } from 'next-intl'
import { getLocalizedProject } from '@/lib/localize'

interface Project {
    id: string
    title: string
    slug: string
    genre: string | null
    tagline: string | null
    status: string
    projectType: string
    year: string | null
    duration: string | null
    coverImage: string | null
    trailerUrl: string | null
    filmUrl: string | null
    episodeCount: number
    translations: string | null
}

interface HeroVideo {
    id: string
    url: string
    duration: number
}

interface WorksPageClientProps {
    projects: Project[]
    completedCount: number
    inProdCount: number
}

export default function WorksPageClient({ projects, completedCount, inProdCount }: WorksPageClientProps) {
    const t = useTranslations('works')
    const locale = useLocale()
    const [videos, setVideos] = useState<HeroVideo[]>([])
    const [currentIdx, setCurrentIdx] = useState(0)
    const [activeSlot, setActiveSlot] = useState<'A' | 'B'>('A')
    const [mounted, setMounted] = useState(false)
    const videoARef = useRef<HTMLVideoElement>(null)
    const videoBRef = useRef<HTMLVideoElement>(null)


    // Page-entry fade-in
    useEffect(() => { setMounted(true) }, [])

    // Fetch videos from admin-controlled API
    useEffect(() => {
        fetch('/api/admin/media?type=hero-video&page=works')
            .then(r => r.json())
            .then((data: HeroVideo[]) => {
                if (data.length > 0) setVideos(data)
            })
            .catch(() => { })
    }, [])

    // Start the first video once loaded
    useEffect(() => {
        if (videos.length === 0) return
        const videoA = videoARef.current
        if (!videoA) return

        videoA.src = videos[0].url
        videoA.load()
        videoA.play().catch(() => { })
        setActiveSlot('A')

        // No automatic crossfade scheduling; videos will start instantly
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [videos])

// Crossfade logic removed; manual navigation will handle video switching with opacity transition

    // Manual dot click
    const jumpToVideo = useCallback((idx: number) => {
        if (idx === currentIdx) return
        setCurrentIdx(idx)

        setActiveSlot(prev => {
            const nextSlot = prev === 'A' ? 'B' : 'A'
            const nextVideo = nextSlot === 'A' ? videoARef.current : videoBRef.current
            if (nextVideo) {
                nextVideo.src = videos[idx].url
                nextVideo.load()
                nextVideo.play().catch(() => { })
            }
            return nextSlot
        })

        // No timer scheduling on manual video jump
    }, [currentIdx, videos])

    return (
        <div style={{
            overflowX: 'hidden', width: '100%',
            opacity: mounted ? 1 : 0,
            transition: 'opacity 0.4s ease',
        }}>
            {/* 3D Particle Background */}
            <Scene3D />

            {/* ═══ FIXED VIDEO BACKGROUND — always rendered dark base + crossfading video slots ═══ */}
            <div style={{
                position: 'fixed',
                top: 0, left: 0,
                width: '100%', height: '100vh',
                zIndex: 0,
                background: '#0d0f14',
            }}>
                {/* Static poster shown until first video loads */}
                <div style={{
                    position: 'absolute', inset: 0,
                    backgroundImage: 'url(/images/works-bg.png)',
                    backgroundSize: 'cover', backgroundPosition: 'center',
                    opacity: videos.length === 0 ? 0.3 : 0,
                    transition: 'opacity 0.8s ease',
                }} />
                <video
                    ref={videoARef}
                    autoPlay muted playsInline
                    controlsList="nodownload"
                    onContextMenu={(e) => e.preventDefault()}
                    poster="/images/works-bg.png"
                    style={{
                        position: 'absolute',
                        inset: 0,
                        width: '100%',
                        height: '100%',
                        objectFit: 'cover',
                        opacity: videos.length > 0 && activeSlot === 'A' ? 1 : 0,
                        transition: 'opacity 1.2s ease-in-out',
                        zIndex: activeSlot === 'A' ? 1 : 0,
                    }}
                />
                <video
                    ref={videoBRef}
                    autoPlay muted playsInline
                    controlsList="nodownload"
                    onContextMenu={(e) => e.preventDefault()}
                    style={{
                        position: 'absolute',
                        inset: 0,
                        width: '100%',
                        height: '100%',
                        objectFit: 'cover',
                        opacity: videos.length > 0 && activeSlot === 'B' ? 1 : 0,
                        transition: 'opacity 1.2s ease-in-out',
                        zIndex: activeSlot === 'B' ? 1 : 0,
                    }}
                />
            </div>

            {/* ═══ SINGLE FIXED GRADIENT OVERLAY — covers the entire viewport over the video ═══ */}
            <div style={{
                position: 'fixed',
                top: 0, left: 0,
                width: '100%', height: '100vh',
                zIndex: 0,
                background: 'linear-gradient(180deg, rgba(13,15,20,0.25) 0%, rgba(13,15,20,0.1) 25%, rgba(13,15,20,0.2) 50%, rgba(13,15,20,0.5) 75%, rgba(13,15,20,0.8) 100%)',
                pointerEvents: 'none',
            }} />

            {/* ═══ HERO CONTENT — scrolls away as user scrolls ═══ */}
            <section style={{
                position: 'relative',
                height: '100vh',
                overflow: 'hidden',
                zIndex: 1,
            }}>
                {/* Content overlay — sits on top of the video */}
                <div style={{
                    position: 'absolute', inset: 0, zIndex: 1,
                    display: 'flex', flexDirection: 'column',
                    alignItems: 'center', justifyContent: 'center',
                    gap: 'var(--space-xl)',
                    paddingTop: '120px', paddingBottom: 'var(--space-3xl)',
                }}>

                    {/* Radial Glow */}
                    <div style={{
                        position: 'absolute', top: '15%', left: '50%', transform: 'translateX(-50%)',
                        width: '700px', height: '700px',
                        background: 'radial-gradient(circle, rgba(228,185,90,0.06), transparent 65%)',
                        pointerEvents: 'none',
                    }} />

                    {/* Decorative corner frames */}
                    <div style={{
                        position: 'absolute', top: '80px', left: '20px', width: '60px', height: '60px',
                        borderTop: '2px solid rgba(228,185,90,0.2)', borderLeft: '2px solid rgba(228,185,90,0.2)',
                        pointerEvents: 'none',
                    }} />
                    <div style={{
                        position: 'absolute', top: '80px', right: '20px', width: '60px', height: '60px',
                        borderTop: '2px solid rgba(228,185,90,0.2)', borderRight: '2px solid rgba(228,185,90,0.2)',
                        pointerEvents: 'none',
                    }} />

                    {/* Cinematic scan lines */}
                    <div style={{
                        position: 'absolute', top: '25%', left: 0, right: 0, height: '1px',
                        background: 'linear-gradient(90deg, transparent 5%, rgba(228,185,90,0.05) 30%, rgba(228,185,90,0.05) 70%, transparent 95%)',
                    }} />
                    <div style={{
                        position: 'absolute', top: '75%', left: 0, right: 0, height: '1px',
                        background: 'linear-gradient(90deg, transparent 5%, rgba(255,255,255,0.03) 30%, rgba(255,255,255,0.03) 70%, transparent 95%)',
                    }} />

                    {/* Title & Subtitle */}
                    <div style={{
                        position: 'relative', zIndex: 1,
                        textAlign: 'center',
                        maxWidth: 'min(700px, 100%)',
                        padding: '0 var(--space-md)',
                        display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'center',
                    }}>
                        <span className="text-label animate-fade-in-up" style={{
                            display: 'inline-flex', alignItems: 'center', gap: '6px',
                            marginBottom: 'var(--space-sm)',
                        }}>
                            <span style={{
                                width: '6px', height: '6px', borderRadius: '50%',
                                background: 'var(--accent-gold)',
                                animation: 'pulse-gold 2s infinite',
                            }} />
                            {t('label')}
                        </span>

                        <h1 className="animate-fade-in-up delay-1" style={{
                            fontSize: 'clamp(1.8rem, 4.5vw, 2.8rem)',
                            fontWeight: 800,
                            marginBottom: 'var(--space-sm)',
                            lineHeight: 1.15,
                        }}>
                            {t('title')}{' '}
                            <span style={{
                                fontFamily: 'var(--font-serif)',
                                fontStyle: 'italic',
                                background: 'linear-gradient(135deg, var(--accent-gold-light), var(--accent-gold))',
                                WebkitBackgroundClip: 'text',
                                WebkitTextFillColor: 'transparent',
                                backgroundClip: 'text',
                            }}>{t('titleAccent')}</span>
                        </h1>

                        {/* Compact stats pill */}
                        <div className="hero-stats-pill animate-fade-in-up delay-2" style={{
                            display: 'inline-flex',
                            gap: 'var(--space-xl)',
                            marginTop: 'var(--space-lg)',
                            padding: '0.6rem 1.5rem',
                            background: 'rgba(255,255,255,0.03)',
                            borderRadius: 'var(--radius-full)',
                            border: '1px solid var(--border-subtle)',
                            backdropFilter: 'blur(12px)',
                        }}>
                            <div>
                                <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 800, color: 'var(--accent-gold)' }}>{projects.length}</span>
                                <span style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)', textTransform: 'uppercase' as const, letterSpacing: '0.1em', marginLeft: '4px' }}>{t('all')}</span>
                            </div>
                            <div style={{ width: '1px', background: 'var(--border-subtle)' }} />
                            <div>
                                <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 800, color: 'var(--text-primary)' }}>{completedCount}</span>
                                <span style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)', textTransform: 'uppercase' as const, letterSpacing: '0.1em', marginLeft: '4px' }}>{t('completed')}</span>
                            </div>
                            <div style={{ width: '1px', background: 'var(--border-subtle)' }} />
                            <div>
                                <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 800, color: 'var(--accent-gold)' }}>{inProdCount}</span>
                                <span style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)', textTransform: 'uppercase' as const, letterSpacing: '0.1em', marginLeft: '4px' }}>{t('inProd')}</span>
                            </div>
                        </div>
                    </div>

                    {/* CTA + Video Dots */}
                    <div style={{
                        position: 'relative', zIndex: 1,
                        display: 'flex', flexDirection: 'column', alignItems: 'center',
                        gap: 'var(--space-md)',
                    }}>
                        <a href="#projects" className="btn btn-primary btn-lg animate-fade-in-up delay-3">
                            {t('viewDetails')}
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M12 5v14M5 12l7 7 7-7" />
                            </svg>
                        </a>

                        {videos.length > 1 && (
                            <div style={{ display: 'flex', justifyContent: 'center', gap: '6px' }}>
                                {videos.map((_, i) => (
                                    <button
                                        key={i}
                                        onClick={() => jumpToVideo(i)}
                                        style={{
                                            width: currentIdx === i ? '28px' : '6px',
                                            height: '6px',
                                            borderRadius: 'var(--radius-full)',
                                            border: 'none',
                                            background: currentIdx === i ? 'var(--accent-gold)' : 'rgba(255,255,255,0.25)',
                                            cursor: 'pointer',
                                            transition: 'all 0.3s ease',
                                            padding: 0,
                                        }}
                                        aria-label={`Play video ${i + 1}`}
                                    />
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </section>

            {/* ═══ PROJECTS GALLERY — scrolls over the video ═══ */}
            <section id="projects" style={{
                position: 'relative',
                zIndex: 2,
                marginTop: '-30px',
            }}>
                <div style={{
                    position: 'relative',
