'use client'

import { useState } from 'react'

// ─── SVG Sparkline ───
export function Sparkline({ data, color = 'var(--accent-gold)', height = 32, width = 80 }: { data: number[]; color?: string; height?: number; width?: number }) {
    if (!data.length || data.every(d => d === 0)) {
        return <div style={{ width, height, opacity: 0.2 }}><svg width={width} height={height}><line x1={0} y1={height / 2} x2={width} y2={height / 2} stroke={color} strokeWidth={1} strokeDasharray="3 3" /></svg></div>
    }
    const max = Math.max(...data, 1)
    const min = Math.min(...data)
    const range = max - min || 1
    const points = data.map((v, i) => {
        const x = (i / (data.length - 1)) * width
        const y = height - 4 - ((v - min) / range) * (height - 8)
        return `${x},${y}`
    }).join(' ')
    const fillPoints = `0,${height} ${points} ${width},${height}`
    return (
        <svg width={width} height={height} style={{ overflow: 'visible' }}>
            <defs>
                <linearGradient id={`sg-${color.replace(/[^a-z0-9]/gi, '')}`} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={color} stopOpacity={0.25} />
                    <stop offset="100%" stopColor={color} stopOpacity={0} />
                </linearGradient>
            </defs>
            <polygon points={fillPoints} fill={`url(#sg-${color.replace(/[^a-z0-9]/gi, '')})`} />
            <polyline points={points} fill="none" stroke={color} strokeWidth={1.5} strokeLinecap="round" strokeLinejoin="round" />
            <circle cx={(data.length - 1) / (data.length - 1) * width} cy={height - 4 - ((data[data.length - 1] - min) / range) * (height - 8)} r={2.5} fill={color} />
        </svg>
    )
}

// ─── Vitality Score Ring ───
export function VitalityRing({ score }: { score: number }) {
    const radius = 58
    const stroke = 8
    const circumference = 2 * Math.PI * radius
    const offset = circumference - (score / 100) * circumference
    const health = score >= 75 ? { label: 'Excellent', color: 'var(--color-success)' }
        : score >= 50 ? { label: 'Growing', color: 'var(--accent-gold)' }
            : score >= 25 ? { label: 'Building', color: 'var(--color-warning)' }
                : { label: 'Getting Started', color: 'var(--color-muted)' }

    return (
        <div style={{ position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width={148} height={148} style={{ transform: 'rotate(-90deg)' }}>
                <defs>
                    <linearGradient id="vitalGrad" x1="0" y1="0" x2="1" y2="1">
                        <stop offset="0%" stopColor="var(--accent-gold)" />
                        <stop offset="100%" stopColor="var(--accent-gold-dark)" />
                    </linearGradient>
                    <filter id="vitalGlow">
                        <feGaussianBlur stdDeviation="4" result="blur" />
                        <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
                    </filter>
                </defs>
                <circle cx={74} cy={74} r={radius} fill="none" stroke="rgba(255,255,255,0.04)" strokeWidth={stroke} />
                <circle cx={74} cy={74} r={radius} fill="none" stroke="url(#vitalGrad)" strokeWidth={stroke}
                    strokeDasharray={circumference} strokeDashoffset={offset}
                    strokeLinecap="round" filter="url(#vitalGlow)"
                    style={{ transition: 'stroke-dashoffset 1.5s cubic-bezier(0.4,0,0.2,1)' }} />
            </svg>
            <div style={{ position: 'absolute', textAlign: 'center' }}>
                <div style={{ fontSize: '2rem', fontWeight: 900, color: health.color, lineHeight: 1 }}>{score}</div>
                <div style={{ fontSize: '0.55rem', textTransform: 'uppercase', letterSpacing: '0.12em', color: 'var(--text-tertiary)', marginTop: '2px', fontWeight: 600 }}>{health.label}</div>
            </div>
        </div>
    )
}

// ─── Donut Chart ───
export function DonutChart({ segments }: { segments: { label: string; value: number; color: string }[] }) {
    const total = segments.reduce((s, seg) => s + seg.value, 0) || 1
    const size = 120
    const radius = 44
    const strokeWidth = 14
    const circumference = 2 * Math.PI * radius
    let accum = 0

    return (
        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-lg)' }}>
            <svg width={size} height={size} style={{ transform: 'rotate(-90deg)', flexShrink: 0 }}>
                <circle cx={size / 2} cy={size / 2} r={radius} fill="none" stroke="rgba(255,255,255,0.03)" strokeWidth={strokeWidth} />
                {segments.map((seg, i) => {
                    const pct = seg.value / total
                    const dash = pct * circumference
                    const gap = circumference - dash
                    const off = -accum * circumference
                    accum += pct
                    return <circle key={i} cx={size / 2} cy={size / 2} r={radius} fill="none"
                        stroke={seg.color} strokeWidth={strokeWidth} strokeLinecap="round"
                        strokeDasharray={`${dash - 2} ${gap + 2}`}
                        strokeDashoffset={off}
                        style={{ transition: 'all 0.8s ease' }} />
                })}
            </svg>
            <div style={{ flex: 1 }}>
                {segments.map((seg, i) => (
                    <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '6px' }}>
                        <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: seg.color, flexShrink: 0 }} />
                        <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', flex: 1, textTransform: 'capitalize' }}>{seg.label}</span>
                        <span style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-primary)' }}>{Math.round((seg.value / total) * 100)}%</span>
                    </div>
                ))}
            </div>
        </div>
    )
}

// ─── Area Chart ───
export function AreaChart({ data, labels, height = 180 }: { data: number[]; labels: string[]; height?: number }) {
    const [hoveredIdx, setHoveredIdx] = useState<number | null>(null)
    const max = Math.max(...data, 1)
    const min = Math.min(...data, 0)
    const range = max - min || 1
    const width = 100
    const pad = 4

    const pts = data.map((v, i) => ({
        x: pad + (i / (data.length - 1)) * (width - pad * 2),
        y: pad + (1 - (v - min) / range) * (100 - pad * 2),
        value: v,
    }))

    // Build smooth cubic bezier path
    function smoothPath(points: { x: number; y: number }[]) {
        if (points.length < 2) return `M${points[0].x},${points[0].y}`
        let d = `M${points[0].x},${points[0].y}`
        for (let i = 1; i < points.length; i++) {
            const cp1x = points[i - 1].x + (points[i].x - points[i - 1].x) / 3
            const cp1y = points[i - 1].y
            const cp2x = points[i].x - (points[i].x - points[i - 1].x) / 3
            const cp2y = points[i].y
            d += ` C${cp1x},${cp1y} ${cp2x},${cp2y} ${points[i].x},${points[i].y}`
        }
        return d
    }
    const linePath = smoothPath(pts)
    const fillPath = `${linePath} L${pts[pts.length - 1].x},${100 - pad} L${pts[0].x},${100 - pad} Z`

    const avg = Math.round(data.reduce((a, b) => a + b, 0) / data.length)
    const peak = Math.max(...data)
    const gradId = `areaG${Math.random().toString(36).slice(2, 7)}`

    return (
        <div style={{
            background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)',
            border: '1px solid var(--border-subtle)', padding: 'var(--space-lg)',
            position: 'relative',
        }}>
            {/* Summary stats */}
            <div style={{ display: 'flex', gap: '16px', marginBottom: '8px', justifyContent: 'flex-end' }}>
                <span style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)' }}>Peak: <strong style={{ color: 'var(--accent-gold)' }}>{peak}</strong></span>
                <span style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)' }}>Avg: <strong style={{ color: 'var(--text-secondary)' }}>{avg}</strong></span>
            </div>
            <svg viewBox={`0 0 ${width} 100`} style={{ width: '100%', height, display: 'block' }}
                onMouseLeave={() => setHoveredIdx(null)}>
                <defs>
                    <linearGradient id={gradId} x1="0" y1="0" x2="0" y2="1">
                        <stop offset="0%" stopColor="var(--accent-gold)" stopOpacity={0.35} />
                        <stop offset="60%" stopColor="var(--accent-gold)" stopOpacity={0.08} />
                        <stop offset="100%" stopColor="var(--accent-gold)" stopOpacity={0.01} />
                    </linearGradient>
                    <filter id="lineGlow">
                        <feGaussianBlur stdDeviation="0.8" result="blur" />
                        <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
                    </filter>
                </defs>
                {/* Grid lines */}
                {[0.25, 0.5, 0.75].map(pct => (
                    <line key={pct} x1={pad} x2={width - pad}
                        y1={pad + (1 - pct) * (100 - pad * 2)} y2={pad + (1 - pct) * (100 - pad * 2)}
                        stroke="rgba(255,255,255,0.04)" strokeWidth={0.3} strokeDasharray="2 2" />
                ))}
                <path d={fillPath} fill={`url(#${gradId})`} />
                <path d={linePath} fill="none" stroke="var(--accent-gold)" strokeWidth={1.5}
                    strokeLinecap="round" strokeLinejoin="round" filter="url(#lineGlow)" />
                {/* Hit areas and dots */}
                {pts.map((p, i) => (
                    <g key={i} onMouseEnter={() => setHoveredIdx(i)}>
                        <rect x={p.x - (width / data.length) / 2} y={0} width={width / data.length} height={100} fill="transparent" style={{ cursor: 'pointer' }} />
                        {hoveredIdx === i && (
                            <>
                                <line x1={p.x} x2={p.x} y1={pad} y2={100 - pad} stroke="rgba(212,168,83,0.25)" strokeWidth={0.5} strokeDasharray="2 2" />
                                <circle cx={p.x} cy={p.y} r={2.5} fill="var(--accent-gold)" stroke="#0a0a0a" strokeWidth={1} />
                            </>
                        )}
                    </g>
                ))}
            </svg>
            {hoveredIdx !== null && (
                <div style={{
                    position: 'absolute',
                    left: `${pad + (hoveredIdx / (data.length - 1)) * (100 - pad * 2)}%`,
                    top: '28px',
                    transform: 'translateX(-50%)',
                    background: 'rgba(10,10,10,0.96)', border: '1px solid var(--accent-gold)',
                    borderRadius: '6px', padding: '4px 10px',
                    fontSize: '0.7rem', fontWeight: 700, color: 'var(--accent-gold)',
                    whiteSpace: 'nowrap', pointerEvents: 'none', zIndex: 5,
                    boxShadow: '0 4px 12px rgba(0,0,0,0.4)',
                }}>
                    {data[hoveredIdx]} views
                    <span style={{ color: 'var(--text-tertiary)', fontWeight: 400, marginLeft: '4px' }}>· {labels[hoveredIdx]}</span>
                </div>
            )}
            <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '6px' }}>
                {labels.map((label, i) => (
                    <span key={i} style={{
                        fontSize: '0.58rem',
                        color: hoveredIdx === i ? 'var(--accent-gold)' : 'var(--text-tertiary)',
                        flex: 1, textAlign: 'center',
                        fontWeight: hoveredIdx === i ? 700 : 400,
                        transition: 'all 0.15s',
                    }}>{label}</span>
                ))}
            </div>
        </div>
    )
}

// ─── Hourly Heatmap ───
export function HourlyHeatmap({ data }: { data: number[] }) {
    const [hovered, setHovered] = useState<number | null>(null)
    const max = Math.max(...data, 1)
    const total = data.reduce((a, b) => a + b, 0)
    const avg = total / 24
    const peakHour = data.indexOf(max)
    const quietHour = data.indexOf(Math.min(...data))

    function getColor(v: number) {
        const t = v / max
        if (t === 0) return 'rgba(255,255,255,0.025)'
        if (t < 0.3) return `rgba(99,102,241,${0.1 + t * 0.5})`   // indigo — low traffic
        if (t < 0.6) return `rgba(212,168,83,${0.2 + t * 0.6})`   // gold — medium
        return `rgba(251,146,60,${0.4 + t * 0.55})`                 // amber/orange — peak
    }

    function formatHour(h: number) {
        if (h === 0) return '12am'
        if (h === 12) return '12pm'
        return h < 12 ? `${h}am` : `${h - 12}pm`
    }

    return (
        <div style={{ position: 'relative' }}>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(24, 1fr)', gap: '2px', marginBottom: '4px' }}>
                {data.map((v, i) => {
                    const isPeak = i === peakHour && v > 0
                    return (
                        <div
                            key={i}
                            onMouseEnter={() => setHovered(i)}
                            onMouseLeave={() => setHovered(null)}
                            style={{
                                height: '36px', borderRadius: '4px',
                                background: getColor(v),
                                border: isPeak
                                    ? '1px solid rgba(251,146,60,0.6)'
                                    : hovered === i
                                    ? '1px solid rgba(212,168,83,0.5)'
                                    : '1px solid transparent',
                                transition: 'all 0.2s',
                                cursor: 'default',
                                position: 'relative',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                            }}
                        >
                            {v > avg * 1.5 && (
                                <span style={{
                                    fontSize: '0.45rem', fontWeight: 800,
                                    color: v / max > 0.6 ? '#fff' : 'var(--accent-gold)',
                                }}>{v}</span>
                            )}
                        </div>
                    )
                })}
            </div>
            {/* Tooltip */}
            {hovered !== null && (
                <div style={{
                    position: 'absolute', top: '-32px',
                    left: `${(hovered / 24) * 100}%`,
                    transform: 'translateX(-50%)',
                    background: 'rgba(10,10,10,0.96)', border: '1px solid var(--accent-gold)',
                    borderRadius: '6px', padding: '3px 8px',
                    fontSize: '0.65rem', fontWeight: 700, color: 'var(--accent-gold)',
                    whiteSpace: 'nowrap', pointerEvents: 'none', zIndex: 10,
                    boxShadow: '0 4px 12px rgba(0,0,0,0.5)',
                }}>
                    {formatHour(hovered)} · {data[hovered]} views
                </div>
            )}
            {/* Hour axis */}
            <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '3px' }}>
                {[0, 4, 8, 12, 16, 20, 23].map(h => (
                    <span key={h} style={{ fontSize: '0.48rem', color: 'var(--text-tertiary)' }}>{formatHour(h)}</span>
                ))}
            </div>
            {/* Peak / quiet summary */}
            <div style={{ display: 'flex', gap: '12px', marginTop: '8px', flexWrap: 'wrap' }}>
                <span style={{ fontSize: '0.58rem', color: 'var(--text-tertiary)' }}>
                    🔥 Peak: <strong style={{ color: '#fb923c' }}>{formatHour(peakHour)}</strong> ({max} views)
                </span>
                <span style={{ fontSize: '0.58rem', color: 'var(--text-tertiary)' }}>
                    🌙 Quiet: <strong style={{ color: '#6366f1' }}>{formatHour(quietHour)}</strong>
                </span>
                <span style={{ fontSize: '0.58rem', color: 'var(--text-tertiary)' }}>
                    Avg: <strong style={{ color: 'var(--text-secondary)' }}>{Math.round(avg)}/hr</strong>
                </span>
            </div>
        </div>
    )
}

// ─── Trend Arrow ───
export function TrendArrow({ current, previous }: { current: number; previous: number }) {
    if (previous === 0 && current === 0) return null
    const pct = previous > 0 ? Math.round(((current - previous) / previous) * 100) : current > 0 ? 100 : 0
    const isUp = pct >= 0
    return (
        <span style={{
            fontSize: '0.65rem', fontWeight: 700,
            color: isUp ? 'var(--color-success)' : 'var(--color-error)',
            display: 'inline-flex', alignItems: 'center', gap: '2px',
        }}>
            {isUp ? '↑' : '↓'} {Math.abs(pct)}%
        </span>
    )
}

// ─── Activity Feed Item ───
export function ActivityItem({ item }: { item: { id: string; path: string; device: string | null; createdAt: string; referrer: string | null } }) {
    const deviceIcon = item.device === 'mobile' ? '📱' : item.device === 'tablet' ? '📋' : '💻'
    const ago = getRelativeTime(item.createdAt)
    return (
        <div style={{
            display: 'flex', alignItems: 'center', gap: '10px',
            padding: '6px 0',
            borderBottom: '1px solid rgba(255,255,255,0.03)',
            fontSize: '0.75rem',
        }}>
            <span style={{ fontSize: '0.65rem', width: '18px', textAlign: 'center' }}>{deviceIcon}</span>
            <span style={{ flex: 1, color: 'var(--text-secondary)', fontWeight: 500 }}>{item.path}</span>
            <span style={{ fontSize: '0.62rem', color: 'var(--text-tertiary)', whiteSpace: 'nowrap' }}>{ago}</span>
        </div>
    )
}

// ─── Helper ───
export function getRelativeTime(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const seconds = Math.floor(diff / 1000)
    if (seconds < 60) return `${seconds}s ago`
    const minutes = Math.floor(seconds / 60)
    if (minutes < 60) return `${minutes}m ago`
    const hours = Math.floor(minutes / 60)
    if (hours < 24) return `${hours}h ago`
    return `${Math.floor(hours / 24)}d ago`
}

'use client'

import { useState, useEffect, useRef } from 'react'

// Type shims for Web Speech API (not in default TS DOM types)
/* eslint-disable @typescript-eslint/no-explicit-any */
type SR = any   // SpeechRecognition instance
type SREvent = any  // SpeechRecognitionEvent  
type SRError = any  // SpeechRecognitionErrorEvent

interface Props {
    onClose: () => void
    insightContext: string
}

type Phase = 'idle' | 'listening' | 'thinking' | 'speaking'

export default function VoiceConversation({ onClose, insightContext }: Props) {
    const [phase, setPhase] = useState<Phase>('idle')
    const [transcript, setTranscript] = useState('')
    const [interimTranscript, setInterimTranscript] = useState('')
    const [messages, setMessages] = useState<{ role: 'user' | 'ai'; text: string }[]>([{
        role: 'ai',
        text: 'Hey! I\'m your AIM Studio analytics advisor. I can see your platform data — ask me anything about your traffic, casting pipeline, or how to grow your audience.'
    }])
    const [volume, setVolume] = useState(0)
    const [ttsProvider, setTtsProvider] = useState<'elevenlabs' | 'openai' | 'browser'>('browser')
    const [voices, setVoices] = useState<{ voiceId: string; name: string }[]>([])
    const [selectedVoiceId, _setSelectedVoiceId] = useState<string>(() => {
        try { return localStorage.getItem('aim_tts_voice') ?? '' } catch { return '' }
    })
    const selectedVoiceIdRef = useRef(selectedVoiceId)
    const setSelectedVoiceId = (id: string) => {
        selectedVoiceIdRef.current = id
        _setSelectedVoiceId(id)
    }

    const setPhaseSync = (p: Phase) => {
        phaseRef.current = p
        setPhase(p)
    }

    const recognitionRef = useRef<SR | null>(null)
    const audioContextRef = useRef<AudioContext | null>(null)
    const analyserRef = useRef<AnalyserNode | null>(null)
    const micStreamRef = useRef<MediaStream | null>(null)
    const animFrameRef = useRef<number>(0)
    const currentAudioRef = useRef<HTMLAudioElement | null>(null)
    const messagesEndRef = useRef<HTMLDivElement>(null)
    const autoListenTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
    const transcriptRef = useRef('')
    const phaseRef = useRef<Phase>('idle')
    const bargeInCountRef = useRef(0)
    const speakResolveRef = useRef<(() => void) | null>(null)
    const bargedInRef = useRef(false)
    const bargeInListeningRef = useRef(false)
    const idleWatchdogRef = useRef<ReturnType<typeof setTimeout> | null>(null)

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
    }, [messages])

    useEffect(() => {
        return () => { stopEverything() }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [])

    useEffect(() => {
        let cancelled = false

        const init = async () => {
            try {
                const r = await fetch('/api/admin/analytics/voices')
                const d = await r.json()
                if (!cancelled && d.voices?.length) {
                    setVoices(d.voices)
                    const saved = localStorage.getItem('aim_tts_voice')
                    const match = d.voices.find((v: { voiceId: string }) => v.voiceId === saved)
                    setSelectedVoiceId(match?.voiceId ?? d.voices[0].voiceId)
                }
            } catch { /* no voices available */ }

            await new Promise(r => setTimeout(r, 100))

            if (cancelled) return
            const greeting = messages[0]?.text ?? ''
            if (greeting) {
                if (window.speechSynthesis) window.speechSynthesis.cancel()
                let listeningStarted = false
                const beginListening = () => {
                    if (listeningStarted || cancelled) return
                    listeningStarted = true
                    currentAudioRef.current?.pause()
                    currentAudioRef.current = null
                    if (window.speechSynthesis) window.speechSynthesis.cancel()
                    speakResolveRef.current?.()
                    speakResolveRef.current = null
                    setPhaseSync('idle')
                    startListening()
                }
                speakResponse(greeting).then(beginListening)
                setTimeout(beginListening, 3000)
            }
        }

        init()
        return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [])

    const stopEverything = () => {
        recognitionRef.current?.stop()
        recognitionRef.current?.abort()
        currentAudioRef.current?.pause()
        micStreamRef.current?.getTracks().forEach(t => t.stop())
        audioContextRef.current?.close()
        cancelAnimationFrame(animFrameRef.current)
        if (autoListenTimeoutRef.current) clearTimeout(autoListenTimeoutRef.current)
        if (idleWatchdogRef.current) clearTimeout(idleWatchdogRef.current)
        setVolume(0)
    }

    const resetIdleWatchdog = () => {
        if (idleWatchdogRef.current) clearTimeout(idleWatchdogRef.current)
        idleWatchdogRef.current = setTimeout(() => {
            if (phaseRef.current === 'idle') startListening()
        }, 4000)
    }

    const startVolumeMeter = async () => {
        stopVolumeMeter()
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
            micStreamRef.current = stream
            const ctx = new AudioContext()
            audioContextRef.current = ctx
            const analyser = ctx.createAnalyser()
            analyserRef.current = analyser
            analyser.fftSize = 256
            ctx.createMediaStreamSource(stream).connect(analyser)
            const data = new Uint8Array(analyser.frequencyBinCount)
            const tick = () => {
                analyser.getByteTimeDomainData(data)
                let sum = 0
                for (const v of data) sum += Math.abs(v - 128)
                const vol = Math.min(sum / data.length / 30, 1)
                setVolume(vol)

                if (phaseRef.current === 'speaking' && vol > 0.35) {
                    bargeInCountRef.current += 1
                    if (bargeInCountRef.current >= 2) {
                        bargeInCountRef.current = 0
                        bargedInRef.current = true
                        bargeInListeningRef.current = true
                        currentAudioRef.current?.pause()
                        currentAudioRef.current = null
                        if (window.speechSynthesis) window.speechSynthesis.cancel()
                        speakResolveRef.current?.()
                        speakResolveRef.current = null
                        setPhaseSync('idle')
                        autoListenTimeoutRef.current = setTimeout(() => startListening(), 150)
                        resetIdleWatchdog()
                        return
                    }
                } else {
                    bargeInCountRef.current = 0
                }

                animFrameRef.current = requestAnimationFrame(tick)
            }
            tick()
        } catch { /* mic denied */ }
    }

    const stopVolumeMeter = () => {
        cancelAnimationFrame(animFrameRef.current)
        micStreamRef.current?.getTracks().forEach(t => t.stop())
        audioContextRef.current?.close().catch(() => {})
        micStreamRef.current = null
        audioContextRef.current = null
        setVolume(0)
    }

    const speakResponse = async (text: string): Promise<void> => {
        return new Promise(async (resolve) => {
            if (currentAudioRef.current) {
                currentAudioRef.current.pause()
                currentAudioRef.current = null
            }
            if (window.speechSynthesis) window.speechSynthesis.cancel()
            if (speakResolveRef.current) {
                speakResolveRef.current()
                speakResolveRef.current = null
            }

            speakResolveRef.current = resolve
            setPhaseSync('speaking')
            bargeInCountRef.current = 0
            startVolumeMeter()

            const safetyTimer = setTimeout(() => {
                if (speakResolveRef.current === resolve) {
                    currentAudioRef.current?.pause()
                    currentAudioRef.current = null
                    if (window.speechSynthesis) window.speechSynthesis.cancel()
                    speakResolveRef.current?.()
                    speakResolveRef.current = null
                }
            }, 15000)

            try {
                const res = await fetch('/api/admin/analytics/tts', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ text, voiceId: selectedVoiceIdRef.current || undefined }),
                })

                const contentType = res.headers.get('content-type') || ''
                if (contentType.includes('audio')) {
                    const provider = res.headers.get('x-tts-provider') || 'openai'
                    setTtsProvider(provider === 'elevenlabs' ? 'elevenlabs' : 'openai')
                    const blob = await res.blob()
                    const url = URL.createObjectURL(blob)
                    const audio = new Audio(url)
                    currentAudioRef.current = audio
                    audio.onended = () => { clearTimeout(safetyTimer); URL.revokeObjectURL(url); speakResolveRef.current?.(); speakResolveRef.current = null }
                    audio.onerror = () => { clearTimeout(safetyTimer); speakResolveRef.current?.(); speakResolveRef.current = null }
                    audio.play().catch(() => { clearTimeout(safetyTimer); speakResolveRef.current?.(); speakResolveRef.current = null })
                    return
                }
            } catch { /* fall through to browser TTS */ }

            setTtsProvider('browser')
            if (typeof window !== 'undefined' && window.speechSynthesis) {
                window.speechSynthesis.cancel()
                const utt = new SpeechSynthesisUtterance(text)
                utt.rate = 0.95; utt.pitch = 1.05
                const voices = window.speechSynthesis.getVoices()
                const best = voices.find(v =>
                    v.name.includes('Google') && v.lang.startsWith('en')
                ) || voices.find(v => v.lang === 'en-US') || voices[0]
                if (best) utt.voice = best
                utt.onend = () => { clearTimeout(safetyTimer); speakResolveRef.current?.(); speakResolveRef.current = null }
                utt.onerror = () => { clearTimeout(safetyTimer); speakResolveRef.current?.(); speakResolveRef.current = null }
                window.speechSynthesis.speak(utt)
            } else {
                speakResolveRef.current?.()
                speakResolveRef.current = null
            }
        })
    }

    const sendToAI = async (userText: string) => {
        setPhaseSync('thinking')
        const history = [...messages, { role: 'user' as const, text: userText }]
        setMessages(history)

        try {
            const res = await fetch('/api/admin/analytics/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ question: userText, context: insightContext }),
            })
            const result = await res.json()
            const answer = result.answer || 'Sorry, I couldn\'t get a response. Try again?'
            setMessages(prev => [...prev, { role: 'ai', text: answer }])
            await speakResponse(answer)
        } catch {
            const errMsg = 'I hit a snag. Can you try asking again?'
            setMessages(prev => [...prev, { role: 'ai', text: errMsg }])
            await speakResponse(errMsg)
        }

        if (!bargedInRef.current) {
            setPhaseSync('idle')
            autoListenTimeoutRef.current = setTimeout(() => startListening(), 600)
            resetIdleWatchdog()
        }
        bargedInRef.current = false
    }

    const startListening = () => {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const w = window as any
        const SR = w.SpeechRecognition || w.webkitSpeechRecognition
        if (!SR) { alert('Voice recognition not supported in this browser. Use Google Chrome.'); return }

        currentAudioRef.current?.pause()
        if (typeof window !== 'undefined' && window.speechSynthesis) window.speechSynthesis.cancel()

        const recognition = new SR()
        recognitionRef.current = recognition
        recognition.continuous = false
        recognition.interimResults = true
        recognition.lang = 'en-US'
        recognition.maxAlternatives = 1

        setPhaseSync('listening')
        transcriptRef.current = ''
        setTranscript('')
        setInterimTranscript('')
        startVolumeMeter()

        recognition.onresult = (e: SREvent) => {
            let interim = ''
            let final = ''
            for (let i = e.resultIndex; i < e.results.length; i++) {
                const t = e.results[i][0].transcript
                if (e.results[i].isFinal) final += t
                else interim += t
            }
            if (final) {
                transcriptRef.current += final
                setTranscript(transcriptRef.current)
            }
            setInterimTranscript(interim)
        }

        recognition.onend = () => {
            stopVolumeMeter()
            setInterimTranscript('')
            const finalText = transcriptRef.current.trim()
            transcriptRef.current = ''
            setTranscript('')
            const wasBargeIn = bargeInListeningRef.current
            bargeInListeningRef.current = false

            if (finalText.length > 2) {
                sendToAI(finalText)
            } else if (wasBargeIn) {
                setPhaseSync('idle')
                autoListenTimeoutRef.current = setTimeout(() => startListening(), 300)
            } else {
                setPhaseSync('idle')
            }
        }

        recognition.onerror = (e: SRError) => {
            stopVolumeMeter()
            bargeInListeningRef.current = false
            if (e.error === 'no-speech') {
                autoListenTimeoutRef.current = setTimeout(() => startListening(), 300)
            } else if (e.error !== 'aborted') {
                setPhaseSync('idle')
            }
        }

        recognition.start()
    }

    const stopListening = () => {
        recognitionRef.current?.stop()
    }

    const toggleListening = () => {
        if (autoListenTimeoutRef.current) clearTimeout(autoListenTimeoutRef.current)
        if (phase === 'listening') { stopListening(); return }
        if (phase === 'speaking') {
            currentAudioRef.current?.pause()
            window.speechSynthesis?.cancel()
        }
        startListening()
    }

    const selectedVoiceName = voices.find(v => v.voiceId === selectedVoiceId)?.name ?? 'ElevenLabs'
    const ttsLabel = ttsProvider === 'elevenlabs' ? `🎙️ ${selectedVoiceName}` : ttsProvider === 'openai' ? '🔊 OpenAI (nova)' : '🔊 Speaking…'
    const phaseColors = {
        idle: { orb: '#1a1a2e', ring: 'rgba(212,168,83,0.3)', label: 'Tap to speak', pulse: false },
        listening: { orb: '#0f2027', ring: '#d4a853', label: 'Listening…', pulse: true },
        thinking: { orb: '#1a0f2e', ring: '#a855f7', label: 'Thinking…', pulse: true },
        speaking: { orb: '#0a1f1a', ring: '#22c55e', label: ttsLabel, pulse: true },
    }
    const pc = phaseColors[phase]
    const orbScale = 1 + volume * 0.4

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 9999,
            background: 'rgba(0,0,0,0.92)',
            backdropFilter: 'blur(20px)',
            display: 'flex', flexDirection: 'column', alignItems: 'center',
        }}>
            {/* Header */}
            <div style={{
                width: '100%', display: 'flex', alignItems: 'center', padding: '20px 24px',
                borderBottom: '1px solid rgba(255,255,255,0.06)',
            }}>
                <div style={{ flex: 1 }}>
                    <div style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--accent-gold)' }}>AIM Studio Analytics Agent</div>
                    <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)' }}>Voice conversation · {ttsProvider === 'elevenlabs' ? `🎙️ ElevenLabs · ${selectedVoiceName}` : ttsProvider === 'openai' ? '🟢 OpenAI TTS' : '🌎 Browser voice'}</div>
                </div>

                {voices.length > 0 && (
                    <select
                        value={selectedVoiceId}
                        onChange={e => {
                            setSelectedVoiceId(e.target.value)
                            try { localStorage.setItem('aim_tts_voice', e.target.value) } catch {}
                        }}
                        style={{
                            background: 'rgba(255,255,255,0.05)',
                            border: '1px solid rgba(255,255,255,0.1)',
                            color: 'var(--text-secondary)',
                            padding: '5px 10px',
                            borderRadius: 'var(--radius-md)',
                            fontSize: '0.75rem',
                            cursor: 'pointer',
                            marginRight: '10px',
                            maxWidth: '160px',
                        }}
                    >
                        {voices.map(v => (
                            <option key={v.voiceId} value={v.voiceId}>{v.name}</option>
                        ))}
                    </select>
                )}

                <button onClick={() => { stopEverything(); onClose() }} style={{
                    background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)',
                    color: 'var(--text-secondary)', padding: '6px 14px', borderRadius: 'var(--radius-md)',
                    cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600,
                }}>✕ End Call</button>
            </div>

            {/* Main area */}
            <div style={{ flex: 1, display: 'flex', width: '100%', maxWidth: '900px', overflow: 'hidden', padding: '24px', gap: '24px' }}>

                {/* Left: Orb + mic */}
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', width: '280px', gap: '28px', flexShrink: 0 }}>

                    {/* Animated orb */}
                    <div
                        onClick={toggleListening}
                        style={{
                            position: 'relative',
                            width: '180px', height: '180px',
                            cursor: 'pointer',
                            userSelect: 'none',
                        }}
                    >
                        {pc.pulse && [
                            { size: 220, delay: '0s', opacity: 0.15 },
                            { size: 250, delay: '0.4s', opacity: 0.09 },
                            { size: 280, delay: '0.8s', opacity: 0.05 },
                        ].map((ring, i) => (
                            <div key={i} style={{
                                position: 'absolute',
                                left: `${(180 - ring.size) / 2}px`,
                                top: `${(180 - ring.size) / 2}px`,
                                width: `${ring.size}px`,
                                height: `${ring.size}px`,
                                borderRadius: '50%',
                                border: `1.5px solid ${pc.ring}`,
                                opacity: ring.opacity,
                                animation: `voicePulse 2s ease-out ${ring.delay} infinite`,
                            }} />
                        ))}

                        <div style={{
                            position: 'absolute', inset: 0,
                            borderRadius: '50%',
                            background: `radial-gradient(circle at 38% 38%, ${pc.ring}30, ${pc.orb} 70%)`,
                            border: `2px solid ${pc.ring}`,
                            boxShadow: `0 0 40px ${pc.ring}30, inset 0 0 40px rgba(0,0,0,0.5)`,
                            transform: `scale(${orbScale})`,
                            transition: 'transform 0.05s, background 0.5s, border-color 0.5s, box-shadow 0.5s',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            fontSize: '3rem',
                        }}>
                            {phase === 'thinking' ? '✦' : phase === 'speaking' ? '🔊' : '🎙'}
                        </div>
                    </div>

                    <div style={{ textAlign: 'center' }}>
                        <div style={{
                            fontSize: '0.9rem', fontWeight: 700,
                            color: pc.ring, letterSpacing: '0.02em',
                            transition: 'color 0.4s',
                        }}>{pc.label}</div>
                        {(transcript || interimTranscript) && (
                            <div style={{
                                marginTop: '10px', fontSize: '0.75rem',
                                color: 'var(--text-secondary)', lineHeight: 1.5,
                                maxWidth: '240px', textAlign: 'center',
                            }}>
                                {transcript}
                                <span style={{ color: 'var(--text-tertiary)', fontStyle: 'italic' }}>{interimTranscript}</span>
                            </div>
                        )}
                    </div>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '3px', height: '32px' }}>
                        {Array.from({ length: 12 }).map((_, i) => {
                            const h = phase === 'listening'
                                ? Math.max(4, volume * 32 * (0.5 + 0.5 * Math.sin(Date.now() / 80 + i)))
                                : phase === 'speaking' ? Math.max(4, 8 + Math.sin(Date.now() / 100 + i * 0.8) * 8) : 4
                            return (
                                <div key={i} style={{
                                    width: '3px', height: `${h}px`, borderRadius: '2px',
                                    background: pc.ring,
                                    opacity: phase === 'idle' ? 0.2 : 0.7,
                                    transition: 'height 0.05s, background 0.4s',
                                }} />
                            )
                        })}
                    </div>

                    <div style={{ fontSize: '0.6rem', color: 'var(--text-tertiary)', textAlign: 'center', lineHeight: 1.5 }}>
