                            }}>
                                <div>
                                    <div style={{ fontSize: '0.78rem', fontWeight: 600 }}>{n.label}</div>
                                    <div style={{ fontSize: '0.65rem', color: 'var(--text-tertiary)' }}>{n.desc}</div>
                                </div>
                                <button onClick={() => toggleNotif(n.key, n.checked, n.setter)} style={{
                                    width: '38px', height: '20px', borderRadius: '10px', border: 'none',
                                    background: n.checked ? 'var(--accent-gold)' : 'rgba(255,255,255,0.1)',
                                    position: 'relative', cursor: 'pointer', transition: 'background 0.3s', flexShrink: 0,
                                }}>
                                    <div style={{
                                        width: '16px', height: '16px', borderRadius: '50%',
                                        background: '#fff', position: 'absolute', top: '2px',
                                        left: n.checked ? '20px' : '2px',
                                        transition: 'left 0.3s ease',
                                        boxShadow: '0 1px 3px rgba(0,0,0,0.3)',
                                    }} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            </ScrollReveal3D>
        </div>
    )
}

import React from 'react';
import Link from 'next/link';
import { useTranslations } from 'next-intl';

export type SearchResult = {
  id: string;
  type: 'project' | 'castingCall' | 'scriptCall' | 'sponsor';
  title: string;
  slug?: string;
  imageUrl?: string;
};

export const ResultItem: React.FC<{ result: SearchResult }> = ({ result }) => {
  const t = useTranslations('search');
  const getLink = () => {
    switch (result.type) {
      case 'project':
        return `/projects/${result.slug ?? result.id}`;
      case 'castingCall':
        return `/casting/${result.id}`;
      case 'scriptCall':
        return `/scripts/${result.id}`;
      case 'sponsor':
        return `/sponsors/${result.id}`;
      default:
        return '#';
    }
  };

  return (
    <Link href={getLink()} className="result-item block p-3 rounded-lg hover:bg-white/10 transition-colors">
      <div className="flex items-center gap-3">
        {result.imageUrl && (
          <img src={result.imageUrl} alt={result.title} className="w-10 h-10 rounded object-cover" />
        )}
        <div className="flex flex-col">
          <span className="font-medium text-white">{result.title}</span>
          <span className="text-sm text-gray-400 capitalize">{t(`type.${result.type}`) ?? result.type}</span>
        </div>
      </div>
    </Link>
  );
};

'use client';

import React, { createContext, useContext, useState, useCallback, useRef } from 'react';
import { useRouter } from 'next/navigation';

interface SearchResult {
  id: string;
  type: 'project' | 'castingCall' | 'scriptCall' | 'sponsor';
  title: string;
  // add other fields as needed
}

interface SearchContextProps {
  query: string;
  setQuery: (q: string) => void;
  results: SearchResult[];
  loading: boolean;
  search: (q: string) => void;
}

const SearchContext = createContext<SearchContextProps | undefined>(undefined);

export const SearchProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const debounceTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const fetchResults = async (q: string) => {
    if (!q) {
      setResults([]);
      setLoading(false);
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`/api/search?query=${encodeURIComponent(q)}`);
      const data = await res.json();
      setResults(data.results || []);
      // Send analytics for search event
      try {
        await fetch('/api/analytics/track', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'search',
            query: q,
            resultsCount: (data.results || []).length,
          }),
        });
      } catch (analyticsErr) {
        console.warn('Analytics tracking failed', analyticsErr);
      }
    } catch (err) {
      console.error('Search error', err);
      setResults([]);
    } finally {
      setLoading(false);
    }
  };

  // Inline debounce to avoid lodash dependency issues during build
  const debouncedFetch = useCallback((q: string) => {
    if (debounceTimer.current) clearTimeout(debounceTimer.current);
    debounceTimer.current = setTimeout(() => fetchResults(q), 300);
  }, []);

  const search = (q: string) => {
    setQuery(q);
    debouncedFetch(q);
  };

  return (
    <SearchContext.Provider value={{ query, setQuery, results, loading, search }}>
      {children}
    </SearchContext.Provider>
  );
};

export const useSearch = () => {
  const ctx = useContext(SearchContext);
  if (!ctx) {
    throw new Error('useSearch must be used within SearchProvider');
  }
  return ctx;
};

