        if (!response.ok) {
            const err = await response.text()
            throw new Error(`Graph test mail send failed: ${response.status} ${err}`)
        }
}

/** Strip HTML tags for plain-text fallback */
function stripHtml(html: string): string {
    return html
        .replace(/<br\s*\/?>/gi, '\n')
        .replace(/<\/p>/gi, '\n\n')
        .replace(/<\/div>/gi, '\n')
        .replace(/<\/h[1-6]>/gi, '\n\n')
        .replace(/<[^>]+>/g, '')
        .replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/\n{3,}/g, '\n\n')
        .trim()
}

'use client'

/**
 * Client-side subtitle translation using Opus-MT models via Transformers.js.
 * Runs entirely in the browser — zero API cost.
 * 
 * Strategy: Source → English (if not already English), then English → all target languages.
 * This only requires one source model + the standard en→X models.
 */

import type { TranscriptSegment } from './transcribe-client'

// English → target language models
const EN_TO_TARGET: Record<string, string> = {
    es: 'Xenova/opus-mt-en-es',
    fr: 'Xenova/opus-mt-en-fr',
    de: 'Xenova/opus-mt-en-de',
    pt: 'Xenova/opus-mt-en-pt',
    ru: 'Xenova/opus-mt-en-ru',
    zh: 'Xenova/opus-mt-en-zh',
    ar: 'Xenova/opus-mt-en-ar',
    ja: 'Xenova/opus-mt-en-jap',
    ko: 'Xenova/opus-mt-en-ko',
    hi: 'Xenova/opus-mt-en-hi',
}

// Source → English models (for non-English films)
const SOURCE_TO_EN: Record<string, string> = {
    es: 'Xenova/opus-mt-es-en',
    fr: 'Xenova/opus-mt-fr-en',
    de: 'Xenova/opus-mt-de-en',
    pt: 'Xenova/opus-mt-pt-en', // may use ROMANCE-en
    ru: 'Xenova/opus-mt-ru-en',
    zh: 'Xenova/opus-mt-zh-en',
    ar: 'Xenova/opus-mt-ar-en',
    ja: 'Xenova/opus-mt-ja-en',
    ko: 'Xenova/opus-mt-ko-en',
    hi: 'Xenova/opus-mt-hi-en',
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const pipelineCache: Record<string, any> = {}

export type TranslationStatus = {
    language: string
    languageName: string
    phase: 'loading-model' | 'translating' | 'done' | 'error' | 'skipped'
    progress: number
    detail?: string
}

export const LANGUAGE_NAMES: Record<string, string> = {
    en: 'English',
    es: 'Español',
    fr: 'Français',
    de: 'Deutsch',
    pt: 'Português',
    ru: 'Русский',
    zh: '中文',
    ar: 'العربية',
    ja: '日本語',
    ko: '한국어',
    hi: 'हिन्दी',
}

/**
 * Load a translation pipeline by model ID.
 */
async function loadPipeline(modelId: string) {
    if (pipelineCache[modelId]) return pipelineCache[modelId]
    try {
        const { pipeline } = await import('@huggingface/transformers')
        const translator = await pipeline('translation', modelId)
        pipelineCache[modelId] = translator
        return translator
    } catch {
        return null
    }
}

/**
 * Translate an array of segments using a given model.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
async function runTranslation(
    segments: TranscriptSegment[],
    translator: any,
): Promise<TranscriptSegment[]> {
    const translated: TranscriptSegment[] = []
    // Process in batches of 5
    for (let i = 0; i < segments.length; i += 5) {
        const batch = segments.slice(i, i + 5)
        const texts = batch.map(s => s.text)
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const results: any[] = await translator(texts)
        for (let j = 0; j < batch.length; j++) {
            translated.push({
                start: batch[j].start,
                end: batch[j].end,
                text: results[j]?.translation_text || results[j]?.generated_text || batch[j].text,
            })
        }
    }
    return translated
}

/**
 * Translate subtitle segments to ALL supported languages.
 * 
 * Strategy:
 * 1. If source is NOT English → translate source→English first (adds English track)
 * 2. Then translate English→all other languages using standard en→X models
 * 3. Skip the source language (it's the original transcript)
 */
export async function translateToAllLanguages(
    segments: TranscriptSegment[],
    sourceLang: string = 'en',
    onStatus?: (status: TranslationStatus) => void,
): Promise<Record<string, TranscriptSegment[]>> {
    const translations: Record<string, TranscriptSegment[]> = {}
    let englishSegments = segments

    // Step 1: If source is not English, translate to English first
    if (sourceLang !== 'en') {
        const srcToEnModel = SOURCE_TO_EN[sourceLang]
        if (srcToEnModel) {
            onStatus?.({
                language: 'en', languageName: 'English',
                phase: 'loading-model', progress: 0,
                detail: 'Loading English translation model...',
            })
            const translator = await loadPipeline(srcToEnModel)
            if (translator) {
                onStatus?.({
                    language: 'en', languageName: 'English',
                    phase: 'translating', progress: 5,
                    detail: 'Translating to English...',
                })
                englishSegments = await runTranslation(segments, translator)
                translations['en'] = englishSegments
                onStatus?.({
                    language: 'en', languageName: 'English',
                    phase: 'done', progress: 10,
                    detail: 'English complete',
                })
            }
        }
    }

    // Step 2: Translate English → all other target languages
    const targetLangs = Object.keys(EN_TO_TARGET).filter(l => l !== sourceLang)
    const totalLangs = targetLangs.length + (sourceLang !== 'en' ? 1 : 0)

    for (let i = 0; i < targetLangs.length; i++) {
        const lang = targetLangs[i]
        const langName = LANGUAGE_NAMES[lang] || lang
        const progress = Math.round(((i + (sourceLang !== 'en' ? 1 : 0)) / totalLangs) * 100)

        onStatus?.({
            language: lang, languageName: langName,
            phase: 'loading-model', progress,
            detail: `Loading ${langName} model...`,
        })

        try {
            const modelId = EN_TO_TARGET[lang]
            const translator = await loadPipeline(modelId)
            if (!translator) {
                onStatus?.({
                    language: lang, languageName: langName,
                    phase: 'skipped', progress,
                    detail: `No model for ${langName}`,
                })
                continue
            }

            onStatus?.({
                language: lang, languageName: langName,
                phase: 'translating', progress,
                detail: `Translating to ${langName}...`,
            })

            translations[lang] = await runTranslation(englishSegments, translator)

            onStatus?.({
                language: lang, languageName: langName,
                phase: 'done',
                progress: Math.round(((i + 1 + (sourceLang !== 'en' ? 1 : 0)) / totalLangs) * 100),
                detail: `${langName} complete`,
            })
        } catch {
            onStatus?.({
                language: lang, languageName: langName,
                phase: 'error', progress,
                detail: `Failed: ${langName}`,
            })
        }
    }

    return translations
}

/**
 * Get the list of all supported subtitle languages.
 */
export function getSupportedSubtitleLanguages(): { code: string; name: string }[] {
    return Object.entries(LANGUAGE_NAMES).map(([code, name]) => ({ code, name }))
}

'use client'

/**
 * Client-side video transcription using FFmpeg WASM + Transformers.js Whisper.
 * Runs entirely in the browser — zero API cost.
 */

import { FFmpeg } from '@ffmpeg/ffmpeg'
import { fetchFile, toBlobURL } from '@ffmpeg/util'

// ── Types ──
export interface TranscriptSegment {
    start: number
    end: number
    text: string
}

export type TranscriptionStatus =
    | 'idle'
    | 'loading-ffmpeg'
    | 'extracting-audio'
    | 'loading-model'
    | 'transcribing'
    | 'done'
    | 'error'

export interface TranscriptionResult {
    segments: TranscriptSegment[]
    fullText: string
}

// ── Singleton caches ──
let ffmpegInstance: FFmpeg | null = null
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let transcriberPipeline: any = null

/**
 * Load and cache FFmpeg WASM instance.
 */
async function getFFmpeg(): Promise<FFmpeg> {
    if (ffmpegInstance) return ffmpegInstance

    const ffmpeg = new FFmpeg()

    // Load WASM from CDN
    const baseURL = 'https://unpkg.com/@ffmpeg/core@0.12.6/dist/umd'
    await ffmpeg.load({
        coreURL: await toBlobURL(`${baseURL}/ffmpeg-core.js`, 'text/javascript'),
        wasmURL: await toBlobURL(`${baseURL}/ffmpeg-core.wasm`, 'application/wasm'),
    })

    ffmpegInstance = ffmpeg
    return ffmpeg
}

/**
 * Load and cache the Whisper ASR pipeline.
 * Uses whisper-small (multilingual) — supports 99 languages and auto-detects
 * language per chunk, so it handles code-switching (mixing languages in one video).
 * First download is ~244MB, cached after that.
 */
async function getTranscriber() {
    if (transcriberPipeline) return transcriberPipeline

    const { pipeline } = await import('@huggingface/transformers')
    transcriberPipeline = await pipeline(
        'automatic-speech-recognition',
        'Xenova/whisper-small',
    )
    return transcriberPipeline
}

/**
 * Transcribe a video file entirely in the browser.
 * Uses Whisper's 'translate' task which auto-translates any spoken language
 * to English — handles multilingual films perfectly.
 *
 * @param videoSource   - The File object or URL string
 * @param onStatus      - Callback for status updates
 * @returns              English transcript segments with timestamps + full text
 */
export async function transcribeVideo(
    videoSource: File | string,
    onStatus?: (status: TranscriptionStatus, detail?: string) => void,
): Promise<TranscriptionResult> {
    const report = (s: TranscriptionStatus, d?: string) => onStatus?.(s, d)

    try {
        // 1. Load FFmpeg
        report('loading-ffmpeg', 'Loading video engine...')
        const ffmpeg = await getFFmpeg()

        // 2. Write video to FFmpeg virtual filesystem
        report('extracting-audio', 'Extracting audio from video...')
        let fileData: Uint8Array
        if (typeof videoSource === 'string') {
            // It's a URL — fetch it
            fileData = await fetchFile(videoSource)
        } else {
            fileData = await fetchFile(videoSource)
        }
        await ffmpeg.writeFile('input-video', fileData)

        // 3. Extract audio as mono 16kHz WAV (Whisper requirement)
        await ffmpeg.exec([
            '-i', 'input-video',
            '-vn',                   // no video
            '-acodec', 'pcm_s16le',  // 16-bit PCM
            '-ar', '16000',          // 16 kHz sample rate
            '-ac', '1',              // mono
            'audio.wav',
        ])

        // 4. Read the WAV output
        const wavData = await ffmpeg.readFile('audio.wav')
        const wavBytes = wavData instanceof Uint8Array ? new Uint8Array(wavData) : wavData
        const wavBlob = new Blob([wavBytes as BlobPart], { type: 'audio/wav' })
        const audioUrl = URL.createObjectURL(wavBlob)

        // 5. Load Whisper model
        report('loading-model', 'Loading AI speech model (~244MB first time)...')
        const transcriber = await getTranscriber()

        // 6. Transcribe — Whisper auto-detects language and translates to English
        report('transcribing', 'Transcribing audio (auto-detects all languages)...')
        const result = await transcriber(audioUrl, {
            chunk_length_s: 30,
            stride_length_s: 5,
            return_timestamps: true,
            task: 'translate',  // auto-translate ANY language to English
        })

        // Cleanup
        URL.revokeObjectURL(audioUrl)
        await ffmpeg.deleteFile('input-video').catch(() => {})
        await ffmpeg.deleteFile('audio.wav').catch(() => {})

        // 7. Parse result
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const output = Array.isArray(result) ? result[0] : result
        const segments: TranscriptSegment[] = Array.isArray(output.chunks)
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            ? output.chunks.map((chunk: any) => ({
                start: chunk.timestamp?.[0] || 0,
                end: chunk.timestamp?.[1] || 0,
                text: (chunk.text || '').trim(),
            }))
            : [{ start: 0, end: 0, text: (output.text || '').trim() }]

        const fullText = segments.map(s => s.text).join(' ')

        report('done', 'Transcription complete!')
        return { segments, fullText }
    } catch (err) {
        report('error', err instanceof Error ? err.message : 'Transcription failed')
        throw err
    }
}

/**
 * Convert transcript segments to SRT subtitle format.
 */
export function segmentsToSRT(segments: TranscriptSegment[]): string {
    return segments
        .map((seg, i) => {
            const startSrt = formatSrtTime(seg.start)
            const endSrt = formatSrtTime(seg.end)
            return `${i + 1}\n${startSrt} --> ${endSrt}\n${seg.text}\n`
        })
        .join('\n')
}

function formatSrtTime(seconds: number): string {
    const h = Math.floor(seconds / 3600)
    const m = Math.floor((seconds % 3600) / 60)
    const s = Math.floor(seconds % 60)
    const ms = Math.round((seconds % 1) * 1000)
    return `${pad(h)}:${pad(m)}:${pad(s)},${pad3(ms)}`
}

function pad(n: number): string {
    return n.toString().padStart(2, '0')
}

function pad3(n: number): string {
    return n.toString().padStart(3, '0')
}

/**
 * Trigger a file download in the browser.
 */
export function downloadFile(content: string, filename: string, mimeType = 'text/plain') {
    const blob = new Blob([content], { type: mimeType })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = filename
    a.click()
    URL.revokeObjectURL(url)
}

import createMiddleware from 'next-intl/middleware'
import { routing } from './i18n/routing'
import { NextResponse, NextRequest } from 'next/server'
import { CSRF_COOKIE_NAME, generateCsrfToken, setCsrfCookie, verifyCsrfToken } from './lib/csrf'

const intlMiddleware = createMiddleware(routing)

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Admin API routes — pass through to route handlers which do their own requireAdmin() check
  // (getSession() supports refresh token renewal; the old middleware check did not)
  if (pathname.startsWith('/api/admin')) {
    const response = NextResponse.next()
    ensureCsrfCookie(request, response)
    return response
  }

  // Auth API routes — exempt from CSRF (login, register, OAuth need to work without it)
  if (pathname.startsWith('/api/auth')) {
    return NextResponse.next()
  }

  // Other API routes (public) — no CSRF needed but set cookie for future use
  if (pathname.startsWith('/api/')) {
    const response = NextResponse.next()
    ensureCsrfCookie(request, response)
    return response
  }

  // Admin panel routes — skip next-intl entirely so it cannot
  // rewrite or redirect /admin/* paths
  if (pathname.startsWith('/admin')) {
    const response = NextResponse.next()
    ensureCsrfCookie(request, response)
    return response
  }

  // All other routes — apply i18n middleware
  const response = intlMiddleware(request)
  // Ensure CSRF cookie is set on page navigations too
  if (response instanceof NextResponse) {
    ensureCsrfCookie(request, response)
  }
  return response
}

/**
 * Set a CSRF cookie if one doesn't already exist on the request.
 */
function ensureCsrfCookie(request: NextRequest, response: NextResponse) {
  const existing = request.cookies.get(CSRF_COOKIE_NAME)?.value
  if (!existing) {
    setCsrfCookie(response, generateCsrfToken())
  }
}

